function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
        console.log(message);
    } else {
        console.log(message, JSON.stringify(data, null, 2));
    }
}

function setOutputSafe(key, value) {
    try {
        output.set(key, value);
    } catch {
        // Output is unavailable in some testing contexts.
    }
}

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    try {
        return table.getField(fieldName);
    } catch {
        return null;
    }
}

function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);
    if (!field) return false;

    const nonWritableTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "createdBy",
        "lastModifiedBy",
        "autoNumber",
        "button",
        "aiText",
        "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getLinkedRecordIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) {
        return [];
    }

    return raw.map((item) => item?.id).filter(Boolean);
}

function getFirstLinkedRecordId(record, table, fieldName) {
    return getLinkedRecordIds(record, table, fieldName)[0] || "";
}

function getAttachments(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);
    return Array.isArray(raw) ? raw : [];
}

function normalizeText(value) {
    return String(value || "").trim();
}

function buildSingleSelectValue(table, fieldName, optionName) {
    const field = getFieldSafe(table, fieldName);

    if (!field) {
        return undefined;
    }

    if (field.type !== "singleSelect") {
        return optionName;
    }

    const cleanOptionName = String(optionName || "").trim();
    const choices = field?.options?.choices || [];

    const match = choices.find((choice) => {
        return (
            String(choice.name || "").trim().toLowerCase() ===
            cleanOptionName.toLowerCase()
        );
    });

    if (!match) {
        throw new Error(
            `Missing single-select option "${cleanOptionName}" in ${CONFIG.tables.assets}.${fieldName}`
        );
    }

    return { id: match.id };
}

function buildAttachmentWriteValue(attachment) {
    const url = normalizeText(attachment?.url);
    const filename = normalizeText(attachment?.filename);

    if (!url) {
        return [];
    }

    return [
        {
            url,
            filename: filename || "Uploaded File",
        },
    ];
}

function addWritableField(fields, table, fieldName, value) {
    if (!fieldExists(table, fieldName)) {
        log(`Skipped missing field: ${fieldName}`);
        return;
    }

    if (!isWritableField(table, fieldName)) {
        log(`Skipped non-writable field: ${fieldName}`);
        return;
    }

    if (value === undefined) {
        return;
    }

    fields[fieldName] = value;
}

function buildAssetFields({
    submissionId,
    enrollmentId,
    attachment,
    assetPurpose,
    assetLabel,
}) {
    const fields = {};

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.submissionLink,
        submissionId ? [{ id: submissionId }] : undefined
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.enrollmentLink,
        enrollmentId ? [{ id: enrollmentId }] : undefined
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.originalFileName,
        normalizeText(attachment?.filename)
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.airtableAttachment,
        buildAttachmentWriteValue(attachment)
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.sourceAttachmentId,
        normalizeText(attachment?.id)
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.assetPurpose,
        buildSingleSelectValue(assetsTable, CONFIG.assets.assetPurpose, assetPurpose)
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.assetLabel,
        assetLabel
    );

    addWritableField(
        fields,
        assetsTable,
        CONFIG.assets.sendToMakeTrigger,
        true
    );

    return fields;
}

function buildSubmissionFieldsToLoad() {
    return [
        CONFIG.submissions.enrollment,
        CONFIG.submissions.week,
        CONFIG.submissions.hwSub1,
        CONFIG.submissions.hwSub2,
        CONFIG.submissions.videoUpload,
        CONFIG.submissions.attachmentUploadStatus,
        CONFIG.submissions.submissionAssetsReady,
        CONFIG.submissions.readyToSendAttachmentsToMake,
    ].filter((fieldName) => fieldExists(submissionsTable, fieldName));
}

function buildAssetFieldsToLoad() {
    return [
        CONFIG.assets.sourceAttachmentId,
        CONFIG.assets.submissionLink,
        CONFIG.assets.assetPurpose,
        CONFIG.assets.assetLabel,
    ].filter((fieldName) => fieldExists(assetsTable, fieldName));
}

function countByPurpose(items, purposeValue) {
    return items.filter((item) => item.assetPurpose === purposeValue).length;
}

/* =========================================================
   SECTION 5: MAIN
   ========================================================= */

async function main() {
    let debugStep = "Start";

    let submission = null;
    let enrollmentId = "";
    let weekId = "";

    let hwSub1Attachments = [];
    let hwSub2Attachments = [];
    let videoAttachments = [];

    let createdHomeworkCount = 0;
    let createdVideoCount = 0;
    let skippedCount = 0;
    let recordsToCreate = [];

    setOutputSafe("debugStep", debugStep);

    try {
        debugStep = "1 - Validate recordId";
        setOutputSafe("debugStep", debugStep);

        if (!recordId.startsWith("rec")) {
            throw new Error(`Invalid Submission recordId input: ${recordId}`);
        }

        debugStep = "2 - Validate Required Fields";
        setOutputSafe("debugStep", debugStep);

        const requiredSubmissionFields = [
            CONFIG.submissions.enrollment,
            CONFIG.submissions.week,
            CONFIG.submissions.hwSub1,
            CONFIG.submissions.hwSub2,
            CONFIG.submissions.videoUpload,
        ];

        for (const fieldName of requiredSubmissionFields) {
            if (!fieldExists(submissionsTable, fieldName)) {
                throw new Error(`Missing required field on Submissions: ${fieldName}`);
            }
        }

        const requiredAssetFields = [
            CONFIG.assets.submissionLink,
            CONFIG.assets.enrollmentLink,
            CONFIG.assets.originalFileName,
            CONFIG.assets.airtableAttachment,
            CONFIG.assets.assetPurpose,
            CONFIG.assets.sourceAttachmentId,
        ];

        for (const fieldName of requiredAssetFields) {
            if (!fieldExists(assetsTable, fieldName)) {
                throw new Error(`Missing required field on Submission Assets: ${fieldName}`);
            }

            if (!isWritableField(assetsTable, fieldName)) {
                throw new Error(`Field is not writable on Submission Assets: ${fieldName}`);
            }
        }

        debugStep = "3 - Load Submission";
        setOutputSafe("debugStep", debugStep);

        submission = await submissionsTable.selectRecordAsync(recordId, {
            fields: buildSubmissionFieldsToLoad(),
        });

        if (!submission) {
            setOutputSafe("ok", false);
            setOutputSafe("submissionId", recordId);
            setOutputSafe("createdCount", 0);
            setOutputSafe("createdHomeworkCount", 0);
            setOutputSafe("createdVideoCount", 0);
            setOutputSafe("skippedCount", 0);
            setOutputSafe("hwSub1AttachmentCount", 0);
            setOutputSafe("hwSub2AttachmentCount", 0);
            setOutputSafe("videoAttachmentCount", 0);
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", `Submission not found: ${recordId}`);
            setOutputSafe("debugStep", "Skipped: Submission not found");
            return;
        }

        debugStep = "4 - Read Submission Values";
        setOutputSafe("debugStep", debugStep);

        enrollmentId = getFirstLinkedRecordId(
            submission,
            submissionsTable,
            CONFIG.submissions.enrollment
        );

        weekId = getFirstLinkedRecordId(
            submission,
            submissionsTable,
            CONFIG.submissions.week
        );

        hwSub1Attachments = getAttachments(
            submission,
            submissionsTable,
            CONFIG.submissions.hwSub1
        );

        hwSub2Attachments = getAttachments(
            submission,
            submissionsTable,
            CONFIG.submissions.hwSub2
        );

        videoAttachments = getAttachments(
            submission,
            submissionsTable,
            CONFIG.submissions.videoUpload
        );

        log("Submission asset creation input", {
            recordId,
            enrollmentId,
            weekId,
            hwSub1AttachmentCount: hwSub1Attachments.length,
            hwSub2AttachmentCount: hwSub2Attachments.length,
            videoAttachmentCount: videoAttachments.length,
        });

        debugStep = "5 - Validate Submission Links";
        setOutputSafe("debugStep", debugStep);

        if (!enrollmentId) {
            throw new Error("Submission is missing Enrollment.");
        }

        if (!weekId) {
            throw new Error("Submission is missing Week.");
        }

        if (
            hwSub1Attachments.length === 0 &&
            hwSub2Attachments.length === 0 &&
            videoAttachments.length === 0
        ) {
            setOutputSafe("ok", true);
            setOutputSafe("submissionId", recordId);
            setOutputSafe("createdCount", 0);
            setOutputSafe("createdHomeworkCount", 0);
            setOutputSafe("createdVideoCount", 0);
            setOutputSafe("skippedCount", 0);
            setOutputSafe("hwSub1AttachmentCount", 0);
            setOutputSafe("hwSub2AttachmentCount", 0);
            setOutputSafe("videoAttachmentCount", 0);
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", "No attachments found on HW Sub 1, HW Sub 2, or Video Upload.");
            setOutputSafe("debugStep", "Skipped: No attachments");
            return;
        }

        debugStep = "6 - Load Existing Submission Assets";
        setOutputSafe("debugStep", debugStep);

        const existingAssetQuery = await assetsTable.selectRecordsAsync({
            fields: buildAssetFieldsToLoad(),
        });

        const existingSourceAttachmentIds = new Set(
            existingAssetQuery.records
                .map((record) =>
                    normalizeText(
                        getText(record, assetsTable, CONFIG.assets.sourceAttachmentId)
                    )
                )
                .filter(Boolean)
        );

        debugStep = "7 - Queue Asset Records";
        setOutputSafe("debugStep", debugStep);

        function queueAttachments(attachments, assetPurpose, assetLabel) {
            for (const attachment of attachments) {
                const sourceAttachmentId = normalizeText(attachment?.id);
                const sourceAttachmentUrl = normalizeText(attachment?.url);

                if (!sourceAttachmentId || !sourceAttachmentUrl) {
                    skippedCount += 1;
                    continue;
                }

                if (existingSourceAttachmentIds.has(sourceAttachmentId)) {
                    skippedCount += 1;
                    continue;
                }

                const fields = buildAssetFields({
                    submissionId: submission.id,
                    enrollmentId,
                    attachment,
                    assetPurpose,
                    assetLabel,
                });

                recordsToCreate.push({
                    fields,
                    assetPurpose,
                    assetLabel,
                    sourceAttachmentId,
                });

                existingSourceAttachmentIds.add(sourceAttachmentId);
            }
        }

        queueAttachments(
            hwSub1Attachments,
            CONFIG.assetPurposeValues.hw1,
            CONFIG.assetLabelValues.hw1
        );

        queueAttachments(
            hwSub2Attachments,
            CONFIG.assetPurposeValues.hw2,
            CONFIG.assetLabelValues.hw2
        );

        queueAttachments(
            videoAttachments,
            CONFIG.assetPurposeValues.video,
            CONFIG.assetLabelValues.video
        );

        createdHomeworkCount =
            countByPurpose(recordsToCreate, CONFIG.assetPurposeValues.hw1) +
            countByPurpose(recordsToCreate, CONFIG.assetPurposeValues.hw2);

        createdVideoCount = countByPurpose(
            recordsToCreate,
            CONFIG.assetPurposeValues.video
        );

        debugStep = "8 - Create Submission Asset Records";
        setOutputSafe("debugStep", debugStep);

        let createBatch = recordsToCreate.map((item) => {
            return {
                fields: item.fields,
            };
        });

        while (createBatch.length > 0) {
            await assetsTable.createRecordsAsync(createBatch.slice(0, 50));
            createBatch.splice(0, 50);
        }

        debugStep = "9 - Outputs";
        setOutputSafe("debugStep", debugStep);

        const createdCount = createdHomeworkCount + createdVideoCount;

        setOutputSafe("ok", true);
        setOutputSafe("submissionId", recordId);
        setOutputSafe("createdCount", createdCount);
        setOutputSafe("createdHomeworkCount", createdHomeworkCount);
        setOutputSafe("createdVideoCount", createdVideoCount);
        setOutputSafe("skippedCount", skippedCount);
        setOutputSafe("hwSub1AttachmentCount", hwSub1Attachments.length);
        setOutputSafe("hwSub2AttachmentCount", hwSub2Attachments.length);
        setOutputSafe("videoAttachmentCount", videoAttachments.length);
        setOutputSafe("statusOut", CONFIG.statuses.success);
        setOutputSafe("errorOut", "");

        log("Submission Assets creation completed", {
            ok: true,
            submissionId: recordId,
            createdCount,
            createdHomeworkCount,
            createdVideoCount,
            skippedCount,
            hwSub1AttachmentCount: hwSub1Attachments.length,
            hwSub2AttachmentCount: hwSub2Attachments.length,
            videoAttachmentCount: videoAttachments.length,
            note: "Upload Destination is intentionally not written because it is computed from Asset Purpose.",
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        setOutputSafe("ok", false);
        setOutputSafe("submissionId", recordId);
        setOutputSafe("createdCount", createdHomeworkCount + createdVideoCount);
        setOutputSafe("createdHomeworkCount", createdHomeworkCount);
        setOutputSafe("createdVideoCount", createdVideoCount);
        setOutputSafe("skippedCount", skippedCount);
        setOutputSafe("hwSub1AttachmentCount", hwSub1Attachments.length);
        setOutputSafe("hwSub2AttachmentCount", hwSub2Attachments.length);
        setOutputSafe("videoAttachmentCount", videoAttachments.length);
        setOutputSafe("statusOut", CONFIG.statuses.error);
        setOutputSafe("errorOut", message);
        setOutputSafe("debugStep", `FAILED AT: ${debugStep}`);

        log("Submission Assets creation failed", {
            submissionId: recordId,
            debugStep,
            error: message,
        });

        throw error;
    }
}

/* =========================================================
   SECTION 6: RUN
   ========================================================= */

await main();

