        "Video Feedback",
        "Video",
    ]);

    const workflowChoice = firstExistingChoice(videoTable, CONFIG.video.workflowStatus, [
        "Pending Upload",
        "Pending",
        "Ready",
        "Processing",
    ]);

    const uploadChoice = firstExistingChoice(videoTable, CONFIG.video.uploadStatus, [
