/************************************************************
 * Utility helpers
 ************************************************************/

function getField(table, fieldName) {
    return table.fields.find(f => f.name === fieldName);
}

function fieldExists(table, fieldName) {
    return Boolean(getField(table, fieldName));
}

function isWritable(table, fieldName) {
    const field = getField(table, fieldName);
    if (!field) return false;

    const readOnlyTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "autoNumber",
        "createdBy",
        "lastModifiedBy",
        "button",
        "externalSyncSource",
    ]);

    return !readOnlyTypes.has(field.type);
}

function safeFields(table, fieldNames) {
    return [...new Set(fieldNames)].filter(name => fieldExists(table, name));
}

function cell(record, fieldName) {
    try {
        return record.getCellValue(fieldName);
    } catch {
        return null;
    }
}

function text(record, fieldName) {
    try {
        return record.getCellValueAsString(fieldName) || "";
    } catch {
        return "";
    }
}

function selectName(record, fieldName) {
    const value = cell(record, fieldName);
    return value && value.name ? value.name : "";
}

function linkedIds(record, fieldName) {
    const value = cell(record, fieldName);
    if (!Array.isArray(value)) return [];
    return value.map(v => v.id).filter(Boolean);
}

function firstLinkedId(record, fieldName) {
    return linkedIds(record, fieldName)[0] || null;
}

function attachments(record, fieldName) {
    const value = cell(record, fieldName);
    return Array.isArray(value) ? value : [];
}

function choiceExists(table, fieldName, choiceName) {
    const field = getField(table, fieldName);
    if (!field || !field.options || !field.options.choices) return false;
    return field.options.choices.some(choice => choice.name === choiceName);
}

function setLink(fields, table, fieldName, ids) {
    if (!isWritable(table, fieldName)) return;

    const cleanIds = [...new Set((ids || []).filter(Boolean))];
    fields[fieldName] = cleanIds.map(id => ({ id }));
}

function setSingleSelect(fields, table, fieldName, choiceName) {
    if (!isWritable(table, fieldName)) return;
    if (!choiceName) return;
    if (!choiceExists(table, fieldName, choiceName)) return;

    fields[fieldName] = { name: choiceName };
}

function setCheckbox(fields, table, fieldName, value) {
    if (!isWritable(table, fieldName)) return;
    fields[fieldName] = Boolean(value);
}

function setText(fields, table, fieldName, value) {
    if (!isWritable(table, fieldName)) return;
    if (value === undefined || value === null || value === "") return;

    fields[fieldName] = String(value);
}

function setDate(fields, table, fieldName, value) {
    if (!isWritable(table, fieldName)) return;
    if (!value) return;

    fields[fieldName] = value;
}

function setAttachment(fields, table, fieldName, files) {
    if (!isWritable(table, fieldName)) return;
    if (!Array.isArray(files) || files.length === 0) return;

    fields[fieldName] = files
        .filter(file => file.url)
        .map(file => ({
            url: file.url,
            filename: file.filename || "uploaded_file",
        }));
}

function inferSlot(asset) {
    const existingSlot = selectName(asset, CONFIG.assets.assetSlot);
    if (existingSlot === "HW1" || existingSlot === "HW2") return existingSlot;

    const purpose = selectName(asset, CONFIG.assets.assetPurpose);
    if (purpose === "Homework 1") return "HW1";
    if (purpose === "Homework 2") return "HW2";

    const label = text(asset, CONFIG.assets.assetLabel);
    if (label.startsWith("HW1")) return "HW1";
    if (label.startsWith("HW2")) return "HW2";

    return "";
}

function homeworkFieldForSlot(slot) {
    if (slot === "HW1") return CONFIG.submissions.homeworkName1;
    if (slot === "HW2") return CONFIG.submissions.homeworkName2;
    return "";
}

function mapAssetUploadStatusToHomeworkStatus(assetStatus) {
    if (assetStatus === "Uploaded") return "Uploaded";
    if (assetStatus === "Processing") return "Processing";
    if (assetStatus === "Error") return "Error";
    return "Pending";
}

function buildAssetErrorFields(message) {
    const fields = {};
    setSingleSelect(fields, assetsTable, CONFIG.assets.uploadStatus, "Error");
    setText(fields, assetsTable, CONFIG.assets.uploadError, message);
    return fields;
}

async function markAssetError(asset, message) {
    const fields = buildAssetErrorFields(message);

    if (Object.keys(fields).length > 0) {
        await assetsTable.updateRecordAsync(asset.id, fields);
    }

    throw new Error(message);
}

/************************************************************
 * Load tables
 ************************************************************/

const assetsTable = base.getTable(CONFIG.tables.assets);
const submissionsTable = base.getTable(CONFIG.tables.submissions);
const homeworkTable = base.getTable(CONFIG.tables.homework);

/************************************************************
 * Load triggering asset
 ************************************************************/

const assetQuery = await assetsTable.selectRecordsAsync({
    fields: safeFields(assetsTable, Object.values(CONFIG.assets)),
});

const asset = assetQuery.getRecord(recordId);

if (!asset) {
    throw new Error(`Submission Asset not found: ${recordId}`);
}

/************************************************************
 * Stop safely if already linked
 ************************************************************/

const existingHomeworkIds = linkedIds(asset, CONFIG.assets.homeworkCompletions);

if (existingHomeworkIds.length > 0) {
    output.set("status", "already_linked");
    output.set("submissionAssetId", asset.id);
    output.set("homeworkCompletionId", existingHomeworkIds[0]);

    console.log("Asset already linked to Homework Completion. No action needed.");
} else {
    /********************************************************
     * Validate asset
     ********************************************************/

    const uploadDestination = text(asset, CONFIG.assets.uploadDestination);
    const assetPurpose = selectName(asset, CONFIG.assets.assetPurpose);
    const assetAttachments = attachments(asset, CONFIG.assets.attachment);
    const submissionId = firstLinkedId(asset, CONFIG.assets.submission);
    const enrollmentIds = linkedIds(asset, CONFIG.assets.enrollment);
    const slot = inferSlot(asset);

    if (uploadDestination !== "Homework Completions") {
        await markAssetError(
            asset,
            `Upload Destination is not Homework Completions. Actual: ${uploadDestination}`
        );
    }

    if (!(assetPurpose === "Homework 1" || assetPurpose === "Homework 2")) {
        await markAssetError(
            asset,
            `Asset Purpose must be Homework 1 or Homework 2. Actual: ${assetPurpose}`
        );
    }

    if (assetAttachments.length === 0) {
        await markAssetError(asset, "Asset has no Airtable Attachment.");
    }

    if (!submissionId) {
        await markAssetError(
            asset,
            "Asset has no linked Submission. Cannot safely create Homework Completion."
        );
    }

    if (enrollmentIds.length === 0) {
        await markAssetError(asset, "Asset has no linked Enrollment.");
    }

    if (!(slot === "HW1" || slot === "HW2")) {
        await markAssetError(
            asset,
            "Could not infer HW1/HW2 from Asset Slot, Asset Purpose, or Asset Label."
        );
    }

    /********************************************************
     * Load linked Submission
     ********************************************************/

    const submissionsQuery = await submissionsTable.selectRecordsAsync({
        fields: safeFields(submissionsTable, Object.values(CONFIG.submissions)),
    });

    const submission = submissionsQuery.getRecord(submissionId);

    if (!submission) {
        await markAssetError(
            asset,
            `Linked Submission could not be loaded: ${submissionId}`
        );
    }

    const homeworkField = homeworkFieldForSlot(slot);
    const homeworkId = firstLinkedId(submission, homeworkField);

    if (!homeworkId) {
        await markAssetError(
            asset,
            `Submission is missing ${homeworkField}. Cannot create Homework Completion.`
        );
    }

    /********************************************************
     * Find existing Homework Completion
     ********************************************************/

    const homeworkQuery = await homeworkTable.selectRecordsAsync({
        fields: safeFields(homeworkTable, Object.values(CONFIG.homework)),
    });

    const exactCandidates = homeworkQuery.records.filter(hw => {
        const hwSubmissionId = firstLinkedId(hw, CONFIG.homework.submission);
        const hwHomeworkId = firstLinkedId(hw, CONFIG.homework.homework);
        const hwSlot =
            selectName(hw, CONFIG.homework.assetSlot) ||
            selectName(hw, CONFIG.homework.itemSlot);

        return (
            hwSubmissionId === submission.id &&
            hwHomeworkId === homeworkId &&
            hwSlot === slot
        );
    });

    const blankSlotCandidates = homeworkQuery.records.filter(hw => {
        const hwSubmissionId = firstLinkedId(hw, CONFIG.homework.submission);
        const hwHomeworkId = firstLinkedId(hw, CONFIG.homework.homework);
        const hwSlot =
            selectName(hw, CONFIG.homework.assetSlot) ||
            selectName(hw, CONFIG.homework.itemSlot);

        return (
            hwSubmissionId === submission.id &&
            hwHomeworkId === homeworkId &&
            !hwSlot
        );
    });

    let homeworkCompletion = null;

    if (exactCandidates.length === 1) {
        homeworkCompletion = exactCandidates[0];
    } else if (exactCandidates.length > 1) {
        await markAssetError(
            asset,
            `Multiple exact Homework Completions found for Submission + Homework + Slot. Count: ${exactCandidates.length}`
        );
    } else if (blankSlotCandidates.length === 1) {
        homeworkCompletion = blankSlotCandidates[0];
    } else if (blankSlotCandidates.length > 1) {
        await markAssetError(
            asset,
            `Multiple blank-slot Homework Completions found for Submission + Homework. Count: ${blankSlotCandidates.length}`
        );
    }

    /********************************************************
     * Create or update Homework Completion
     ********************************************************/

    let homeworkCompletionId = null;

    if (homeworkCompletion) {
        const updateFields = {};
        const existingAssetIds = linkedIds(homeworkCompletion, CONFIG.homework.submissionAssets);

        setLink(updateFields, homeworkTable, CONFIG.homework.submissionAssets, [
            ...existingAssetIds,
            asset.id,
        ]);

        if (!selectName(homeworkCompletion, CONFIG.homework.assetSlot)) {
            setSingleSelect(updateFields, homeworkTable, CONFIG.homework.assetSlot, slot);
        }

        if (!selectName(homeworkCompletion, CONFIG.homework.itemSlot)) {
            setSingleSelect(updateFields, homeworkTable, CONFIG.homework.itemSlot, slot);
        }

        if (!firstLinkedId(homeworkCompletion, CONFIG.homework.homework)) {
            setLink(updateFields, homeworkTable, CONFIG.homework.homework, [homeworkId]);
        }

        if (!text(homeworkCompletion, CONFIG.homework.googleDriveFileUrl) && text(asset, CONFIG.assets.googleDriveFileUrl)) {
            setText(updateFields, homeworkTable, CONFIG.homework.googleDriveFileUrl, text(asset, CONFIG.assets.googleDriveFileUrl));
        }

        if (!text(homeworkCompletion, CONFIG.homework.googleDriveFileId) && text(asset, CONFIG.assets.googleDriveFileId)) {
            setText(updateFields, homeworkTable, CONFIG.homework.googleDriveFileId, text(asset, CONFIG.assets.googleDriveFileId));
        }

        if (Object.keys(updateFields).length > 0) {
            await homeworkTable.updateRecordAsync(homeworkCompletion.id, updateFields);
        }

        homeworkCompletionId = homeworkCompletion.id;
        console.log(`Linked existing Homework Completion: ${homeworkCompletionId}`);
    } else {
        const createFields = {};

        setLink(createFields, homeworkTable, CONFIG.homework.homework, [homeworkId]);
        setLink(createFields, homeworkTable, CONFIG.homework.submission, [submission.id]);
        setLink(createFields, homeworkTable, CONFIG.homework.enrollment, enrollmentIds);
        setLink(createFields, homeworkTable, CONFIG.homework.week, linkedIds(submission, CONFIG.submissions.week));
        setLink(createFields, homeworkTable, CONFIG.homework.gradeBand, linkedIds(submission, CONFIG.submissions.gradeBand));
        setLink(createFields, homeworkTable, CONFIG.homework.weeklySummaryLink, linkedIds(submission, CONFIG.submissions.weeklySummary));
        setLink(createFields, homeworkTable, CONFIG.homework.submissionAssets, [asset.id]);

        setDate(createFields, homeworkTable, CONFIG.homework.submissionDate, cell(submission, CONFIG.submissions.activityDate));

        setSingleSelect(createFields, homeworkTable, CONFIG.homework.uploadStatus, mapAssetUploadStatusToHomeworkStatus(selectName(asset, CONFIG.assets.uploadStatus)));
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.completionStatus, "Submitted");
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.reviewStatus, "Ready for Review");
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.assetSlot, slot);
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.itemSlot, slot);
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.assetType, selectName(asset, CONFIG.assets.assetType));

        /*
         * Homework Completions uses a general purpose value.
         * Do not copy "Homework 1" / "Homework 2" into this field unless
         * those are actual choices in Homework Completions.
         */
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.assetPurpose, "Homework Turn-In");

        setSingleSelect(createFields, homeworkTable, CONFIG.homework.sourceSystem, "Fillout");
        setSingleSelect(createFields, homeworkTable, CONFIG.homework.itemType, "Homework");

        setText(createFields, homeworkTable, CONFIG.homework.assetLabel, text(asset, CONFIG.assets.assetLabel));
        setText(createFields, homeworkTable, CONFIG.homework.originalFileName, text(asset, CONFIG.assets.originalFileName));
        setText(createFields, homeworkTable, CONFIG.homework.googleDriveFileId, text(asset, CONFIG.assets.googleDriveFileId));
        setText(createFields, homeworkTable, CONFIG.homework.googleDriveFileUrl, text(asset, CONFIG.assets.googleDriveFileUrl));
        setText(createFields, homeworkTable, CONFIG.homework.googleDriveFolderId, text(asset, CONFIG.assets.googleDriveFolderId));
        setText(createFields, homeworkTable, CONFIG.homework.googleDriveFolderUrl, text(asset, CONFIG.assets.googleDriveFolderUrl));
        setText(createFields, homeworkTable, CONFIG.homework.uploadError, text(asset, CONFIG.assets.uploadError));

        setDate(createFields, homeworkTable, CONFIG.homework.uploadedAt, cell(asset, CONFIG.assets.uploadedAt));
        setAttachment(createFields, homeworkTable, CONFIG.homework.attachment, assetAttachments);

        homeworkCompletionId = await homeworkTable.createRecordAsync(createFields);

        console.log(`Created Homework Completion: ${homeworkCompletionId}`);
    }

    /********************************************************
     * Update Submission Asset
     ********************************************************/

    const assetUpdateFields = {};

    setLink(assetUpdateFields, assetsTable, CONFIG.assets.homeworkCompletions, [homeworkCompletionId]);

    if (!selectName(asset, CONFIG.assets.assetSlot)) {
        setSingleSelect(assetUpdateFields, assetsTable, CONFIG.assets.assetSlot, slot);
    }

    /*
     * After the correction record exists, the asset can be sent to Make.
     */
    const currentUploadStatus = selectName(asset, CONFIG.assets.uploadStatus);

    if (
        !currentUploadStatus ||
        currentUploadStatus === "Pending Link" ||
        currentUploadStatus === "Error"
    ) {
        setSingleSelect(assetUpdateFields, assetsTable, CONFIG.assets.uploadStatus, "Ready");
    }

    setCheckbox(assetUpdateFields, assetsTable, CONFIG.assets.sendToMakeTrigger, true);

    if (Object.keys(assetUpdateFields).length > 0) {
        await assetsTable.updateRecordAsync(asset.id, assetUpdateFields);
    }

    output.set("status", homeworkCompletion ? "linked_existing" : "created_new");
    output.set("submissionAssetId", asset.id);
    output.set("homeworkCompletionId", homeworkCompletionId);
    output.set("slot", slot);

    console.log("020 complete.");
}

/************************************************************
 * 021 - SUBMISSION INTAKE AND ASSET CREATION
 * Set Attachment Upload Status
 *
 * Version: v2.0
 * Date Written: 2026-04-13
 * Last Reviewed: 2026-05-23
 *
 * PURPOSE
 * - Runs from one Submissions record.
 * - Checks whether the submission has files in:
 *   1) HW Sub 1
 *   2) HW Sub 2
 *   3) Video Upload
 * - Sets Submissions → Attachment Upload Status to:
 *   - No Files when no upload fields contain files.
 *   - Processing when one or more upload fields contain files.
 * - Avoids unnecessary writeback when the status is already correct.
 *
 * FOLDER
 * - 02 - Submission Intake and Asset Creation
 *
 * AUTOMATION NAME
 * - 021 - Submission Intake and Asset Creation - Set Attachment Upload Status
 *
 * TRIGGER TABLE
 * - Submissions
 *
 * TRIGGER TYPE
 * - When record matches conditions
 *
 * REQUIRED TRIGGER CONDITIONS
 * - Attachment Upload Status is empty
 *   OR
 * - Attachment Upload Status is No Files
 *
 * REQUIRED INPUT VARIABLES
 * - recordId = Airtable record ID from the triggering Submission record
 *
 * PRIMARY TABLES USED
 * - Submissions
 *
 * CURRENT SCHEMA FIELDS USED
 * - Submissions → HW Sub 1
 * - Submissions → HW Sub 2
 * - Submissions → Video Upload
 * - Submissions → Attachment Upload Status
 *
 * OUTPUT / WRITEBACK FIELDS
 * - Submissions → Attachment Upload Status = No Files or Processing
 *
 * IMPORTANT NOTES
 * - This is not the Submission Assets creation automation.
 * - This is not the Google Drive upload automation.
 * - This is not an XP automation.
 * - This script only flags whether attachment processing is needed.
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: EASY-EDIT VARIABLES
   ========================================================= */

const TABLE_NAME = "Submissions";

/* ---------- Attachment fields ---------- */

const FIELD_HW_SUB_1 = "HW Sub 1";
const FIELD_HW_SUB_2 = "HW Sub 2";
const FIELD_VIDEO_UPLOAD = "Video Upload";

/* ---------- Status field ---------- */

const FIELD_ATTACHMENT_STATUS = "Attachment Upload Status";

/* ---------- Status values ---------- */

const STATUS_NO_FILES = "No Files";
const STATUS_PROCESSING = "Processing";

/* ---------- Output statuses ---------- */

const STATUS_SUCCESS = "success";
const STATUS_SKIPPED = "skipped";
const STATUS_ERROR = "error";

/* =========================================================
   SECTION 2: INPUTS
   ========================================================= */

const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLE REFERENCE
   ========================================================= */

const submissionsTable = base.getTable(TABLE_NAME);

/* =========================================================
   SECTION 4: HELPER FUNCTIONS
   ========================================================= */

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function requireField(table, fieldName) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing required field on ${table.name}: ${fieldName}`);
    }
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function hasAttachmentFiles(value) {
    return Array.isArray(value) && value.length > 0;
}

function buildSingleSelectValue(table, fieldName, optionName) {
    if (!fieldExists(table, fieldName)) return optionName;

    const field = table.getField(fieldName);

    if (field.type !== "singleSelect") {
        return optionName;
    }

    const choices = field?.options?.choices || [];

    const match = choices.find(choice =>
        String(choice?.name || "").trim().toLowerCase() ===
        String(optionName || "").trim().toLowerCase()
    );

    if (!match) {
        throw new Error(`Missing single-select option "${optionName}" in ${table.name}.${fieldName}`);
    }

    return { id: match.id };
}

function setOutputSafe(name, value) {
    try {
        output.set(name, value);
    } catch {
        // Ignore output mapping errors.
    }
}

function exitSkipped(reason, details = {}) {
    setOutputSafe("statusOut", STATUS_SKIPPED);
    setOutputSafe("errorOut", reason || "");
    setOutputSafe("recordIdOut", recordId);
    setOutputSafe("currentStatusOut", details.currentStatus || "");
    setOutputSafe("newStatusOut", details.newStatus || "");
    setOutputSafe("hasHwSub1Out", Boolean(details.hasHwSub1));
    setOutputSafe("hasHwSub2Out", Boolean(details.hasHwSub2));
    setOutputSafe("hasVideoUploadOut", Boolean(details.hasVideoUpload));
    setOutputSafe("hasAnyFilesOut", Boolean(details.hasAnyFiles));
}

/* =========================================================
   SECTION 5: VALIDATE REQUIRED FIELDS
   ========================================================= */

requireField(submissionsTable, FIELD_HW_SUB_1);
requireField(submissionsTable, FIELD_HW_SUB_2);
requireField(submissionsTable, FIELD_VIDEO_UPLOAD);
requireField(submissionsTable, FIELD_ATTACHMENT_STATUS);

/* =========================================================
   SECTION 6: LOAD SUBMISSION RECORD
   ========================================================= */

const submissionRecord = await submissionsTable.selectRecordAsync(recordId, {
    fields: [
        FIELD_HW_SUB_1,
        FIELD_HW_SUB_2,
        FIELD_VIDEO_UPLOAD,
        FIELD_ATTACHMENT_STATUS,
    ],
});

if (!submissionRecord) {
    throw new Error(`Submission record not found: ${recordId}`);
}

/* =========================================================
   SECTION 7: READ ATTACHMENT VALUES
   ========================================================= */

const hwSub1 = getRaw(submissionRecord, submissionsTable, FIELD_HW_SUB_1);
const hwSub2 = getRaw(submissionRecord, submissionsTable, FIELD_HW_SUB_2);
const videoUpload = getRaw(submissionRecord, submissionsTable, FIELD_VIDEO_UPLOAD);

const hasHwSub1 = hasAttachmentFiles(hwSub1);
const hasHwSub2 = hasAttachmentFiles(hwSub2);
const hasVideoUpload = hasAttachmentFiles(videoUpload);

const hasAnyFiles = hasHwSub1 || hasHwSub2 || hasVideoUpload;

const currentStatus = getText(
    submissionRecord,
    submissionsTable,
    FIELD_ATTACHMENT_STATUS
);

/* =========================================================
   SECTION 8: DETERMINE NEXT STATUS
   ========================================================= */

const newStatus = hasAnyFiles
    ? STATUS_PROCESSING
    : STATUS_NO_FILES;

/* =========================================================
   SECTION 9: AVOID UNNECESSARY WRITEBACK
   ========================================================= */

if (currentStatus === newStatus) {
    exitSkipped("Attachment Upload Status is already correct.", {
        currentStatus,
        newStatus,
        hasHwSub1,
        hasHwSub2,
        hasVideoUpload,
        hasAnyFiles,
    });

    return;
}

/* =========================================================
   SECTION 10: WRITE ATTACHMENT STATUS
   ========================================================= */

await submissionsTable.updateRecordAsync(recordId, {
    [FIELD_ATTACHMENT_STATUS]: buildSingleSelectValue(
        submissionsTable,
        FIELD_ATTACHMENT_STATUS,
        newStatus
    ),
});

/* =========================================================
   SECTION 11: OUTPUTS
   ========================================================= */

setOutputSafe("statusOut", STATUS_SUCCESS);
setOutputSafe("errorOut", "");
setOutputSafe("recordIdOut", recordId);
setOutputSafe("previousStatusOut", currentStatus);
setOutputSafe("newStatusOut", newStatus);
setOutputSafe("hasHwSub1Out", hasHwSub1);
setOutputSafe("hasHwSub2Out", hasHwSub2);
setOutputSafe("hasVideoUploadOut", hasVideoUpload);
setOutputSafe("hasAnyFilesOut", hasAnyFiles);

console.log(JSON.stringify({
    automation: "021 - Submission Intake and Asset Creation - Set Attachment Upload Status",
    statusOut: STATUS_SUCCESS,
    recordIdOut: recordId,
    previousStatusOut: currentStatus,
    newStatusOut: newStatus,
    hasHwSub1Out: hasHwSub1,
    hasHwSub2Out: hasHwSub2,
    hasVideoUploadOut: hasVideoUpload,
    hasAnyFilesOut: hasAnyFiles,
}, null, 2));

/************************************************************
 * AUTOMATION NAME
 * 023 - Submission Intake and Asset Creation - Assign Enrollment to Submission
 *
 * Version: v2.0
 * Date Written: 2026-05-20
 *
 * PURPOSE
 * - Reads one Submission record.
 * - Reads the linked Athlete on the Submission.
 * - Finds the matching active Enrollment for that Athlete.
 * - If Program Instance exists on both Submission and Enrollment, uses it to narrow the match.
 * - Writes the matching Enrollment link back to the Submission.
 * - Does not guess if zero or multiple active Enrollments match.
 *
 * CURRENT SCHEMA NOTES
 * - Submissions.Athlete is a writable linked-record field.
 * - Submissions.Enrollment is a writable linked-record field.
 * - Submissions.Program Instance is treated as optional because it is not present in the current schema snapshot.
 * - Enrollments.Athlete is a linked-record field.
 * - Enrollments.Active? is a writable checkbox.
 * - Enrollments.Program Instance is a linked-record field.
 * - Enrollments.Enrollment Key is a formula field and is read only.
 *
 * REQUIRED AUTOMATION INPUT
 * - recordId: Airtable record ID from Submissions
 *
 * RECOMMENDED TRIGGER VIEW CONDITIONS
 * - Athlete is not empty.
 * - Enrollment is empty.
 *
 * OUTPUTS
 * - ok
 * - recordId
 * - athleteIdOut
 * - submissionProgramInstanceIdOut
 * - matchedEnrollmentId
 * - matchedEnrollmentKey
 * - candidateCountOut
 * - matchModeOut
 * - statusOut
 * - errorOut
 * - debugStep
 ************************************************************/

/// <reference path="../../Welcome Email/airtable-automation-script.d.ts" />
// @ts-nocheck

/* =========================================================
   SECTION 1: CONFIG
   ========================================================= */

const CONFIG = {
    tables: {
        submissions: "Submissions",
        enrollments: "Enrollments",
    },

    submissions: {
        athlete: "Athlete",
        enrollment: "Enrollment",
        programInstance: "Program Instance", // optional; not present in current schema snapshot
    },

    enrollments: {
        athlete: "Athlete",
        active: "Active?",
        programInstance: "Program Instance",
        enrollmentKey: "Enrollment Key", // formula; read only
    },

    statuses: {
        complete: "Complete",
        skipped: "Skipped",
        error: "Error",
    },

    debug: {
        logToConsole: true,
        clearBadEnrollmentLinks: true,
    },
};

/* =========================================================
   SECTION 2: INPUTS
   ========================================================= */

const cfg =
    typeof input !== "undefined" && input && typeof input.config === "function"
        ? input.config()
        : {};

const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLES
   ========================================================= */

const submissionsTable = base.getTable(CONFIG.tables.submissions);
const enrollmentsTable = base.getTable(CONFIG.tables.enrollments);

/* =========================================================
   SECTION 4: HELPERS
   ========================================================= */

function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
        console.log(message);
    } else {
        console.log(message, JSON.stringify(data, null, 2));
    }
}

function setOutputSafe(key, value) {
    try {
        output.set(key, value);
    } catch {
        // Output is unavailable in some testing contexts.
    }
}

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    try {
        return table.getField(fieldName);
    } catch {
        return null;
    }
}

function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);
    if (!field) return false;

    const nonWritableTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "createdBy",
        "lastModifiedBy",
        "autoNumber",
        "button",
        "aiText",
        "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getSingleLinkedId(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (Array.isArray(raw) && raw.length > 0 && raw[0]?.id) {
        return raw[0].id;
    }

    return "";
}

function getLinkedRecordIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) {
        return [];
    }

    return raw.map((item) => item?.id).filter(Boolean);
}

function getBooleanish(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (raw === true) return true;
    if (raw === false) return false;
    if (raw === 1) return true;
    if (raw === 0) return false;

    const value = String(raw ?? "").trim().toLowerCase();
    return ["1", "true", "yes", "checked", "active"].includes(value);
}

async function updateSubmissionSafe(targetRecordId, updates) {
    const safeUpdates = {};

    for (const [fieldName, value] of Object.entries(updates || {})) {
        if (!fieldExists(submissionsTable, fieldName)) {
            log(`Skipped missing Submission field: ${fieldName}`);
            continue;
        }

        if (!isWritableField(submissionsTable, fieldName)) {
            log(`Skipped non-writable Submission field: ${fieldName}`);
            continue;
        }

        if (value === undefined) {
            continue;
        }

        safeUpdates[fieldName] = value;
    }

    if (Object.keys(safeUpdates).length === 0) {
        return false;
    }

    await submissionsTable.updateRecordAsync(targetRecordId, safeUpdates);
    return true;
}

async function clearSubmissionEnrollmentIfNeeded(submissionRecord) {
    if (!CONFIG.debug.clearBadEnrollmentLinks) {
        return false;
    }

    if (!fieldExists(submissionsTable, CONFIG.submissions.enrollment)) {
        return false;
    }

    if (!isWritableField(submissionsTable, CONFIG.submissions.enrollment)) {
        return false;
    }

    const existingEnrollmentLinks = getLinkedRecordIds(
        submissionRecord,
        submissionsTable,
        CONFIG.submissions.enrollment
    );

    if (existingEnrollmentLinks.length === 0) {
        return false;
    }

    await updateSubmissionSafe(recordId, {
        [CONFIG.submissions.enrollment]: [],
    });

    return true;
}

function buildEnrollmentFieldsToLoad() {
    return [
        CONFIG.enrollments.athlete,
        CONFIG.enrollments.active,
        CONFIG.enrollments.programInstance,
        CONFIG.enrollments.enrollmentKey,
    ].filter((fieldName) => fieldExists(enrollmentsTable, fieldName));
}

function buildCandidateFromEnrollment(record) {
    const enrollmentAthleteId = getSingleLinkedId(
        record,
        enrollmentsTable,
        CONFIG.enrollments.athlete
    );

    const enrollmentProgramInstanceId = fieldExists(
        enrollmentsTable,
        CONFIG.enrollments.programInstance
    )
        ? getSingleLinkedId(record, enrollmentsTable, CONFIG.enrollments.programInstance)
        : "";

    const enrollmentKey = fieldExists(enrollmentsTable, CONFIG.enrollments.enrollmentKey)
        ? getText(record, enrollmentsTable, CONFIG.enrollments.enrollmentKey)
        : "";

    const isActive = fieldExists(enrollmentsTable, CONFIG.enrollments.active)
        ? getBooleanish(record, enrollmentsTable, CONFIG.enrollments.active)
        : true;

    return {
        id: record.id,
        enrollmentKey,
        athleteId: enrollmentAthleteId,
        programInstanceId: enrollmentProgramInstanceId,
        isActive,
    };
}

/* =========================================================
   SECTION 5: MAIN
   ========================================================= */

async function main() {
    let debugStep = "Start";
    let submission = null;
    let athleteId = "";
    let existingEnrollmentId = "";
    let submissionProgramInstanceId = "";
    let matchedEnrollmentId = "";
    let matchedEnrollmentKey = "";
    let candidateCount = 0;
    let matchMode = "not-started";

    setOutputSafe("debugStep", debugStep);

    try {
        debugStep = "1 - Validate recordId";
        setOutputSafe("debugStep", debugStep);

        if (!recordId.startsWith("rec")) {
            throw new Error(`Invalid Submission recordId input: ${recordId}`);
        }

        debugStep = "2 - Load Submission";
        setOutputSafe("debugStep", debugStep);

        submission = await submissionsTable.selectRecordAsync(recordId);

        if (!submission) {
            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("athleteIdOut", "");
            setOutputSafe("submissionProgramInstanceIdOut", "");
            setOutputSafe("matchedEnrollmentId", "");
            setOutputSafe("matchedEnrollmentKey", "");
            setOutputSafe("candidateCountOut", 0);
            setOutputSafe("matchModeOut", "");
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", `Submission not found: ${recordId}`);
            setOutputSafe("debugStep", "Skipped: Submission not found");
            return;
        }

        debugStep = "3 - Read Submission Values";
        setOutputSafe("debugStep", debugStep);

        athleteId = getSingleLinkedId(
            submission,
            submissionsTable,
            CONFIG.submissions.athlete
        );

        existingEnrollmentId = getSingleLinkedId(
            submission,
            submissionsTable,
            CONFIG.submissions.enrollment
        );

        submissionProgramInstanceId = fieldExists(
            submissionsTable,
            CONFIG.submissions.programInstance
        )
            ? getSingleLinkedId(
                  submission,
                  submissionsTable,
                  CONFIG.submissions.programInstance
              )
            : "";

        log("Submission input", {
            recordId,
            athleteId,
            existingEnrollmentId,
            submissionProgramInstanceId,
            hasSubmissionProgramInstanceField: fieldExists(
                submissionsTable,
                CONFIG.submissions.programInstance
            ),
        });

        debugStep = "4 - Validate Athlete";
        setOutputSafe("debugStep", debugStep);

        if (!athleteId) {
            await clearSubmissionEnrollmentIfNeeded(submission);

            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("athleteIdOut", "");
            setOutputSafe("submissionProgramInstanceIdOut", submissionProgramInstanceId);
            setOutputSafe("matchedEnrollmentId", "");
            setOutputSafe("matchedEnrollmentKey", "");
            setOutputSafe("candidateCountOut", 0);
            setOutputSafe("matchModeOut", "no-athlete");
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", "Submission is missing Athlete.");
            setOutputSafe("debugStep", "Skipped: Submission missing Athlete");
            return;
        }

        debugStep = "5 - Load Enrollments";
        setOutputSafe("debugStep", debugStep);

        const enrollmentQuery = await enrollmentsTable.selectRecordsAsync({
            fields: buildEnrollmentFieldsToLoad(),
        });

        debugStep = "6 - Find Active Athlete Matches";
        setOutputSafe("debugStep", debugStep);

        let candidates = enrollmentQuery.records
            .map((record) => buildCandidateFromEnrollment(record))
            .filter((candidate) => {
                return candidate.athleteId === athleteId && candidate.isActive;
            });

        matchMode = "athlete-only";

        const canUseProgramInstance =
            fieldExists(submissionsTable, CONFIG.submissions.programInstance) &&
            fieldExists(enrollmentsTable, CONFIG.enrollments.programInstance) &&
            !!submissionProgramInstanceId;

        if (canUseProgramInstance) {
            const narrowed = candidates.filter((candidate) => {
                return candidate.programInstanceId === submissionProgramInstanceId;
            });

            if (narrowed.length > 0) {
                candidates = narrowed;
                matchMode = "athlete-plus-program-instance";
            } else {
                matchMode = "athlete-only-program-instance-no-match";
            }
        }

        candidateCount = candidates.length;

        log("Enrollment match candidates", {
            candidateCount,
            matchMode,
            candidates,
        });

        debugStep = "7 - Resolve Candidate Count";
        setOutputSafe("debugStep", debugStep);

        if (candidates.length === 0) {
            await clearSubmissionEnrollmentIfNeeded(submission);

            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("athleteIdOut", athleteId);
            setOutputSafe("submissionProgramInstanceIdOut", submissionProgramInstanceId);
            setOutputSafe("matchedEnrollmentId", "");
            setOutputSafe("matchedEnrollmentKey", "");
            setOutputSafe("candidateCountOut", 0);
            setOutputSafe("matchModeOut", matchMode);
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", "No matching active Enrollment found for this Submission.");
            setOutputSafe("debugStep", "Skipped: No matching Enrollment");
            return;
        }

        if (candidates.length > 1) {
            await clearSubmissionEnrollmentIfNeeded(submission);

            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("athleteIdOut", athleteId);
            setOutputSafe("submissionProgramInstanceIdOut", submissionProgramInstanceId);
            setOutputSafe("matchedEnrollmentId", "");
            setOutputSafe("matchedEnrollmentKey", "");
            setOutputSafe("candidateCountOut", candidates.length);
            setOutputSafe("matchModeOut", matchMode);
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe(
                "errorOut",
                `Multiple matching active Enrollments found (${candidates.length}). Submission was not updated.`
            );
            setOutputSafe("debugStep", "Skipped: Multiple matching Enrollments");
            return;
        }

        const chosen = candidates[0];
        matchedEnrollmentId = chosen.id;
        matchedEnrollmentKey = chosen.enrollmentKey;

        debugStep = "8 - Write Enrollment Link";
        setOutputSafe("debugStep", debugStep);

        const shouldWrite =
            !existingEnrollmentId || existingEnrollmentId !== matchedEnrollmentId;

        if (shouldWrite) {
            await updateSubmissionSafe(recordId, {
                [CONFIG.submissions.enrollment]: [{ id: matchedEnrollmentId }],
            });
        }

        debugStep = "9 - Outputs";
        setOutputSafe("debugStep", debugStep);

        setOutputSafe("ok", true);
        setOutputSafe("recordId", recordId);
        setOutputSafe("athleteIdOut", athleteId);
        setOutputSafe("submissionProgramInstanceIdOut", submissionProgramInstanceId);
        setOutputSafe("matchedEnrollmentId", matchedEnrollmentId);
        setOutputSafe("matchedEnrollmentKey", matchedEnrollmentKey);
        setOutputSafe("candidateCountOut", 1);
        setOutputSafe("matchModeOut", matchMode);
        setOutputSafe("statusOut", CONFIG.statuses.complete);
        setOutputSafe("errorOut", "");

        log("Submission Enrollment assignment completed", {
            recordId,
            athleteId,
            matchedEnrollmentId,
            matchedEnrollmentKey,
            matchMode,
            wroteUpdate: shouldWrite,
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        setOutputSafe("ok", false);
        setOutputSafe("recordId", recordId);
        setOutputSafe("athleteIdOut", athleteId);
        setOutputSafe("submissionProgramInstanceIdOut", submissionProgramInstanceId);
        setOutputSafe("matchedEnrollmentId", matchedEnrollmentId);
        setOutputSafe("matchedEnrollmentKey", matchedEnrollmentKey);
