    debugStep = "4 - Validate Submission Links";
    setOutputSafe("debugStep", debugStep);

    if (!submissionEnrollmentId) {
      throw new Error(`Submission ${recordId} is missing Enrollment link.`);
    }

    if (!submissionWeekId) {
      throw new Error(
        `Submission ${recordId} is missing Week link. Run the Week assignment automation before this automation.`
      );
    }

    if (existingSubmissionSummaryId) {
      weeklySummaryId = existingSubmissionSummaryId;
      actionTaken = "already_linked_to_summary";

      setOutputSafe("ok", true);
      setOutputSafe("recordId", recordId);
      setOutputSafe("weeklySummaryId", weeklySummaryId);
      setOutputSafe("summaryKeyOut", "");
      setOutputSafe("weekId", submissionWeekId);
      setOutputSafe("weekName", "");
      setOutputSafe("actionTaken", actionTaken);
      setOutputSafe("statusOut", CONFIG.outputStatuses.found);
      setOutputSafe("errorOut", "");
      setOutputSafe("debugStep", "Done - Already linked");

      log("Submission already linked to Weekly Athlete Summary", {
        recordId,
        weeklySummaryId,
      });

      return;
    }

    debugStep = "5 - Load Enrollment";
    setOutputSafe("debugStep", debugStep);

    const enrollment = await enrollmentsTable.selectRecordAsync(submissionEnrollmentId);

    if (!enrollment) {
      throw new Error(`Enrollment not found: ${submissionEnrollmentId}`);
    }

    const enrollmentKey = getText(
      enrollment,
      enrollmentsTable,
      CONFIG.enrollments.enrollmentKey
    );

    if (!enrollmentKey) {
      throw new Error(`Enrollment Key is blank for Enrollment ${submissionEnrollmentId}.`);
    }

    debugStep = "6 - Load Week";
    setOutputSafe("debugStep", debugStep);

    const weekRecord = await weeksTable.selectRecordAsync(submissionWeekId);

    if (!weekRecord) {
      throw new Error(`Week not found: ${submissionWeekId}`);
    }

    const resolvedWeekKey = getText(weekRecord, weeksTable, CONFIG.weeks.weekKey);
    resolvedWeekName = getText(weekRecord, weeksTable, CONFIG.weeks.weekName);

    if (!resolvedWeekKey) {
      throw new Error(`Week Key is blank for Week ${submissionWeekId}.`);
    }

    targetSummaryKey = `${enrollmentKey}|${resolvedWeekKey}`;

    debugStep = "7 - Load Weekly Athlete Summaries";
    setOutputSafe("debugStep", debugStep);

    const summariesQuery = await summariesTable.selectRecordsAsync({
      fields: buildSummaryFieldsToLoad(),
    });

    debugStep = "8 - Find Matching Summary";
    setOutputSafe("debugStep", debugStep);

    const matchingSummaries = summariesQuery.records.filter(summary => {
      const summaryKey = getText(
        summary,
        summariesTable,
        CONFIG.summaries.summaryKey
      );

      return summaryKey === targetSummaryKey;
    });

    if (
      matchingSummaries.length > 1 &&
      CONFIG.flags.throwOnDuplicateSummaryKey
    ) {
      const duplicateIds = matchingSummaries.map(record => record.id).join(", ");

      throw new Error(
        `Duplicate Weekly Athlete Summary records found for Summary Key ${targetSummaryKey}. Record IDs: ${duplicateIds}`
      );
    }

    debugStep = "9 - Find or Create Summary";
    setOutputSafe("debugStep", debugStep);

    if (matchingSummaries.length === 1) {
      const matchingSummary = matchingSummaries[0];

      const existingSubmissionIds = getLinkedRecordIds(
        matchingSummary,
        summariesTable,
        CONFIG.summaries.submissions
      );

      const mergedSubmissionIds = uniqueIds([...existingSubmissionIds, recordId]);

      const summaryUpdates = {
        ...buildSummaryStatusUpdate(),
      };

      if (!sameIdArray(existingSubmissionIds, mergedSubmissionIds)) {
        summaryUpdates[CONFIG.summaries.submissions] = linkedCell(mergedSubmissionIds);
      }

      updatedFields = await updateRecordSafe(
        summariesTable,
        matchingSummary.id,
        summaryUpdates
      );

      weeklySummaryId = matchingSummary.id;
      actionTaken = "found_existing_summary";
    } else {
      const createFields = {
        [CONFIG.summaries.enrollment]: [{ id: submissionEnrollmentId }],
        [CONFIG.summaries.week]: [{ id: submissionWeekId }],
        [CONFIG.summaries.submissions]: [{ id: recordId }],
        ...buildSummaryStatusUpdate(),
      };

      weeklySummaryId = await createRecordSafe(summariesTable, createFields);
      actionTaken = "created_new_summary";
    }

    debugStep = "10 - Link Summary Back to Submission";
    setOutputSafe("debugStep", debugStep);

    await updateRecordSafe(submissionsTable, recordId, {
      [CONFIG.submissions.weeklySummary]: [{ id: weeklySummaryId }],
    });

    debugStep = "11 - Validate Final Summary";
    setOutputSafe("debugStep", debugStep);

    const finalSummary = await summariesTable.selectRecordAsync(weeklySummaryId);

    if (!finalSummary) {
      throw new Error(
        `Weekly Athlete Summary could not be reloaded after find/create: ${weeklySummaryId}`
      );
    }

    const finalEnrollmentId = getFirstLinkedRecordId(
      finalSummary,
      summariesTable,
      CONFIG.summaries.enrollment
    );

    const finalWeekId = getFirstLinkedRecordId(
      finalSummary,
      summariesTable,
      CONFIG.summaries.week
    );

    const finalSubmissionIds = getLinkedRecordIds(
      finalSummary,
      summariesTable,
      CONFIG.summaries.submissions
    );

    if (finalEnrollmentId !== submissionEnrollmentId) {
      throw new Error(
        `Weekly Athlete Summary has wrong Enrollment. Expected ${submissionEnrollmentId}, got ${finalEnrollmentId || "(blank)"}`
      );
    }

    if (finalWeekId !== submissionWeekId) {
      throw new Error(
        `Weekly Athlete Summary has wrong Week. Expected ${submissionWeekId}, got ${finalWeekId || "(blank)"}`
      );
    }

    if (!finalSubmissionIds.includes(recordId)) {
      throw new Error("Weekly Athlete Summary is missing the source Submission link.");
    }

    debugStep = "12 - Outputs";
    setOutputSafe("debugStep", debugStep);

    setOutputSafe("ok", true);
    setOutputSafe("recordId", recordId);
    setOutputSafe("weeklySummaryId", weeklySummaryId);
    setOutputSafe("summaryKeyOut", targetSummaryKey);
    setOutputSafe("weekId", submissionWeekId);
    setOutputSafe("weekName", resolvedWeekName);
    setOutputSafe("actionTaken", actionTaken);
    setOutputSafe(
      "statusOut",
      actionTaken === "created_new_summary"
        ? CONFIG.outputStatuses.created
        : CONFIG.outputStatuses.found
    );
    setOutputSafe("errorOut", "");

    log("Weekly Summary find/create completed", {
      recordId,
      weeklySummaryId,
      summaryKeyOut: targetSummaryKey,
      actionTaken,
      updatedFields,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setOutputSafe("ok", false);
    setOutputSafe("recordId", recordId);
    setOutputSafe("weeklySummaryId", weeklySummaryId);
    setOutputSafe("summaryKeyOut", targetSummaryKey);
    setOutputSafe("weekId", submissionWeekId);
    setOutputSafe("weekName", resolvedWeekName);
    setOutputSafe("actionTaken", actionTaken);
    setOutputSafe("statusOut", CONFIG.outputStatuses.error);
    setOutputSafe("errorOut", message);
    setOutputSafe("debugStep", `FAILED AT: ${debugStep}`);

    log("Weekly Summary find/create failed", {
      recordId,
      debugStep,
      error: message,
    });

    throw error;
  }
}

/* =========================================================
   SECTION 7: RUN
========================================================= */

await main();

/************************************************************
 * 032 - WEEKLY SUMMARY AND GOAL LOGIC
 * Link Challenge Goal Record to Weekly Athlete Summary
 *
 * Version: v3.2
 * Date Written: 2026-05-27
 * Last Updated: 2026-05-27
 *
 * PURPOSE
 * - Runs from one Weekly Athlete Summary record.
 * - Reads the linked Grade Band.
 * - Finds the matching Target Goal Shots record for the entire challenge.
 * - Matches Target Goal Shots by Grade Band only.
 * - Requires Target Goal Shots.Active? to be checked if that field exists.
 * - Writes the matching Target Goal Shots record into Weekly Athlete Summary → Goal Record.
 *
 * IMPORTANT DESIGN RULES
 * - Target Goal Shots are challenge-wide goals, not weekly goals.
 * - Do NOT match Target Goal Shots by Week.
 * - Week may exist on Weekly Athlete Summary, but it is not used for goal matching.
 * - One active Target Goal Shots record should exist per Grade Band.
 * - Do not create Target Goal Shots records here.
 * - Do not write to formula, lookup, rollup, or other read-only fields.
 *
 * FOLDER
 * - 03 - Weekly Summary and Goal Logic
 *
 * AUTOMATION NAME
 * - 032 - Weekly Summary and Goal Logic - Link Challenge Goal Record to Weekly Athlete Summary
 *
 * TRIGGER TABLE
 * - Weekly Athlete Summary
 *
 * TRIGGER TYPE
 * - When record enters view
 *
 * RECOMMENDED TRIGGER VIEW CONDITIONS
 * - Grade Band is not empty
 * - Goal Record is empty
 * - Week is not empty
 *
 * REQUIRED AUTOMATION INPUT
 * - recordId = Airtable record ID from the triggering Weekly Athlete Summary record
 *
 * TABLES USED
 * - Weekly Athlete Summary
 * - Target Goal Shots
 *
 * OUTPUTS
 * - ok
 * - weeklySummaryId
 * - gradeBandId
 * - goalRecordId
 * - goalLabel
 * - matchCount
 * - actionTaken
 * - statusOut
 * - errorOut
 * - debugStep
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: CONFIG
========================================================= */

const CONFIG = {
  scriptName: "032 - Weekly Summary and Goal Logic - Link Challenge Goal Record to Weekly Athlete Summary",
  version: "v3.2",

  tables: {
    weeklySummary: "Weekly Athlete Summary",
    targetGoalShots: "Target Goal Shots",
  },

  weeklySummary: {
    week: "Week",
    gradeBand: "Grade Band",
    goalRecord: "Goal Record",
  },

  targetGoalShots: {
    targetLabel: "Target Label",
    goalKey: "Goal Key",
    gradeBand: "Grade Band",
    totalShotTarget: "Total Shot Target",
    active: "Active?",
  },

  statuses: {
    success: "success",
    skipped: "skipped",
    error: "error",
  },

  actions: {
    linkedGoalRecord: "linked_goal_record",
    alreadyLinked: "already_linked",
    skippedNoMatch: "skipped_no_matching_challenge_goal_record",
    errorDuplicateMatches: "error_duplicate_challenge_goal_records",
  },

  debug: {
    logToConsole: true,
    requireActiveGoalRecord: true,
  },
};

/* =========================================================
   SECTION 2: INPUTS
========================================================= */

const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
  throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLE REFERENCES
========================================================= */

const weeklySummaryTable = base.getTable(CONFIG.tables.weeklySummary);
const targetGoalShotsTable = base.getTable(CONFIG.tables.targetGoalShots);

/* =========================================================
   SECTION 4: HELPER FUNCTIONS
========================================================= */

function log(message, data = null) {
  if (!CONFIG.debug.logToConsole) return;

  if (data === null || data === undefined) {
    console.log(message);
  } else {
    console.log(message, JSON.stringify(data, null, 2));
  }
}

function setOutputSafe(key, value) {
  try {
    output.set(key, value);
  } catch {
    // Ignore output mapping errors.
  }
}

function fieldExists(table, fieldName) {
  if (!table || !fieldName) return false;

  try {
    table.getField(fieldName);
    return true;
  } catch {
    return false;
  }
}

function getFieldSafe(table, fieldName) {
  if (!table || !fieldName) return null;

  try {
    return table.getField(fieldName);
  } catch {
    return null;
  }
}

function isWritableField(table, fieldName) {
  const field = getFieldSafe(table, fieldName);
  if (!field) return false;

  const nonWritableTypes = new Set([
    "formula",
    "rollup",
    "count",
    "lookup",
    "multipleLookupValues",
    "createdTime",
    "lastModifiedTime",
    "createdBy",
    "lastModifiedBy",
    "autoNumber",
    "button",
    "aiText",
    "externalSyncSource",
  ]);

  return !nonWritableTypes.has(field.type);
}

function requireField(table, fieldName, label) {
  if (!fieldExists(table, fieldName)) {
    throw new Error(`Missing required field: ${label} (${table.name} -> ${fieldName})`);
  }
}

function requireWritableField(table, fieldName, label) {
  requireField(table, fieldName, label);

  if (!isWritableField(table, fieldName)) {
    throw new Error(`Required field is not writable: ${label} (${table.name} -> ${fieldName})`);
  }
}

function getRaw(record, table, fieldName) {
  if (!record || !fieldExists(table, fieldName)) return null;
  return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
  if (!record || !fieldExists(table, fieldName)) return "";
  return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getBooleanish(record, table, fieldName) {
  const raw = getRaw(record, table, fieldName);

  if (raw === true) return true;
  if (raw === false) return false;
  if (raw === 1) return true;
  if (raw === 0) return false;

  const text = String(raw ?? "").trim().toLowerCase();
  return ["1", "true", "yes", "checked", "active"].includes(text);
}

function getLinkedRecordIds(record, table, fieldName) {
  const raw = getRaw(record, table, fieldName);

  if (!Array.isArray(raw)) return [];

  return raw
    .map(item => item?.id)
    .filter(Boolean);
}

function getFirstLinkedRecordId(record, table, fieldName) {
  const ids = getLinkedRecordIds(record, table, fieldName);
  return ids[0] || "";
}

async function updateRecordSafe(table, targetRecordId, updates) {
  const safeUpdates = {};

  for (const [fieldName, value] of Object.entries(updates || {})) {
    if (!fieldExists(table, fieldName)) {
      log(`Skipped missing field: ${table.name}.${fieldName}`);
      continue;
    }

    if (!isWritableField(table, fieldName)) {
      log(`Skipped non-writable field: ${table.name}.${fieldName}`);
      continue;
    }

    if (value === undefined || value === null) {
      continue;
    }

    safeUpdates[fieldName] = value;
  }

  if (Object.keys(safeUpdates).length === 0) {
    return [];
  }

  await table.updateRecordAsync(targetRecordId, safeUpdates);
  return Object.keys(safeUpdates);
}

function buildTargetGoalFieldsToLoad() {
  return [
    CONFIG.targetGoalShots.targetLabel,
    CONFIG.targetGoalShots.goalKey,
    CONFIG.targetGoalShots.gradeBand,
    CONFIG.targetGoalShots.totalShotTarget,
    CONFIG.targetGoalShots.active,
  ].filter(fieldName => fieldExists(targetGoalShotsTable, fieldName));
}

function setFinalOutputs({
  ok,
  weeklySummaryId,
  gradeBandId,
  goalRecordId,
  goalLabel,
  matchCount,
  actionTaken,
  statusOut,
  errorOut,
  debugStep,
}) {
  setOutputSafe("ok", ok);
  setOutputSafe("weeklySummaryId", weeklySummaryId || recordId);
  setOutputSafe("gradeBandId", gradeBandId || "");
  setOutputSafe("goalRecordId", goalRecordId || "");
  setOutputSafe("goalLabel", goalLabel || "");
  setOutputSafe("matchCount", matchCount || 0);
  setOutputSafe("actionTaken", actionTaken || "");
  setOutputSafe("statusOut", statusOut || "");
  setOutputSafe("errorOut", errorOut || "");
  setOutputSafe("debugStep", debugStep || "");
}

/* =========================================================
   SECTION 5: FIELD VALIDATION
========================================================= */

requireField(
  weeklySummaryTable,
  CONFIG.weeklySummary.week,
  "Weekly Athlete Summary -> Week"
);

requireField(
  weeklySummaryTable,
  CONFIG.weeklySummary.gradeBand,
  "Weekly Athlete Summary -> Grade Band"
);

requireWritableField(
  weeklySummaryTable,
  CONFIG.weeklySummary.goalRecord,
  "Weekly Athlete Summary -> Goal Record"
);

requireField(
  targetGoalShotsTable,
  CONFIG.targetGoalShots.gradeBand,
  "Target Goal Shots -> Grade Band"
);

if (
  CONFIG.debug.requireActiveGoalRecord &&
  fieldExists(targetGoalShotsTable, CONFIG.targetGoalShots.active)
) {
  requireField(
    targetGoalShotsTable,
    CONFIG.targetGoalShots.active,
    "Target Goal Shots -> Active?"
  );
}

/* =========================================================
   SECTION 6: MAIN
========================================================= */

async function main() {
  let debugStep = "Start";

  let gradeBandId = "";
  let goalRecordId = "";
  let goalLabel = "";
  let matchCount = 0;
  let actionTaken = "";

  try {
    debugStep = "1 - Validate recordId";
    setOutputSafe("debugStep", debugStep);

    if (!recordId.startsWith("rec")) {
      throw new Error(`Invalid Weekly Athlete Summary recordId input: ${recordId}`);
    }

    debugStep = "2 - Load Weekly Athlete Summary";
    setOutputSafe("debugStep", debugStep);

    const summaryRecord = await weeklySummaryTable.selectRecordAsync(recordId);

    if (!summaryRecord) {
      setFinalOutputs({
        ok: false,
        weeklySummaryId: recordId,
        actionTaken: "summary_not_found",
        statusOut: CONFIG.statuses.error,
        errorOut: `Weekly Athlete Summary record not found: ${recordId}`,
        debugStep,
      });
      return;
    }

    debugStep = "3 - Read Weekly Summary Links";
    setOutputSafe("debugStep", debugStep);

    const weekId = getFirstLinkedRecordId(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.week
    );

    gradeBandId = getFirstLinkedRecordId(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.gradeBand
    );

    const existingGoalRecordId = getFirstLinkedRecordId(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.goalRecord
    );

    log("032 input", {
      recordId,
      weekId,
      gradeBandId,
      existingGoalRecordId,
      matchingRule: "Grade Band + Active only. Week is not used.",
    });

    debugStep = "4 - Validate Weekly Summary State";
    setOutputSafe("debugStep", debugStep);

    if (existingGoalRecordId) {
      goalRecordId = existingGoalRecordId;
      actionTaken = CONFIG.actions.alreadyLinked;

      setFinalOutputs({
        ok: true,
        weeklySummaryId: recordId,
        gradeBandId,
        goalRecordId,
        goalLabel: "",
        matchCount: 1,
        actionTaken,
        statusOut: CONFIG.statuses.skipped,
        errorOut: "",
        debugStep: "Done - Already linked",
      });

      log("032 skipped because Goal Record was already linked", {
        recordId,
        goalRecordId,
      });

      return;
    }

    if (!weekId) {
      throw new Error("Weekly Athlete Summary is missing Week.");
    }

    if (!gradeBandId) {
      throw new Error("Weekly Athlete Summary is missing Grade Band.");
    }

    debugStep = "5 - Load Target Goal Shots";
    setOutputSafe("debugStep", debugStep);

    const goalsQuery = await targetGoalShotsTable.selectRecordsAsync({
      fields: buildTargetGoalFieldsToLoad(),
    });

    debugStep = "6 - Find Matching Challenge Goal Record";
    setOutputSafe("debugStep", debugStep);

    const matchingGoals = goalsQuery.records.filter(goalRecord => {
      const goalGradeBandId = getFirstLinkedRecordId(
        goalRecord,
        targetGoalShotsTable,
        CONFIG.targetGoalShots.gradeBand
      );

      if (goalGradeBandId !== gradeBandId) {
        return false;
      }

      if (
        CONFIG.debug.requireActiveGoalRecord &&
        fieldExists(targetGoalShotsTable, CONFIG.targetGoalShots.active)
      ) {
        return getBooleanish(
          goalRecord,
          targetGoalShotsTable,
          CONFIG.targetGoalShots.active
        );
      }

      return true;
    });

    matchCount = matchingGoals.length;

    if (matchCount === 0) {
      actionTaken = CONFIG.actions.skippedNoMatch;

      setFinalOutputs({
        ok: true,
        weeklySummaryId: recordId,
        gradeBandId,
        goalRecordId: "",
        goalLabel: "",
        matchCount,
        actionTaken,
        statusOut: CONFIG.statuses.skipped,
        errorOut: "No active challenge-wide Target Goal Shots record found for this Grade Band.",
        debugStep,
      });

      log("032 skipped: no matching challenge-wide Target Goal Shots record", {
        recordId,
        gradeBandId,
      });

      return;
    }

    if (matchCount > 1) {
      const duplicateIds = matchingGoals.map(record => record.id).join(", ");

      actionTaken = CONFIG.actions.errorDuplicateMatches;

      throw new Error(
        `Multiple active challenge-wide Target Goal Shots records found for this Grade Band. Record IDs: ${duplicateIds}`
      );
    }

    const matchedGoal = matchingGoals[0];
    goalRecordId = matchedGoal.id;

    goalLabel =
      getText(matchedGoal, targetGoalShotsTable, CONFIG.targetGoalShots.targetLabel) ||
      getText(matchedGoal, targetGoalShotsTable, CONFIG.targetGoalShots.goalKey) ||
      matchedGoal.name ||
      goalRecordId;

    debugStep = "7 - Write Goal Record Link";
    setOutputSafe("debugStep", debugStep);

    const updatedFields = await updateRecordSafe(weeklySummaryTable, recordId, {
      [CONFIG.weeklySummary.goalRecord]: [{ id: goalRecordId }],
    });

    actionTaken = CONFIG.actions.linkedGoalRecord;

    debugStep = "8 - Outputs";
    setOutputSafe("debugStep", debugStep);

    setFinalOutputs({
      ok: true,
      weeklySummaryId: recordId,
      gradeBandId,
      goalRecordId,
      goalLabel,
      matchCount,
      actionTaken,
      statusOut: CONFIG.statuses.success,
      errorOut: "",
      debugStep,
    });

    log("032 completed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      recordId,
      gradeBandId,
      goalRecordId,
      goalLabel,
      updatedFields,
      actionTaken,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setFinalOutputs({
      ok: false,
      weeklySummaryId: recordId,
      gradeBandId,
      goalRecordId,
      goalLabel,
      matchCount,
      actionTaken: actionTaken || "error",
      statusOut: CONFIG.statuses.error,
      errorOut: message,
      debugStep: `FAILED AT: ${debugStep}`,
    });

    log("032 failed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      recordId,
      debugStep,
      error: message,
      gradeBandId,
    });

    throw error;
  }
}

/* =========================================================
   SECTION 7: RUN
========================================================= */

await main();

