const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
  throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLE REFERENCES
========================================================= */

const weeklySummaryTable = base.getTable(CONFIG.tables.weeklySummary);
const curriculumTable = base.getTable(CONFIG.tables.curriculum);

/* =========================================================
   SECTION 4: HELPER FUNCTIONS
========================================================= */

function log(message, data = null) {
  if (!CONFIG.debug.logToConsole) return;

  if (data === null || data === undefined) {
    console.log(message);
  } else {
    console.log(message, JSON.stringify(data, null, 2));
  }
}

function setOutputSafe(key, value) {
  try {
    output.set(key, value);
  } catch {
    // Ignore output mapping errors.
  }
}

function fieldExists(table, fieldName) {
  if (!table || !fieldName) return false;

  try {
    table.getField(fieldName);
    return true;
  } catch {
    return false;
  }
}

function getFieldSafe(table, fieldName) {
  if (!table || !fieldName) return null;

  try {
    return table.getField(fieldName);
  } catch {
    return null;
  }
}

function isWritableField(table, fieldName) {
  const field = getFieldSafe(table, fieldName);
  if (!field) return false;

  const nonWritableTypes = new Set([
    "formula",
    "rollup",
    "count",
    "lookup",
    "multipleLookupValues",
    "createdTime",
    "lastModifiedTime",
    "createdBy",
    "lastModifiedBy",
    "autoNumber",
    "button",
    "aiText",
    "externalSyncSource",
  ]);

  return !nonWritableTypes.has(field.type);
}

function requireField(table, fieldName, label) {
  if (!fieldExists(table, fieldName)) {
    throw new Error(`Missing required field: ${label} (${table.name} -> ${fieldName})`);
  }
}

function requireWritableField(table, fieldName, label) {
  requireField(table, fieldName, label);

  if (!isWritableField(table, fieldName)) {
    throw new Error(`Required field is not writable: ${label} (${table.name} -> ${fieldName})`);
  }
}

function getRaw(record, table, fieldName) {
  if (!record || !fieldExists(table, fieldName)) return null;
  return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
  if (!record || !fieldExists(table, fieldName)) return "";
  return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getNumber(record, table, fieldName, fallback = 999999) {
  const raw = getRaw(record, table, fieldName);

  if (typeof raw === "number" && Number.isFinite(raw)) {
    return raw;
  }

  const text = String(raw ?? "").replace(/,/g, "").trim();
  if (!text) return fallback;

  const parsed = Number(text);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function getBooleanish(record, table, fieldName) {
  const raw = getRaw(record, table, fieldName);

  if (raw === true) return true;
  if (raw === false) return false;
  if (raw === 1) return true;
  if (raw === 0) return false;

  const text = String(raw ?? "").trim().toLowerCase();
  return ["1", "true", "yes", "checked", "active"].includes(text);
}

function getLinkedRecordIds(record, table, fieldName) {
  const raw = getRaw(record, table, fieldName);

  if (!Array.isArray(raw)) return [];

  return raw
    .map(item => item?.id)
    .filter(Boolean);
}

function getFirstLinkedRecordId(record, table, fieldName) {
  const ids = getLinkedRecordIds(record, table, fieldName);
  return ids[0] || "";
}

function linkedCell(ids) {
  return [...new Set((ids || []).filter(Boolean))].map(id => ({ id }));
}

async function updateRecordSafe(table, targetRecordId, updates) {
  const safeUpdates = {};

  for (const [fieldName, value] of Object.entries(updates || {})) {
    if (!fieldExists(table, fieldName)) {
      log(`Skipped missing field: ${table.name}.${fieldName}`);
      continue;
    }

    if (!isWritableField(table, fieldName)) {
      log(`Skipped non-writable field: ${table.name}.${fieldName}`);
      continue;
    }

    if (value === undefined || value === null) {
      continue;
    }

    safeUpdates[fieldName] = value;
  }

  if (Object.keys(safeUpdates).length === 0) {
    return [];
  }

  await table.updateRecordAsync(targetRecordId, safeUpdates);
  return Object.keys(safeUpdates);
}

function buildCurriculumFieldsToLoad() {
  return [
    CONFIG.curriculum.assignmentFullName,
    CONFIG.curriculum.week,
    CONFIG.curriculum.gradeBand,
    CONFIG.curriculum.active,
    CONFIG.curriculum.published,
    CONFIG.curriculum.assignmentNumber,
  ].filter(fieldName => fieldExists(curriculumTable, fieldName));
}

function setFinalOutputs({
  ok,
  weeklySummaryId,
  weekId,
  gradeBandId,
  matchedCountOut,
  homeworkIdsOut,
  homeworkTitlesOut,
  updatedOut,
  actionTaken,
  statusOut,
  errorOut,
  debugStep,
}) {
  setOutputSafe("ok", ok);
  setOutputSafe("weeklySummaryId", weeklySummaryId || recordId);
  setOutputSafe("weekId", weekId || "");
  setOutputSafe("gradeBandId", gradeBandId || "");
  setOutputSafe("matchedCountOut", matchedCountOut || 0);
  setOutputSafe("homeworkIdsOut", homeworkIdsOut || "");
  setOutputSafe("homeworkTitlesOut", homeworkTitlesOut || "");
  setOutputSafe("updatedOut", Boolean(updatedOut));
  setOutputSafe("actionTaken", actionTaken || "");
  setOutputSafe("statusOut", statusOut || "");
  setOutputSafe("errorOut", errorOut || "");
  setOutputSafe("debugStep", debugStep || "");
}

/* =========================================================
   SECTION 5: FIELD VALIDATION
========================================================= */

requireField(
  weeklySummaryTable,
  CONFIG.weeklySummary.week,
  "Weekly Athlete Summary -> Week"
);

requireField(
  weeklySummaryTable,
  CONFIG.weeklySummary.gradeBand,
  "Weekly Athlete Summary -> Grade Band"
);

requireWritableField(
  weeklySummaryTable,
  CONFIG.weeklySummary.homework,
  "Weekly Athlete Summary -> Homework"
);

requireField(
  curriculumTable,
  CONFIG.curriculum.week,
  "FBC Curriculum - SYNC -> Week"
);

requireField(
  curriculumTable,
  CONFIG.curriculum.gradeBand,
  "FBC Curriculum - SYNC -> Grade Band"
);

if (CONFIG.debug.requireActive && fieldExists(curriculumTable, CONFIG.curriculum.active)) {
  requireField(
    curriculumTable,
    CONFIG.curriculum.active,
    "FBC Curriculum - SYNC -> Active?"
  );
}

if (CONFIG.debug.requirePublished && fieldExists(curriculumTable, CONFIG.curriculum.published)) {
  requireField(
    curriculumTable,
    CONFIG.curriculum.published,
    "FBC Curriculum - SYNC -> Published?"
  );
}

/* =========================================================
   SECTION 6: MAIN
========================================================= */

async function main() {
  let debugStep = "Start";

  let weekId = "";
  let gradeBandId = "";
  let matchedHomeworkIds = [];
  let homeworkTitles = [];
  let actionTaken = "";
  let updatedFields = [];

  try {
    debugStep = "1 - Validate recordId";
    setOutputSafe("debugStep", debugStep);

    if (!recordId.startsWith("rec")) {
      throw new Error(`Invalid Weekly Athlete Summary recordId input: ${recordId}`);
    }

    debugStep = "2 - Load Weekly Athlete Summary";
    setOutputSafe("debugStep", debugStep);

    const summaryRecord = await weeklySummaryTable.selectRecordAsync(recordId);

    if (!summaryRecord) {
      setFinalOutputs({
        ok: false,
        weeklySummaryId: recordId,
        actionTaken: "summary_not_found",
        statusOut: CONFIG.statuses.error,
        errorOut: `Weekly Athlete Summary record not found: ${recordId}`,
        debugStep,
      });
      return;
    }

    debugStep = "3 - Read Summary Links";
    setOutputSafe("debugStep", debugStep);

    weekId = getFirstLinkedRecordId(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.week
    );

    gradeBandId = getFirstLinkedRecordId(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.gradeBand
    );

    const existingHomeworkIds = getLinkedRecordIds(
      summaryRecord,
      weeklySummaryTable,
      CONFIG.weeklySummary.homework
    );

    log("033 input", {
      recordId,
      weekId,
      gradeBandId,
      existingHomeworkIds,
    });

    debugStep = "4 - Validate Summary State";
    setOutputSafe("debugStep", debugStep);

    if (existingHomeworkIds.length > 0) {
      actionTaken = CONFIG.actions.alreadyAssigned;

      setFinalOutputs({
        ok: true,
        weeklySummaryId: recordId,
        weekId,
        gradeBandId,
        matchedCountOut: existingHomeworkIds.length,
        homeworkIdsOut: existingHomeworkIds.join(", "),
        homeworkTitlesOut: "",
        updatedOut: false,
        actionTaken,
        statusOut: CONFIG.statuses.skipped,
        errorOut: "",
        debugStep: "Done - Already assigned",
      });

      return;
    }

    if (!weekId) {
      throw new Error("Weekly Athlete Summary is missing Week.");
    }

    if (!gradeBandId) {
      throw new Error("Weekly Athlete Summary is missing Grade Band.");
    }

    debugStep = "5 - Load Curriculum Records";
    setOutputSafe("debugStep", debugStep);

    const curriculumQuery = await curriculumTable.selectRecordsAsync({
      fields: buildCurriculumFieldsToLoad(),
    });

    debugStep = "6 - Find Matching Homework";
    setOutputSafe("debugStep", debugStep);

    const matchingHomework = curriculumQuery.records.filter(homeworkRecord => {
      const homeworkWeekId = getFirstLinkedRecordId(
        homeworkRecord,
        curriculumTable,
        CONFIG.curriculum.week
      );

      const homeworkGradeBandIds = getLinkedRecordIds(
        homeworkRecord,
        curriculumTable,
        CONFIG.curriculum.gradeBand
      );

      if (homeworkWeekId !== weekId) return false;
      if (!homeworkGradeBandIds.includes(gradeBandId)) return false;

      if (
        CONFIG.debug.requireActive &&
        fieldExists(curriculumTable, CONFIG.curriculum.active)
      ) {
        if (!getBooleanish(homeworkRecord, curriculumTable, CONFIG.curriculum.active)) {
          return false;
        }
      }

      if (
        CONFIG.debug.requirePublished &&
        fieldExists(curriculumTable, CONFIG.curriculum.published)
      ) {
        if (!getBooleanish(homeworkRecord, curriculumTable, CONFIG.curriculum.published)) {
          return false;
        }
      }

      return true;
    });

    matchingHomework.sort((a, b) => {
      const aOrder = getNumber(a, curriculumTable, CONFIG.curriculum.assignmentNumber, 999999);
      const bOrder = getNumber(b, curriculumTable, CONFIG.curriculum.assignmentNumber, 999999);

      if (aOrder !== bOrder) return aOrder - bOrder;

      const aName = getText(a, curriculumTable, CONFIG.curriculum.assignmentFullName) || a.name;
      const bName = getText(b, curriculumTable, CONFIG.curriculum.assignmentFullName) || b.name;

      return aName.localeCompare(bName);
    });

    matchedHomeworkIds = matchingHomework.map(record => record.id);

    homeworkTitles = matchingHomework.map(record => {
      return (
        getText(record, curriculumTable, CONFIG.curriculum.assignmentFullName) ||
        record.name ||
        record.id
      );
    });

    if (matchedHomeworkIds.length === 0) {
      actionTaken = CONFIG.actions.skippedNoMatches;

      setFinalOutputs({
        ok: true,
        weeklySummaryId: recordId,
        weekId,
        gradeBandId,
        matchedCountOut: 0,
        homeworkIdsOut: "",
        homeworkTitlesOut: "",
        updatedOut: false,
        actionTaken,
        statusOut: CONFIG.statuses.skipped,
        errorOut: "No active/published homework found for this Week + Grade Band.",
        debugStep,
      });

      log("033 skipped: no matching homework", {
        recordId,
        weekId,
        gradeBandId,
      });

      return;
    }

    debugStep = "7 - Write Homework Links";
    setOutputSafe("debugStep", debugStep);

    updatedFields = await updateRecordSafe(weeklySummaryTable, recordId, {
      [CONFIG.weeklySummary.homework]: linkedCell(matchedHomeworkIds),
    });

    actionTaken = CONFIG.actions.assignedHomework;

    debugStep = "8 - Outputs";
    setOutputSafe("debugStep", debugStep);

    setFinalOutputs({
      ok: true,
      weeklySummaryId: recordId,
      weekId,
      gradeBandId,
      matchedCountOut: matchedHomeworkIds.length,
      homeworkIdsOut: matchedHomeworkIds.join(", "),
      homeworkTitlesOut: homeworkTitles.join(" | "),
      updatedOut: updatedFields.length > 0,
      actionTaken,
      statusOut: CONFIG.statuses.success,
      errorOut: "",
      debugStep,
    });

    log("033 completed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      weeklySummaryId: recordId,
      weekId,
      gradeBandId,
      matchedCountOut: matchedHomeworkIds.length,
      homeworkIdsOut: matchedHomeworkIds,
      homeworkTitlesOut: homeworkTitles,
      updatedFields,
      actionTaken,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setFinalOutputs({
      ok: false,
      weeklySummaryId: recordId,
      weekId,
      gradeBandId,
      matchedCountOut: matchedHomeworkIds.length,
      homeworkIdsOut: matchedHomeworkIds.join(", "),
      homeworkTitlesOut: homeworkTitles.join(" | "),
      updatedOut: updatedFields.length > 0,
      actionTaken: actionTaken || "error",
      statusOut: CONFIG.statuses.error,
      errorOut: message,
      debugStep: `FAILED AT: ${debugStep}`,
    });

    log("033 failed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      weeklySummaryId: recordId,
      debugStep,
      error: message,
    });

    throw error;
  }
}

/* =========================================================
   SECTION 7: RUN
========================================================= */

await main();

/************************************************************************************************
 * 034 - WEEKLY SUMMARY AND GOAL LOGIC
 * Set Previous Week Helper Values
 *
 * Version: v3.3
 * Date Written: 2026-05-20
 * Last Updated: 2026-06-17
 *
 * PURPOSE
 * - Runs from one Weekly Athlete Summary record.
 * - Reads the linked Enrollment and Week.
 * - Finds the previous Weekly Athlete Summary for the same Enrollment.
 * - Uses Weeks -> Start Date to determine chronological order.
 * - Writes previous-week helper values into the current Weekly Athlete Summary.
 * - Sets Summary Calculation Status = Complete.
 * - Sets Perfect Week Automation Status = Pending when that field exists and is writable.
 *
 * IMPORTANT DESIGN RULES
 * - Total Shots This Week is read-only and must not be written by script.
 * - Total XP After Week is read-only and must not be written by script.
 * - Week Start Date comes from the linked Weeks record.
 * - The previous summary must belong to the same Enrollment.
 * - The previous summary must have a Week with Start Date before the current Week Start Date.
 * - If no previous weekly summary exists, Previous Week Shots and Previous Total XP are set to 0.
 *
 * REQUIRED AUTOMATION INPUT
 * - recordId = Airtable record ID from the triggering Weekly Athlete Summary record
 ************************************************************************************************/

// @ts-nocheck

async function main() {
  const CONFIG = {
    scriptName: "034 - Weekly Summary and Goal Logic - Set Previous Week Helper Values",
    version: "v3.3",

    tables: {
      weeklySummary: "Weekly Athlete Summary",
      weeks: "Weeks",
    },

    weeklySummary: {
      enrollment: "Enrollment",
      week: "Week",

      totalShotsThisWeek: "Total Shots This Week",
      totalXpAfterWeek: "Total XP After Week",

      previousWeekShots: "Previous Week Shots",
      previousTotalXp: "Previous Total XP",

      summaryCalculationStatus: "Summary Calculation Status",
      perfectWeekAutomationStatus: "Perfect Week Automation Status",
    },

    weeks: {
      startDate: "Start Date",
      weekName: "Week Name",
    },

    statusValues: {
      complete: "Complete",
      error: "Error",
      perfectWeekPending: "Pending",
    },

    outputStatuses: {
      complete: "complete",
      skipped: "skipped",
      error: "error",
    },

    debug: {
      logToConsole: true,
    },
  };

  const inputConfig = input.config();
  const recordId = String(inputConfig.recordId || "").trim();

  if (!recordId) {
    throw new Error("Missing required input: recordId");
  }

  const weeklySummaryTable = base.getTable(CONFIG.tables.weeklySummary);
  const weeksTable = base.getTable(CONFIG.tables.weeks);

  const fieldCache = new Map();

  function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
      console.log(message);
    } else {
      console.log(message, JSON.stringify(data, null, 2));
    }
  }

  function setOutputSafe(key, value) {
    try {
      output.set(key, value);
    } catch {
      // Ignore output mapping errors.
    }
  }

  function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    const cacheKey = `${table.name}:${fieldName}`;

    if (fieldCache.has(cacheKey)) {
      return fieldCache.get(cacheKey);
    }

    try {
      const field = table.getField(fieldName);
      fieldCache.set(cacheKey, field);
      return field;
    } catch {
      fieldCache.set(cacheKey, null);
      return null;
    }
  }

  function fieldExists(table, fieldName) {
    return Boolean(getFieldSafe(table, fieldName));
  }

  function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);
    if (!field) return false;

    if (field.isComputed === true) return false;

    const nonWritableTypes = new Set([
      "formula",
      "rollup",
      "count",
      "lookup",
      "multipleLookupValues",
      "createdTime",
      "lastModifiedTime",
      "createdBy",
      "lastModifiedBy",
      "autoNumber",
      "button",
      "aiText",
      "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
  }

  function requireField(table, fieldName, label) {
    if (!fieldExists(table, fieldName)) {
      throw new Error(`Missing required field: ${label} (${table.name} -> ${fieldName})`);
    }
  }

  function requireWritableField(table, fieldName, label) {
    requireField(table, fieldName, label);

    if (!isWritableField(table, fieldName)) {
      throw new Error(`Required field is not writable: ${label} (${table.name} -> ${fieldName})`);
    }
  }

  function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
  }

  function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
  }

  function getNumber(record, table, fieldName, fallback = 0) {
    const raw = getRaw(record, table, fieldName);

    if (typeof raw === "number" && Number.isFinite(raw)) {
      return raw;
    }

    const displayText = record && fieldExists(table, fieldName)
      ? String(record.getCellValueAsString(fieldName) || "")
      : "";

    const text = String(displayText || raw || "")
      .replace(/[$,%]/g, "")
      .replace(/,/g, "")
      .trim();

    if (!text) return fallback;

    const parsed = Number(text);
    return Number.isFinite(parsed) ? parsed : fallback;
  }

  function getLinkedRecordIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) return [];

    return raw
      .map((item) => item?.id)
      .filter(Boolean);
  }

  function getFirstLinkedRecordId(record, table, fieldName) {
    return getLinkedRecordIds(record, table, fieldName)[0] || "";
  }

  function parseDateValue(value) {
    if (!value) return null;

    if (value instanceof Date && !Number.isNaN(value.getTime())) {
      return value;
    }

    if (typeof value === "string") {
      const parsed = new Date(value);
      if (!Number.isNaN(parsed.getTime())) {
        return parsed;
      }
    }

    return null;
  }

  function dateKeyFromValue(value) {
    const date = parseDateValue(value);
    if (!date) return "";

    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");

    return `${year}-${month}-${day}`;
  }

  function getDateKey(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";

    const raw = record.getCellValue(fieldName);
    const rawKey = dateKeyFromValue(raw);

    if (rawKey) return rawKey;

    const display = record.getCellValueAsString(fieldName);
    return dateKeyFromValue(display);
  }

  function buildSingleSelectValue(table, fieldName, optionName) {
    const field = getFieldSafe(table, fieldName);

    if (!field) return undefined;

    if (field.type !== "singleSelect") {
      return optionName;
    }

    const cleanOptionName = String(optionName || "").trim();
    const choices = field?.options?.choices || [];

    const match = choices.find((choice) => {
      return (
        String(choice.name || "").trim().toLowerCase() ===
        cleanOptionName.toLowerCase()
      );
    });

    if (!match) {
      const available = choices.map((choice) => choice.name).join(", ");
      throw new Error(
        `Missing single-select option "${cleanOptionName}" in ${table.name}.${fieldName}. Available options: ${available}`
      );
    }

    return { name: match.name };
  }

  async function updateRecordSafe(table, targetRecordId, updates) {
    const safeUpdates = {};

    for (const [fieldName, value] of Object.entries(updates || {})) {
      if (!fieldExists(table, fieldName)) {
        log(`Skipped missing field: ${table.name}.${fieldName}`);
        continue;
      }

      if (!isWritableField(table, fieldName)) {
        log(`Skipped non-writable field: ${table.name}.${fieldName}`);
        continue;
      }

      if (value === undefined || value === null) {
        continue;
      }

      safeUpdates[fieldName] = value;
    }

    if (Object.keys(safeUpdates).length === 0) {
      return [];
    }

    await table.updateRecordAsync(targetRecordId, safeUpdates);
    return Object.keys(safeUpdates);
  }

  function buildWeeklySummaryFieldsToLoad() {
    return [
      CONFIG.weeklySummary.enrollment,
      CONFIG.weeklySummary.week,
      CONFIG.weeklySummary.totalShotsThisWeek,
      CONFIG.weeklySummary.totalXpAfterWeek,
      CONFIG.weeklySummary.previousWeekShots,
      CONFIG.weeklySummary.previousTotalXp,
      CONFIG.weeklySummary.summaryCalculationStatus,
      CONFIG.weeklySummary.perfectWeekAutomationStatus,
    ].filter((fieldName) => fieldExists(weeklySummaryTable, fieldName));
  }

  function buildWeekFieldsToLoad() {
    return [
      CONFIG.weeks.startDate,
      CONFIG.weeks.weekName,
    ].filter((fieldName) => fieldExists(weeksTable, fieldName));
  }

  function setFinalOutputs({
    ok,
    enrollmentId,
    currentWeekId,
    currentWeekStartDate,
    previousSummaryFound,
    previousSummaryId,
    previousWeekShots,
    previousTotalXp,
    summaryCalculationStatus,
    perfectWeekAutomationStatus,
    updatedFields,
    statusOut,
    errorOut,
    debugStep,
  }) {
    setOutputSafe("ok", ok);
    setOutputSafe("recordId", recordId);
    setOutputSafe("enrollmentId", enrollmentId || "");
    setOutputSafe("currentWeekId", currentWeekId || "");
    setOutputSafe("currentWeekStartDate", currentWeekStartDate || "");
    setOutputSafe("previousSummaryFound", Boolean(previousSummaryFound));
    setOutputSafe("previousSummaryId", previousSummaryId || "");
    setOutputSafe("previousWeekShots", previousWeekShots || 0);
    setOutputSafe("previousTotalXp", previousTotalXp || 0);
    setOutputSafe("summaryCalculationStatus", summaryCalculationStatus || "");
    setOutputSafe("perfectWeekAutomationStatus", perfectWeekAutomationStatus || "");
    setOutputSafe("updatedFields", (updatedFields || []).join(", "));
    setOutputSafe("statusOut", statusOut || "");
    setOutputSafe("errorOut", errorOut || "");
    setOutputSafe("debugStep", debugStep || "");
  }

  function assertRequiredSchema() {
    requireField(
      weeklySummaryTable,
      CONFIG.weeklySummary.enrollment,
      "Weekly Athlete Summary -> Enrollment"
    );

    requireField(
      weeklySummaryTable,
      CONFIG.weeklySummary.week,
      "Weekly Athlete Summary -> Week"
    );

    requireField(
      weeklySummaryTable,
      CONFIG.weeklySummary.totalShotsThisWeek,
      "Weekly Athlete Summary -> Total Shots This Week"
    );

    requireField(
      weeklySummaryTable,
      CONFIG.weeklySummary.totalXpAfterWeek,
      "Weekly Athlete Summary -> Total XP After Week"
    );

    requireWritableField(
      weeklySummaryTable,
      CONFIG.weeklySummary.previousWeekShots,
      "Weekly Athlete Summary -> Previous Week Shots"
    );

    requireWritableField(
      weeklySummaryTable,
      CONFIG.weeklySummary.previousTotalXp,
      "Weekly Athlete Summary -> Previous Total XP"
    );

    requireWritableField(
      weeklySummaryTable,
      CONFIG.weeklySummary.summaryCalculationStatus,
      "Weekly Athlete Summary -> Summary Calculation Status"
    );

    requireField(
      weeksTable,
      CONFIG.weeks.startDate,
      "Weeks -> Start Date"
    );
  }

  let debugStep = "Start";

  let enrollmentId = "";
  let currentWeekId = "";
  let currentWeekStartDate = "";
  let previousSummaryFound = false;
  let previousSummaryId = "";
  let previousWeekShots = 0;
  let previousTotalXp = 0;
  let updatedFields = [];

  try {
    debugStep = "1 - Validate recordId";
    setOutputSafe("debugStep", debugStep);

    if (!recordId.startsWith("rec")) {
      throw new Error(`Invalid Weekly Athlete Summary recordId input: ${recordId}`);
    }

    debugStep = "2 - Validate schema";
    setOutputSafe("debugStep", debugStep);
    assertRequiredSchema();

    debugStep = "3 - Load Current Weekly Athlete Summary";
    setOutputSafe("debugStep", debugStep);

    const currentSummary = await weeklySummaryTable.selectRecordAsync(recordId, {
      fields: buildWeeklySummaryFieldsToLoad(),
    });

    if (!currentSummary) {
      throw new Error(`Weekly Athlete Summary record not found: ${recordId}`);
    }

    debugStep = "4 - Read Current Links";
    setOutputSafe("debugStep", debugStep);

    enrollmentId = getFirstLinkedRecordId(
      currentSummary,
      weeklySummaryTable,
      CONFIG.weeklySummary.enrollment
    );

    currentWeekId = getFirstLinkedRecordId(
      currentSummary,
      weeklySummaryTable,
      CONFIG.weeklySummary.week
    );

    log("034 current summary input", {
      recordId,
      enrollmentId,
      currentWeekId,
      enrollmentDisplay: getText(
        currentSummary,
        weeklySummaryTable,
        CONFIG.weeklySummary.enrollment
      ),
      weekDisplay: getText(
        currentSummary,
        weeklySummaryTable,
        CONFIG.weeklySummary.week
      ),
    });

    if (!enrollmentId) {
      throw new Error("Current Weekly Athlete Summary is missing Enrollment.");
    }

    if (!currentWeekId) {
      throw new Error("Current Weekly Athlete Summary is missing Week.");
    }

    debugStep = "5 - Load Current Week";
    setOutputSafe("debugStep", debugStep);

    const currentWeek = await weeksTable.selectRecordAsync(currentWeekId, {
      fields: buildWeekFieldsToLoad(),
    });

    if (!currentWeek) {
      throw new Error(`Linked Week record not found: ${currentWeekId}`);
    }

    currentWeekStartDate = getDateKey(
      currentWeek,
      weeksTable,
      CONFIG.weeks.startDate
    );

    log("034 current week", {
      currentWeekId,
      currentWeekName: getText(currentWeek, weeksTable, CONFIG.weeks.weekName),
      currentWeekStartDate,
      rawStartDate: currentWeek.getCellValue(CONFIG.weeks.startDate),
      displayStartDate: currentWeek.getCellValueAsString(CONFIG.weeks.startDate),
    });

    if (!currentWeekStartDate) {
      throw new Error(
        `Linked Week is missing or has an unreadable Start Date: ${currentWeekId}. Display value: "${currentWeek.getCellValueAsString(CONFIG.weeks.startDate)}"`
      );
    }

    debugStep = "6 - Load All Summaries and Weeks";
    setOutputSafe("debugStep", debugStep);

    const summariesQuery = await weeklySummaryTable.selectRecordsAsync({
      fields: buildWeeklySummaryFieldsToLoad(),
    });

    const weeksQuery = await weeksTable.selectRecordsAsync({
      fields: buildWeekFieldsToLoad(),
    });

    const weekStartById = new Map();

    for (const weekRecord of weeksQuery.records) {
      const startDate = getDateKey(
        weekRecord,
        weeksTable,
        CONFIG.weeks.startDate
      );

      if (startDate) {
        weekStartById.set(weekRecord.id, startDate);
      }
    }

    debugStep = "7 - Find Previous Weekly Summary";
    setOutputSafe("debugStep", debugStep);

    const previousCandidates = summariesQuery.records
      .filter((summaryRecord) => {
        if (summaryRecord.id === recordId) return false;

        const rowEnrollmentId = getFirstLinkedRecordId(
          summaryRecord,
          weeklySummaryTable,
          CONFIG.weeklySummary.enrollment
        );

        if (rowEnrollmentId !== enrollmentId) return false;

        const rowWeekId = getFirstLinkedRecordId(
          summaryRecord,
          weeklySummaryTable,
          CONFIG.weeklySummary.week
        );

        if (!rowWeekId) return false;

        const rowWeekStartDate = weekStartById.get(rowWeekId);

        if (!rowWeekStartDate) return false;

        return rowWeekStartDate < currentWeekStartDate;
      })
      .map((summaryRecord) => {
        const rowWeekId = getFirstLinkedRecordId(
          summaryRecord,
          weeklySummaryTable,
          CONFIG.weeklySummary.week
        );

        return {
          record: summaryRecord,
          weekId: rowWeekId,
          weekStartDate: weekStartById.get(rowWeekId),
        };
      })
      .sort((a, b) => {
        if (a.weekStartDate < b.weekStartDate) return 1;
        if (a.weekStartDate > b.weekStartDate) return -1;
        return 0;
      });

    log("034 previous candidates", {
      count: previousCandidates.length,
      candidates: previousCandidates.slice(0, 5).map((item) => ({
        summaryId: item.record.id,
        weekId: item.weekId,
        weekStartDate: item.weekStartDate,
        totalShotsThisWeek: getNumber(
          item.record,
          weeklySummaryTable,
          CONFIG.weeklySummary.totalShotsThisWeek,
          0
        ),
        totalXpAfterWeek: getNumber(
          item.record,
          weeklySummaryTable,
          CONFIG.weeklySummary.totalXpAfterWeek,
          0
        ),
      })),
    });

    if (previousCandidates.length > 0) {
      const previousSummary = previousCandidates[0].record;

      previousSummaryFound = true;
      previousSummaryId = previousSummary.id;

      previousWeekShots = getNumber(
        previousSummary,
        weeklySummaryTable,
        CONFIG.weeklySummary.totalShotsThisWeek,
        0
      );

      previousTotalXp = getNumber(
        previousSummary,
        weeklySummaryTable,
        CONFIG.weeklySummary.totalXpAfterWeek,
        0
      );
    }

    debugStep = "8 - Write Helper Values";
    setOutputSafe("debugStep", debugStep);

    const completeStatusValue = buildSingleSelectValue(
      weeklySummaryTable,
      CONFIG.weeklySummary.summaryCalculationStatus,
      CONFIG.statusValues.complete
    );

    const updateFields = {
      [CONFIG.weeklySummary.previousWeekShots]: previousWeekShots,
      [CONFIG.weeklySummary.previousTotalXp]: previousTotalXp,
      [CONFIG.weeklySummary.summaryCalculationStatus]: completeStatusValue,
    };

    if (
      fieldExists(weeklySummaryTable, CONFIG.weeklySummary.perfectWeekAutomationStatus) &&
      isWritableField(weeklySummaryTable, CONFIG.weeklySummary.perfectWeekAutomationStatus)
    ) {
      updateFields[CONFIG.weeklySummary.perfectWeekAutomationStatus] =
        buildSingleSelectValue(
          weeklySummaryTable,
          CONFIG.weeklySummary.perfectWeekAutomationStatus,
          CONFIG.statusValues.perfectWeekPending
        );
    }

    updatedFields = await updateRecordSafe(
      weeklySummaryTable,
      recordId,
      updateFields
    );

    debugStep = "9 - Outputs";
    setOutputSafe("debugStep", debugStep);

    setFinalOutputs({
      ok: true,
      enrollmentId,
      currentWeekId,
      currentWeekStartDate,
      previousSummaryFound,
      previousSummaryId,
      previousWeekShots,
      previousTotalXp,
      summaryCalculationStatus: CONFIG.statusValues.complete,
      perfectWeekAutomationStatus: fieldExists(
        weeklySummaryTable,
        CONFIG.weeklySummary.perfectWeekAutomationStatus
      )
        ? CONFIG.statusValues.perfectWeekPending
        : "",
      updatedFields,
      statusOut: CONFIG.outputStatuses.complete,
      errorOut: "",
      debugStep,
    });

    log("034 completed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      recordId,
      enrollmentId,
      currentWeekId,
      currentWeekStartDate,
      previousSummaryFound,
      previousSummaryId,
      previousWeekShots,
      previousTotalXp,
      updatedFields,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setFinalOutputs({
      ok: false,
      enrollmentId,
      currentWeekId,
      currentWeekStartDate,
      previousSummaryFound,
      previousSummaryId,
      previousWeekShots,
      previousTotalXp,
      summaryCalculationStatus: CONFIG.statusValues.error,
      perfectWeekAutomationStatus: "",
      updatedFields,
      statusOut: CONFIG.outputStatuses.error,
      errorOut: message,
      debugStep: `FAILED AT: ${debugStep}`,
    });

    log("034 failed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      recordId,
      debugStep,
      error: message,
      enrollmentId,
      currentWeekId,
      currentWeekStartDate,
    });

    try {
      if (
        fieldExists(weeklySummaryTable, CONFIG.weeklySummary.summaryCalculationStatus) &&
        isWritableField(weeklySummaryTable, CONFIG.weeklySummary.summaryCalculationStatus)
      ) {
        const errorStatusValue = buildSingleSelectValue(
          weeklySummaryTable,
          CONFIG.weeklySummary.summaryCalculationStatus,
          CONFIG.statusValues.error
        );

        await updateRecordSafe(weeklySummaryTable, recordId, {
          [CONFIG.weeklySummary.summaryCalculationStatus]: errorStatusValue,
        });
      }
    } catch (writebackError) {
      log("034 could not write Error status", {
        error:
          writebackError instanceof Error
            ? writebackError.message
            : String(writebackError),
      });
    }

    throw error;
  }
}

await main();

/************************************************************************************************
 * 041 - Levels and Progression - Mark Enrollment for Level Recalculation
 * Version: 3.0
 * Date Revised: 2026-05-28
 *
 * Purpose:
 * Marks the linked Enrollment record as needing level recalculation after an official XP Event
 * is created or updated with XP points.
 *
 * Correct Trigger Setup:
 * Table: XP Events
 * Trigger: When record matches conditions
 *
 * Trigger Conditions:
 * Enrollment is not empty
 * XP Points is greater than 0
 *
 * Required Input Variable:
 * recordId = Airtable record ID from the triggering XP Events record
 *
 * Writes:
 * Enrollments.Level Recalc Needed? = checked
 *
 * Notes:
 * - This automation does not assign Current Level.
 * - This automation does not assign Next Level.
 * - This automation does not assign Level Gate Rule.
 * - Its only job is to flag the Enrollment so Automation 042 can process it.
 ************************************************************************************************/


/************************************************************************************************
 * 1. CONFIG
 ************************************************************************************************/

const CONFIG = {
    automation: {
        name: "041 - Levels and Progression - Mark Enrollment for Level Recalculation",
        version: "3.0",
    },

    tables: {
        xpEvents: "XP Events",
        enrollments: "Enrollments",
    },

    fields: {
        xpEventEnrollment: "Enrollment",
        xpPoints: "XP Points",
        levelRecalcNeeded: "Level Recalc Needed?",
    },

    outputs: {
        status: "statusOut",
        message: "messageOut",
        xpEventRecordId: "xpEventRecordIdOut",
        enrollmentRecordId: "enrollmentRecordIdOut",
    },
};


/************************************************************************************************
 * 2. HELPERS
 ************************************************************************************************/

function cleanString(value) {
    return String(value || "").trim();
}

function getFirstLinkedRecordId(value) {
    if (!Array.isArray(value) || value.length === 0) {
        return "";
    }

    return cleanString(value[0]?.id);
}

function getNumber(value) {
    if (typeof value === "number") {
        return value;
    }

    const parsed = Number(value);

    if (Number.isFinite(parsed)) {
        return parsed;
    }

    return 0;
}

function setOutputs(status, message, xpEventRecordId = "", enrollmentRecordId = "") {
    output.set(CONFIG.outputs.status, status);
    output.set(CONFIG.outputs.message, message);
    output.set(CONFIG.outputs.xpEventRecordId, xpEventRecordId);
    output.set(CONFIG.outputs.enrollmentRecordId, enrollmentRecordId);
}


/************************************************************************************************
 * 3. MAIN
 ************************************************************************************************/

async function main() {
    const inputConfig = input.config();
    const xpEventRecordId = cleanString(inputConfig.recordId);

    if (!xpEventRecordId) {
        const message = "Missing required input variable: recordId.";
        setOutputs("error", message);
        throw new Error(message);
    }

    const xpEventsTable = base.getTable(CONFIG.tables.xpEvents);
    const enrollmentsTable = base.getTable(CONFIG.tables.enrollments);

    const xpEventRecord = await xpEventsTable.selectRecordAsync(xpEventRecordId, {
        fields: [
            CONFIG.fields.xpEventEnrollment,
            CONFIG.fields.xpPoints,
        ],
    });

    if (!xpEventRecord) {
        const message = `XP Event record not found: ${xpEventRecordId}`;
        setOutputs("error", message, xpEventRecordId);
        throw new Error(message);
    }

    const enrollmentRecordId = getFirstLinkedRecordId(
        xpEventRecord.getCellValue(CONFIG.fields.xpEventEnrollment)
    );

    if (!enrollmentRecordId) {
        const message = `XP Event has no linked Enrollment: ${xpEventRecordId}`;
        setOutputs("skipped", message, xpEventRecordId);
        return;
    }

    const xpPoints = getNumber(xpEventRecord.getCellValue(CONFIG.fields.xpPoints));

    if (xpPoints <= 0) {
        const message = `XP Event has no positive XP Points: ${xpEventRecordId}`;
        setOutputs("skipped", message, xpEventRecordId, enrollmentRecordId);
        return;
    }

    const enrollmentRecord = await enrollmentsTable.selectRecordAsync(enrollmentRecordId, {
        fields: [
            CONFIG.fields.levelRecalcNeeded,
        ],
    });

    if (!enrollmentRecord) {
        const message = `Linked Enrollment record not found: ${enrollmentRecordId}`;
        setOutputs("error", message, xpEventRecordId, enrollmentRecordId);
        throw new Error(message);
    }

    const alreadyMarked = enrollmentRecord.getCellValue(CONFIG.fields.levelRecalcNeeded) === true;

    if (alreadyMarked) {
        const message = `Enrollment already marked for level recalculation: ${enrollmentRecordId}`;
        console.log(message);
        setOutputs("skipped", message, xpEventRecordId, enrollmentRecordId);
        return;
    }

    await enrollmentsTable.updateRecordAsync(enrollmentRecordId, {
        [CONFIG.fields.levelRecalcNeeded]: true,
    });

    const message = `Enrollment marked for level recalculation: ${enrollmentRecordId}`;
    console.log(message);
    setOutputs("success", message, xpEventRecordId, enrollmentRecordId);
}


/************************************************************************************************
 * 4. RUN
 ************************************************************************************************/

await main();

/************************************************************************************************
 * 042 - Levels and Progression - Assign Current and Next Level
 * Version: 2.0
 * Date Revised: 2026-05-28
 *
 * Purpose:
 * Recalculates an Enrollment's Current Level and Next Level based on Lifetime XP Total.
 * Clears the existing Level Gate Rule so Automation 043 can assign the correct gate rule
 * from the newly assigned Next Level.
 *
 * Folder:
 * 04 - Levels and Progression
 *
 * Correct Trigger Setup:
 * Table: Enrollments
 * Trigger Type: When record enters view
 * View: 042 - Needs Level Assignment
 *
 * View Filter:
 * Level Recalc Needed? is checked
 *
 * Required Input Variable:
 * recordId = Airtable record ID from the triggering Enrollment record
 *
 * Reads:
 * Enrollments.Lifetime XP Total
 * Levels.XP Required (Cumulative)
 * Levels.Active?
 *
 * Writes:
 * Enrollments.Current Level
 * Enrollments.Next Level
 * Enrollments.Level Gate Rule = cleared
 * Enrollments.Level Status = Assigned or Error
 * Enrollments.Level Recalc Needed? = unchecked after successful assignment
 *
 * Run Order:
 * 041 = Mark Enrollment for Level Recalculation
 * 042 = Assign Current and Next Level
 * 043 = Set Level Gate Rule from Next Level
 ************************************************************************************************/


/************************************************************************************************
 * 1. CONFIG
 ************************************************************************************************/

const CONFIG = {
    automation: {
        name: "042 - Levels and Progression - Assign Current and Next Level",
        version: "2.0",
    },

    tables: {
        enrollments: "Enrollments",
        levels: "Levels",
    },

    enrollmentFields: {
        lifetimeXpTotal: "Lifetime XP Total",
        currentLevel: "Current Level",
        nextLevel: "Next Level",
        levelGateRule: "Level Gate Rule",
        levelStatus: "Level Status",
        levelRecalcNeeded: "Level Recalc Needed?",
    },

    levelFields: {
        xpRequired: "XP Required (Cumulative)",
        active: "Active?",
    },

    statusValues: {
        assigned: "Assigned",
        error: "Error",
    },

    input: {
        recordId: "recordId",
    },

    outputs: {
        status: "statusOut",
        message: "messageOut",
        enrollmentRecordId: "enrollmentRecordIdOut",
        lifetimeXp: "lifetimeXpOut",
        currentLevel: "currentLevelOut",
        nextLevel: "nextLevelOut",
    },
};


/************************************************************************************************
 * 2. HELPERS
 ************************************************************************************************/

function cleanString(value) {
    return String(value || "").trim();
}

function getNumber(value, fallback = 0) {
    if (typeof value === "number" && Number.isFinite(value)) {
        return value;
    }

    const parsed = Number(value);

    if (Number.isFinite(parsed)) {
        return parsed;
    }

    return fallback;
}

function fieldExists(table, fieldName) {
    return table.fields.some((field) => field.name === fieldName);
}

function assertFieldExists(table, fieldName) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing field "${fieldName}" in table "${table.name}".`);
    }
}

function singleSelectValue(name) {
    return { name };
}

function linkedRecordValue(recordId) {
    return [{ id: recordId }];
}

function emptyLinkedRecordValue() {
    return [];
}

function setOutputs({
    status = "",
    message = "",
    enrollmentRecordId = "",
    lifetimeXp = "",
    currentLevel = "",
    nextLevel = "",
}) {
    output.set(CONFIG.outputs.status, status);
    output.set(CONFIG.outputs.message, message);
    output.set(CONFIG.outputs.enrollmentRecordId, enrollmentRecordId);
    output.set(CONFIG.outputs.lifetimeXp, lifetimeXp);
    output.set(CONFIG.outputs.currentLevel, currentLevel);
    output.set(CONFIG.outputs.nextLevel, nextLevel);
}

async function markEnrollmentError(enrollmentsTable, recordId, message) {
    await enrollmentsTable.updateRecordAsync(recordId, {
        [CONFIG.enrollmentFields.levelStatus]: singleSelectValue(CONFIG.statusValues.error),
    });

    setOutputs({
        status: "error",
        message,
        enrollmentRecordId: recordId,
    });
}


/************************************************************************************************
 * 3. VALIDATION
 ************************************************************************************************/

function validateSchema(enrollmentsTable, levelsTable) {
    const enrollmentRequiredFields = [
        CONFIG.enrollmentFields.lifetimeXpTotal,
        CONFIG.enrollmentFields.currentLevel,
        CONFIG.enrollmentFields.nextLevel,
        CONFIG.enrollmentFields.levelGateRule,
        CONFIG.enrollmentFields.levelStatus,
        CONFIG.enrollmentFields.levelRecalcNeeded,
    ];

    const levelRequiredFields = [
        CONFIG.levelFields.xpRequired,
    ];

    for (const fieldName of enrollmentRequiredFields) {
        assertFieldExists(enrollmentsTable, fieldName);
    }

    for (const fieldName of levelRequiredFields) {
        assertFieldExists(levelsTable, fieldName);
    }
}


/************************************************************************************************
 * 4. LEVEL LOGIC
 ************************************************************************************************/

function buildLevelList(levelRecords, levelsTable) {
    const activeFieldExists = fieldExists(levelsTable, CONFIG.levelFields.active);

    const levels = levelRecords
        .map((levelRecord) => {
            const xpRequired = getNumber(
                levelRecord.getCellValue(CONFIG.levelFields.xpRequired),
                null
            );

            const activeValue = activeFieldExists
                ? levelRecord.getCellValue(CONFIG.levelFields.active)
                : true;

            return {
                id: levelRecord.id,
                name: levelRecord.name,
                xpRequired,
                active: Boolean(activeValue),
            };
        })
        .filter((level) => level.active)
        .filter((level) => typeof level.xpRequired === "number" && Number.isFinite(level.xpRequired))
        .sort((a, b) => a.xpRequired - b.xpRequired);

    if (levels.length === 0) {
        throw new Error("No active Levels found with valid XP Required (Cumulative) values.");
    }

    const seenThresholds = new Map();

    for (const level of levels) {
        if (seenThresholds.has(level.xpRequired)) {
            const existingLevelName = seenThresholds.get(level.xpRequired);

            throw new Error(
                `Duplicate active level threshold found: ${level.xpRequired} XP is used by "${existingLevelName}" and "${level.name}".`
            );
        }

        seenThresholds.set(level.xpRequired, level.name);
    }

    return levels;
}

function determineCurrentAndNextLevel(levels, lifetimeXp) {
    let currentLevel = levels[0];
    let nextLevel = null;

    for (let i = 0; i < levels.length; i++) {
        const level = levels[i];

        if (lifetimeXp >= level.xpRequired) {
            currentLevel = level;
            nextLevel = levels[i + 1] || null;
        } else {
            nextLevel = level;
            break;
        }
    }

    return {
        currentLevel,
        nextLevel,
    };
}


/************************************************************************************************
 * 5. MAIN
 ************************************************************************************************/

async function main() {
    const inputConfig = input.config();
    const recordId = cleanString(inputConfig[CONFIG.input.recordId]);

    if (!recordId) {
        const message = "Missing required input variable: recordId.";
        setOutputs({
            status: "error",
            message,
        });
        throw new Error(message);
    }

    const enrollmentsTable = base.getTable(CONFIG.tables.enrollments);
    const levelsTable = base.getTable(CONFIG.tables.levels);

    validateSchema(enrollmentsTable, levelsTable);

    const enrollment = await enrollmentsTable.selectRecordAsync(recordId, {
        fields: [
            CONFIG.enrollmentFields.lifetimeXpTotal,
            CONFIG.enrollmentFields.currentLevel,
            CONFIG.enrollmentFields.nextLevel,
            CONFIG.enrollmentFields.levelGateRule,
            CONFIG.enrollmentFields.levelStatus,
            CONFIG.enrollmentFields.levelRecalcNeeded,
        ],
    });

    if (!enrollment) {
        const message = `Enrollment record not found: ${recordId}`;
        setOutputs({
            status: "error",
            message,
            enrollmentRecordId: recordId,
        });
        throw new Error(message);
    }

    const lifetimeXp = getNumber(
        enrollment.getCellValue(CONFIG.enrollmentFields.lifetimeXpTotal),
        0
    );

    try {
        const levelFieldsToSelect = [
            CONFIG.levelFields.xpRequired,
        ];

        if (fieldExists(levelsTable, CONFIG.levelFields.active)) {
            levelFieldsToSelect.push(CONFIG.levelFields.active);
        }

        const levelsQuery = await levelsTable.selectRecordsAsync({
            fields: levelFieldsToSelect,
        });

        const levels = buildLevelList(levelsQuery.records, levelsTable);

        const { currentLevel, nextLevel } = determineCurrentAndNextLevel(levels, lifetimeXp);

        const fieldsToUpdate = {
            [CONFIG.enrollmentFields.currentLevel]: linkedRecordValue(currentLevel.id),

            [CONFIG.enrollmentFields.nextLevel]: nextLevel
                ? linkedRecordValue(nextLevel.id)
                : emptyLinkedRecordValue(),

            // Important:
            // 043 only runs when Level Gate Rule is empty.
            // Clearing this here ensures the gate rule always matches the newly assigned Next Level.
            [CONFIG.enrollmentFields.levelGateRule]: emptyLinkedRecordValue(),

            [CONFIG.enrollmentFields.levelStatus]: singleSelectValue(CONFIG.statusValues.assigned),

            [CONFIG.enrollmentFields.levelRecalcNeeded]: false,
        };

        await enrollmentsTable.updateRecordAsync(recordId, fieldsToUpdate);

        const message = `Level assignment complete for Enrollment ${recordId}.`;

        console.log(
            JSON.stringify(
                {
                    ok: true,
                    automation: CONFIG.automation.name,
                    version: CONFIG.automation.version,
                    enrollmentRecordId: recordId,
                    lifetimeXp,
                    currentLevel: {
                        id: currentLevel.id,
                        name: currentLevel.name,
                        xpRequired: currentLevel.xpRequired,
                    },
                    nextLevel: nextLevel
                        ? {
                              id: nextLevel.id,
                              name: nextLevel.name,
                              xpRequired: nextLevel.xpRequired,
                          }
                        : null,
                    levelGateRuleCleared: true,
                    levelRecalcNeededCleared: true,
                },
                null,
                2
            )
        );

        setOutputs({
            status: "success",
            message,
            enrollmentRecordId: recordId,
            lifetimeXp,
            currentLevel: currentLevel.name,
            nextLevel: nextLevel ? nextLevel.name : "",
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        await markEnrollmentError(enrollmentsTable, recordId, message);

        throw new Error(message);
    }
}


/************************************************************************************************
 * 6. RUN
 ************************************************************************************************/

await main();

/************************************************************
 * AUTOMATION NAME
 * 043 - Levels and Progression - Set Level Gate Rule from Next Level
 *
 * Version: v2.0
 * Date Written: 2026-05-20
 *
 * PURPOSE
 * - Reads one Enrollment record.
 * - Reads the linked Next Level.
 * - Finds the matching Level Gate Rules record where Level = Next Level.
 * - Preferably uses only active Level Gate Rules when Version Active? exists.
 * - Writes the matching Level Gate Rule into Enrollments.Level Gate Rule.
 *
 * CURRENT SCHEMA NOTES
 * - Enrollments.Next Level is a linked-record field.
 * - Enrollments.Level Gate Rule is a writable linked-record field.
 * - Level Gate Rules.Level is a linked-record field.
 * - Level Gate Rules.Version Active? is a checkbox and should be used when present.
 * - Gate minimum fields on Enrollments are lookups from Level Gate Rule and must not be written by script.
 *
 * REQUIRED AUTOMATION INPUT
 * - recordId: Airtable record ID from Enrollments
 *
 * CORRECT TRIGGER CONDITIONS
 * - Next Level is not empty.
 * - Level Gate Rule is empty.
 * - Optional: Active? is checked.
 *
 * OUTPUTS
 * - ok
 * - recordId
 * - nextLevelId
 * - levelGateRuleId
 * - matchCount
 * - actionTaken
 * - statusOut
 * - errorOut
 * - debugStep
 ************************************************************/

/// <reference path="../../Welcome Email/airtable-automation-script.d.ts" />
// @ts-nocheck

/* =========================================================
   SECTION 1: CONFIG
   ========================================================= */

const CONFIG = {
    tables: {
        enrollments: "Enrollments",
        levelGateRules: "Level Gate Rules",
    },

    enrollments: {
        nextLevel: "Next Level",
        levelGateRule: "Level Gate Rule",
        active: "Active?",
    },

    levelGateRules: {
        level: "Level",
        versionActive: "Version Active?",
        name: "Level Gate Rule Name",
    },

    statuses: {
        success: "success",
        skipped: "skipped",
        error: "error",
    },

    debug: {
        logToConsole: true,
        requireActiveGateRuleWhenFieldExists: true,
    },
};

/* =========================================================
   SECTION 2: INPUTS
   ========================================================= */

const cfg =
    typeof input !== "undefined" && input && typeof input.config === "function"
        ? input.config()
        : {};

const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLES
   ========================================================= */

const enrollmentsTable = base.getTable(CONFIG.tables.enrollments);
const levelGateRulesTable = base.getTable(CONFIG.tables.levelGateRules);

/* =========================================================
   SECTION 4: HELPERS
   ========================================================= */

function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
        console.log(message);
    } else {
        console.log(message, JSON.stringify(data, null, 2));
    }
}

function setOutputSafe(key, value) {
    try {
        output.set(key, value);
    } catch {
        // Output is unavailable in some testing contexts.
    }
}

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    try {
        return table.getField(fieldName);
    } catch {
        return null;
    }
}

function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);
    if (!field) return false;

    const nonWritableTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "createdBy",
        "lastModifiedBy",
        "autoNumber",
        "button",
        "aiText",
        "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
}

function requireField(table, fieldName, label) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing required field: ${label} (${table.name} -> ${fieldName})`);
    }
}

function requireWritableField(table, fieldName, label) {
    requireField(table, fieldName, label);

    if (!isWritableField(table, fieldName)) {
        throw new Error(`Required field is not writable: ${label} (${table.name} -> ${fieldName})`);
    }
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getLinkedRecordIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) {
        return [];
    }

    return raw.map((item) => item?.id).filter(Boolean);
}

function getFirstLinkedRecordId(record, table, fieldName) {
    return getLinkedRecordIds(record, table, fieldName)[0] || "";
}

function getBooleanish(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (raw === true) return true;
    if (raw === false) return false;
    if (raw === 1) return true;
    if (raw === 0) return false;

    const value = String(raw ?? "").trim().toLowerCase();
    return ["1", "true", "yes", "checked", "active"].includes(value);
}

async function updateRecordSafe(table, targetRecordId, updates) {
    const safeUpdates = {};

    for (const [fieldName, value] of Object.entries(updates || {})) {
        if (!fieldExists(table, fieldName)) {
            log(`Skipped missing field: ${table.name}.${fieldName}`);
            continue;
        }

        if (!isWritableField(table, fieldName)) {
            log(`Skipped non-writable field: ${table.name}.${fieldName}`);
            continue;
        }

        if (value === undefined) {
            continue;
        }

        safeUpdates[fieldName] = value;
    }

    if (Object.keys(safeUpdates).length === 0) {
        return [];
    }

    await table.updateRecordAsync(targetRecordId, safeUpdates);

    return Object.keys(safeUpdates);
}

function buildEnrollmentFieldsToLoad() {
    return [
        CONFIG.enrollments.nextLevel,
        CONFIG.enrollments.levelGateRule,
        CONFIG.enrollments.active,
    ].filter((fieldName) => fieldExists(enrollmentsTable, fieldName));
}

function buildGateRuleFieldsToLoad() {
    return [
        CONFIG.levelGateRules.level,
        CONFIG.levelGateRules.versionActive,
        CONFIG.levelGateRules.name,
    ].filter((fieldName) => fieldExists(levelGateRulesTable, fieldName));
}

/* =========================================================
   SECTION 5: FIELD VALIDATION
   ========================================================= */

requireField(
    enrollmentsTable,
    CONFIG.enrollments.nextLevel,
    "Enrollments -> Next Level"
);

requireWritableField(
    enrollmentsTable,
    CONFIG.enrollments.levelGateRule,
    "Enrollments -> Level Gate Rule"
);

requireField(
    levelGateRulesTable,
    CONFIG.levelGateRules.level,
    "Level Gate Rules -> Level"
);

/* =========================================================
   SECTION 6: MAIN
   ========================================================= */

async function main() {
    let debugStep = "Start";

    let enrollment = null;
    let nextLevelId = "";
    let existingLevelGateRuleId = "";
    let levelGateRuleId = "";
    let matchCount = 0;
    let actionTaken = "";

    setOutputSafe("debugStep", debugStep);

    try {
        debugStep = "1 - Validate recordId";
        setOutputSafe("debugStep", debugStep);

        if (!recordId.startsWith("rec")) {
            throw new Error(`Invalid Enrollment recordId input: ${recordId}`);
        }

        debugStep = "2 - Load Enrollment";
        setOutputSafe("debugStep", debugStep);

        enrollment = await enrollmentsTable.selectRecordAsync(recordId, {
            fields: buildEnrollmentFieldsToLoad(),
        });

        if (!enrollment) {
            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("nextLevelId", "");
            setOutputSafe("levelGateRuleId", "");
            setOutputSafe("matchCount", 0);
            setOutputSafe("actionTaken", "skipped_enrollment_not_found");
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", `Enrollment record not found: ${recordId}`);
            setOutputSafe("debugStep", "Skipped: Enrollment not found");
            return;
        }

        debugStep = "3 - Read Enrollment Values";
        setOutputSafe("debugStep", debugStep);

        nextLevelId = getFirstLinkedRecordId(
            enrollment,
            enrollmentsTable,
            CONFIG.enrollments.nextLevel
        );

        existingLevelGateRuleId = getFirstLinkedRecordId(
            enrollment,
            enrollmentsTable,
            CONFIG.enrollments.levelGateRule
        );

        log("Level Gate Rule input", {
            recordId,
            nextLevelId,
            existingLevelGateRuleId,
        });

        debugStep = "4 - Validate Next Level";
        setOutputSafe("debugStep", debugStep);

        if (!nextLevelId) {
            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("nextLevelId", "");
            setOutputSafe("levelGateRuleId", "");
            setOutputSafe("matchCount", 0);
            setOutputSafe("actionTaken", "skipped_no_next_level");
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", "No Next Level is linked on this Enrollment.");
            setOutputSafe("debugStep", "Skipped: Next Level blank");
            return;
        }

        if (existingLevelGateRuleId) {
            setOutputSafe("ok", true);
            setOutputSafe("recordId", recordId);
            setOutputSafe("nextLevelId", nextLevelId);
            setOutputSafe("levelGateRuleId", existingLevelGateRuleId);
            setOutputSafe("matchCount", 1);
            setOutputSafe("actionTaken", "already_linked");
            setOutputSafe("statusOut", CONFIG.statuses.success);
            setOutputSafe("errorOut", "");
            setOutputSafe("debugStep", "Done - Already linked");
            return;
        }

        debugStep = "5 - Load Level Gate Rules";
        setOutputSafe("debugStep", debugStep);

        const gateRuleQuery = await levelGateRulesTable.selectRecordsAsync({
            fields: buildGateRuleFieldsToLoad(),
        });

        debugStep = "6 - Find Matching Level Gate Rule";
        setOutputSafe("debugStep", debugStep);

        const matches = gateRuleQuery.records.filter((ruleRecord) => {
            const linkedLevelIds = getLinkedRecordIds(
                ruleRecord,
                levelGateRulesTable,
                CONFIG.levelGateRules.level
            );

            const levelMatches = linkedLevelIds.includes(nextLevelId);

            if (!levelMatches) return false;

            if (
                CONFIG.debug.requireActiveGateRuleWhenFieldExists &&
                fieldExists(levelGateRulesTable, CONFIG.levelGateRules.versionActive)
            ) {
                return getBooleanish(
                    ruleRecord,
                    levelGateRulesTable,
                    CONFIG.levelGateRules.versionActive
                );
            }

            return true;
        });

        matchCount = matches.length;

        if (matches.length === 0) {
            setOutputSafe("ok", false);
            setOutputSafe("recordId", recordId);
            setOutputSafe("nextLevelId", nextLevelId);
            setOutputSafe("levelGateRuleId", "");
            setOutputSafe("matchCount", 0);
            setOutputSafe("actionTaken", "skipped_no_matching_gate_rule");
            setOutputSafe("statusOut", CONFIG.statuses.skipped);
            setOutputSafe("errorOut", "No matching active Level Gate Rule found for this Next Level.");
            setOutputSafe("debugStep", "Skipped: No matching gate rule");
            return;
        }

        if (matches.length > 1) {
            const duplicateIds = matches.map((record) => record.id).join(", ");
            throw new Error(
                `Multiple active Level Gate Rules matched this Next Level. Record IDs: ${duplicateIds}`
            );
        }

        const matchingGateRule = matches[0];
        levelGateRuleId = matchingGateRule.id;

        debugStep = "7 - Write Level Gate Rule";
        setOutputSafe("debugStep", debugStep);

        await updateRecordSafe(enrollmentsTable, recordId, {
            [CONFIG.enrollments.levelGateRule]: [{ id: levelGateRuleId }],
        });

        actionTaken = "linked_level_gate_rule";

        debugStep = "8 - Outputs";
        setOutputSafe("debugStep", debugStep);

        setOutputSafe("ok", true);
        setOutputSafe("recordId", recordId);
        setOutputSafe("nextLevelId", nextLevelId);
        setOutputSafe("levelGateRuleId", levelGateRuleId);
        setOutputSafe("matchCount", matchCount);
        setOutputSafe("actionTaken", actionTaken);
        setOutputSafe("statusOut", CONFIG.statuses.success);
        setOutputSafe("errorOut", "");

        log("Level Gate Rule assigned successfully", {
            recordId,
            nextLevelId,
            levelGateRuleId,
            matchCount,
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        setOutputSafe("ok", false);
        setOutputSafe("recordId", recordId);
        setOutputSafe("nextLevelId", nextLevelId);
        setOutputSafe("levelGateRuleId", levelGateRuleId);
        setOutputSafe("matchCount", matchCount);
        setOutputSafe("actionTaken", actionTaken || "error");
        setOutputSafe("statusOut", CONFIG.statuses.error);
        setOutputSafe("errorOut", message);
        setOutputSafe("debugStep", `FAILED AT: ${debugStep}`);

        log("Level Gate Rule assignment failed", {
            recordId,
            debugStep,
            error: message,
        });

        throw error;
    }
}

/* =========================================================
   SECTION 7: RUN
   ========================================================= */

await main();

/************************************************************************************************
 * 053 - Achievements and Milestones - Streak Occurrences - Rebuild and Upsert From Submissions
 * Version: 5.0
 * Date Written: 2026-06-04
 *
 * PURPOSE
 * - Rebuild streak milestone occurrences for one Enrollment after a valid Submission changes.
 * - Count only valid shooting Submissions using the canonical/countable shot logic:
 *      Count This Submission? = 1
 *      Total Shots Counted > 0
 *      Activity Date is not empty
 * - Treat multiple valid submissions on the same Activity Date as one streak day.
 * - Use active Achievements where Trigger Type = "Streak Length".
 * - Create or repair one canonical Streak Occurrence per:
 *      Enrollment + Achievement + Streak End Date
 * - Allow the same streak achievement to be earned again only after a streak breaks
 *   and a new streak block reaches the threshold again.
 * - Set Week based on the week containing the Streak End Date.
 * - Populate streak detail fields used by reporting and level gates:
 *      Streak Days
 *      Streak Start Date
 *      Streak End Date
 *      Week
 *      Source Submission Date
 *      Trigger Submission Date
 *      Last Evaluated At
 * - Never create XP Events directly.
 * - Never write to formula fields such as Streak Occurrence Key.
 *
 * REQUIRED INPUT
 * - recordId = triggering Submission record ID
 ************************************************************************************************/


/************************************************************************************************
 * SECTION 1 — CONFIGURATION
 ************************************************************************************************/

const CONFIG = {
    tables: {
        submissions: "Submissions",
        achievements: "Achievements",
        streakOccurrences: "Streak Occurrences",
        weeks: "Weeks",
    },

    submissions: {
        enrollment: "Enrollment",
        activityDate: "Activity Date",
        totalShotsCounted: "Total Shots Counted",
        countThisSubmission: "Count This Submission?",
    },

    achievements: {
        active: "Active?",
        triggerType: "Trigger Type",
        triggerThreshold: "Trigger Threshold",
        rewardRuleKey: "Reward Rule Key",
    },

    streakOccurrences: {
        active: "Active?",
        enrollment: "Enrollment",
        achievement: "Achievement",
        streakDays: "Streak Days",
        streakStartDate: "Streak Start Date",
        streakEndDate: "Streak End Date",
        week: "Week",
        xpEvents: "XP Events",
        sourceStatus: "Source Status",
        sourceSubmissionDate: "Source Submission Date",
        triggerSubmissionDate: "Trigger Submission Date",
        lastEvaluatedAt: "Last Evaluated At",
        notes: "Notes",
    },

    weeks: {
        startDate: "Start Date",
        endDate: "End Date",
    },

    values: {
        triggerTypeStreakLength: "Streak Length",
        statusReady: "Ready for XP",
        statusAwarded: "Awarded",
        statusDuplicate: "Duplicate",
        statusError: "Error",
    },

    outputs: {
        success: "success",
        skipped: "skipped",
        error: "error",
    },
};


/************************************************************************************************
 * SECTION 2 — INPUT
 ************************************************************************************************/

const inputConfig = input.config();
const recordId = String(inputConfig.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input variable: recordId");
}


/************************************************************************************************
 * SECTION 3 — TABLES
 ************************************************************************************************/

const submissionsTable = base.getTable(CONFIG.tables.submissions);
const achievementsTable = base.getTable(CONFIG.tables.achievements);
const streakOccurrencesTable = base.getTable(CONFIG.tables.streakOccurrences);
const weeksTable = base.getTable(CONFIG.tables.weeks);


/************************************************************************************************
 * SECTION 4 — HELPERS
 ************************************************************************************************/

function setOutputs(values) {
    for (const [key, value] of Object.entries(values)) {
        output.set(key, value);
    }
}

function getLinkedRecordId(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return Array.isArray(value) && value.length > 0 ? value[0].id : null;
}

function getLinkedRecordIds(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return Array.isArray(value) ? value.map((item) => item.id) : [];
}

function getSelectName(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return value && value.name ? value.name : "";
}

function getNumber(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return typeof value === "number" ? value : 0;
}

function isChecked(record, fieldName) {
    return record.getCellValue(fieldName) === true;
}

function toDateKey(value) {
    if (!value) {
        return "";
    }

    const date = new Date(value);

    if (Number.isNaN(date.getTime())) {
        return "";
    }

    return date.toISOString().slice(0, 10);
}

function addDays(dateKey, daysToAdd) {
    const date = new Date(`${dateKey}T00:00:00.000Z`);
    date.setUTCDate(date.getUTCDate() + daysToAdd);
    return date.toISOString().slice(0, 10);
}

function daysBetween(previousDateKey, nextDateKey) {
    const previousDate = new Date(`${previousDateKey}T00:00:00.000Z`);
    const nextDate = new Date(`${nextDateKey}T00:00:00.000Z`);
    return Math.round((nextDate - previousDate) / 86400000);
}

function makeOccurrenceKey(enrollmentId, achievementId, streakEndDateKey) {
    return `${enrollmentId}|${achievementId}|${streakEndDateKey}`;
}

function chunkArray(items, chunkSize) {
    const chunks = [];

    for (let i = 0; i < items.length; i += chunkSize) {
        chunks.push(items.slice(i, i + chunkSize));
    }

    return chunks;
}

async function batchCreate(table, records) {
    for (const chunk of chunkArray(records, 50)) {
        await table.createRecordsAsync(chunk);
    }
}

async function batchUpdate(table, records) {
    for (const chunk of chunkArray(records, 50)) {
        await table.updateRecordsAsync(chunk);
    }
}

function findWeekForDate(weekRecords, dateKey) {
    if (!dateKey) {
        return null;
    }

    const target = new Date(`${dateKey}T12:00:00.000Z`);

    for (const week of weekRecords) {
        const startRaw = week.getCellValue(CONFIG.weeks.startDate);
        const endRaw = week.getCellValue(CONFIG.weeks.endDate);

        if (!startRaw || !endRaw) {
            continue;
        }

        const start = new Date(startRaw);
        const end = new Date(endRaw);

        if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
            continue;
        }

        const startDateOnly = new Date(Date.UTC(
            start.getUTCFullYear(),
            start.getUTCMonth(),
            start.getUTCDate(),
            0,
            0,
            0,
            0
        ));

        const endDateOnly = new Date(Date.UTC(
            end.getUTCFullYear(),
            end.getUTCMonth(),
            end.getUTCDate(),
            23,
            59,
            59,
            999
        ));

        if (target >= startDateOnly && target <= endDateOnly) {
            return week;
        }
    }

    return null;
}

function buildStreakBlocks(dateKeys) {
    const blocks = [];

    if (dateKeys.length === 0) {
        return blocks;
    }

    let currentBlock = [dateKeys[0]];

    for (let i = 1; i < dateKeys.length; i++) {
        const previousDateKey = dateKeys[i - 1];
        const currentDateKey = dateKeys[i];

        if (daysBetween(previousDateKey, currentDateKey) === 1) {
            currentBlock.push(currentDateKey);
        } else {
            blocks.push(currentBlock);
            currentBlock = [currentDateKey];
        }
    }

    blocks.push(currentBlock);
    return blocks;
}


/************************************************************************************************
 * SECTION 5 — LOAD TRIGGER SUBMISSION
 ************************************************************************************************/

const triggerSubmission = await submissionsTable.selectRecordAsync(recordId);

if (!triggerSubmission) {
    setOutputs({
        ok: false,
        actionOut: "skipped_missing_trigger_submission",
        statusOut: CONFIG.outputs.skipped,
        errorOut: `Submission not found: ${recordId}`,
    });
    return;
}

const enrollmentId = getLinkedRecordId(
    triggerSubmission,
    CONFIG.submissions.enrollment
);

if (!enrollmentId) {
    setOutputs({
        ok: true,
        actionOut: "skipped_submission_missing_enrollment",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        submissionId: recordId,
    });
    return;
}


/************************************************************************************************
 * SECTION 6 — LOAD RECORDS
 ************************************************************************************************/

const [
    submissionsQuery,
    achievementsQuery,
    streakOccurrencesQuery,
    weeksQuery,
] = await Promise.all([
    submissionsTable.selectRecordsAsync({
        fields: [
            CONFIG.submissions.enrollment,
            CONFIG.submissions.activityDate,
            CONFIG.submissions.totalShotsCounted,
            CONFIG.submissions.countThisSubmission,
        ],
    }),
    achievementsTable.selectRecordsAsync({
        fields: [
            CONFIG.achievements.active,
            CONFIG.achievements.triggerType,
            CONFIG.achievements.triggerThreshold,
            CONFIG.achievements.rewardRuleKey,
        ],
    }),
    streakOccurrencesTable.selectRecordsAsync({
        fields: [
            CONFIG.streakOccurrences.active,
            CONFIG.streakOccurrences.enrollment,
            CONFIG.streakOccurrences.achievement,
            CONFIG.streakOccurrences.streakDays,
            CONFIG.streakOccurrences.streakStartDate,
            CONFIG.streakOccurrences.streakEndDate,
            CONFIG.streakOccurrences.week,
            CONFIG.streakOccurrences.xpEvents,
            CONFIG.streakOccurrences.sourceStatus,
        ],
    }),
    weeksTable.selectRecordsAsync({
        fields: [
            CONFIG.weeks.startDate,
            CONFIG.weeks.endDate,
        ],
    }),
]);


/************************************************************************************************
 * SECTION 7 — BUILD VALID DISTINCT SHOOTING DATES
 ************************************************************************************************/

const validDateSet = new Set();

for (const submission of submissionsQuery.records) {
    const submissionEnrollmentId = getLinkedRecordId(
        submission,
        CONFIG.submissions.enrollment
    );

    if (submissionEnrollmentId !== enrollmentId) {
        continue;
    }

    const countThisSubmission = getNumber(
        submission,
        CONFIG.submissions.countThisSubmission
    );

    const totalShotsCounted = getNumber(
        submission,
        CONFIG.submissions.totalShotsCounted
    );

    const activityDateKey = toDateKey(
        submission.getCellValue(CONFIG.submissions.activityDate)
    );

    if (
        countThisSubmission === 1 &&
        totalShotsCounted > 0 &&
        activityDateKey
    ) {
        validDateSet.add(activityDateKey);
    }
}

const validDateKeys = Array.from(validDateSet).sort();

if (validDateKeys.length === 0) {
    setOutputs({
        ok: true,
        actionOut: "skipped_no_valid_counted_shooting_dates",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        enrollmentId,
        validDatesProcessed: 0,
    });
    return;
}


/************************************************************************************************
 * SECTION 8 — LOAD ACTIVE STREAK ACHIEVEMENTS
 ************************************************************************************************/

let activeStreakAchievements = achievementsQuery.records
    .filter((achievement) => {
        const active = isChecked(
            achievement,
            CONFIG.achievements.active
        );

        const triggerType = getSelectName(
            achievement,
            CONFIG.achievements.triggerType
        );

        const threshold = getNumber(
            achievement,
            CONFIG.achievements.triggerThreshold
        );

        return (
            active &&
            triggerType === CONFIG.values.triggerTypeStreakLength &&
            threshold > 0
        );
    })
    .sort((a, b) => {
        return (
            getNumber(a, CONFIG.achievements.triggerThreshold) -
            getNumber(b, CONFIG.achievements.triggerThreshold)
        );
    });

if (activeStreakAchievements.length === 0) {
    setOutputs({
        ok: true,
        actionOut: "skipped_no_active_streak_achievements",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        enrollmentId,
        validDatesProcessed: validDateKeys.length,
    });
    return;
}


/************************************************************************************************
 * SECTION 9 — BUILD TARGET STREAK OCCURRENCES
 ************************************************************************************************/

const streakBlocks = buildStreakBlocks(validDateKeys);
const targetOccurrencesByKey = new Map();

for (const block of streakBlocks) {
    const streakStartDateKey = block[0];

    for (const achievement of activeStreakAchievements) {
        const threshold = getNumber(
            achievement,
            CONFIG.achievements.triggerThreshold
        );

        if (block.length < threshold) {
            continue;
        }

        const streakEndDateKey = block[threshold - 1];
        const week = findWeekForDate(weeksQuery.records, streakEndDateKey);
        const occurrenceKey = makeOccurrenceKey(
            enrollmentId,
            achievement.id,
            streakEndDateKey
        );

        targetOccurrencesByKey.set(occurrenceKey, {
            occurrenceKey,
            enrollmentId,
            achievementId: achievement.id,
            streakDays: threshold,
            streakStartDateKey,
            streakEndDateKey,
            weekId: week ? week.id : null,
        });
    }
}


/************************************************************************************************
 * SECTION 10 — INDEX EXISTING STREAK OCCURRENCES
 ************************************************************************************************/

const existingOccurrencesByKey = new Map();

for (const occurrence of streakOccurrencesQuery.records) {
    const occurrenceEnrollmentId = getLinkedRecordId(
        occurrence,
        CONFIG.streakOccurrences.enrollment
    );

    if (occurrenceEnrollmentId !== enrollmentId) {
        continue;
    }

    const achievementId = getLinkedRecordId(
        occurrence,
        CONFIG.streakOccurrences.achievement
    );

    const streakEndDateKey = toDateKey(
        occurrence.getCellValue(CONFIG.streakOccurrences.streakEndDate)
    );

    if (!achievementId || !streakEndDateKey) {
        continue;
    }

    const occurrenceKey = makeOccurrenceKey(
        occurrenceEnrollmentId,
        achievementId,
        streakEndDateKey
    );

    if (!existingOccurrencesByKey.has(occurrenceKey)) {
        existingOccurrencesByKey.set(occurrenceKey, []);
    }

    existingOccurrencesByKey.get(occurrenceKey).push(occurrence);
}


/************************************************************************************************
 * SECTION 11 — CREATE MISSING OCCURRENCES
 ************************************************************************************************/

const nowIso = new Date().toISOString();
const recordsToCreate = [];

for (const target of targetOccurrencesByKey.values()) {
    const existing = existingOccurrencesByKey.get(target.occurrenceKey) || [];

    if (existing.length > 0) {
        continue;
    }

    const fields = {
        [CONFIG.streakOccurrences.active]: true,
        [CONFIG.streakOccurrences.enrollment]: [{ id: target.enrollmentId }],
        [CONFIG.streakOccurrences.achievement]: [{ id: target.achievementId }],
        [CONFIG.streakOccurrences.streakDays]: target.streakDays,
        [CONFIG.streakOccurrences.streakStartDate]: target.streakStartDateKey,
        [CONFIG.streakOccurrences.streakEndDate]: target.streakEndDateKey,
        [CONFIG.streakOccurrences.sourceStatus]: "Pending",
        [CONFIG.streakOccurrences.sourceSubmissionDate]: `${target.streakEndDateKey}T12:00:00.000Z`,
        [CONFIG.streakOccurrences.triggerSubmissionDate]: `${target.streakEndDateKey}T12:00:00.000Z`,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: nowIso,
    };

    if (target.weekId) {
        fields[CONFIG.streakOccurrences.week] = [{ id: target.weekId }];
    }

    recordsToCreate.push({ fields });
}

if (recordsToCreate.length > 0) {
    await batchCreate(streakOccurrencesTable, recordsToCreate);
}


/************************************************************************************************
 * SECTION 12 — RELOAD AND REPAIR / DEDUPE OCCURRENCES
 ************************************************************************************************/

const refreshedOccurrencesQuery = await streakOccurrencesTable.selectRecordsAsync({
    fields: [
        CONFIG.streakOccurrences.active,
        CONFIG.streakOccurrences.enrollment,
        CONFIG.streakOccurrences.achievement,
        CONFIG.streakOccurrences.streakDays,
        CONFIG.streakOccurrences.streakStartDate,
        CONFIG.streakOccurrences.streakEndDate,
        CONFIG.streakOccurrences.week,
        CONFIG.streakOccurrences.xpEvents,
        CONFIG.streakOccurrences.sourceStatus,
    ],
});

const refreshedByKey = new Map();

for (const occurrence of refreshedOccurrencesQuery.records) {
    const occurrenceEnrollmentId = getLinkedRecordId(
        occurrence,
        CONFIG.streakOccurrences.enrollment
    );

    if (occurrenceEnrollmentId !== enrollmentId) {
        continue;
    }

    const achievementId = getLinkedRecordId(
        occurrence,
        CONFIG.streakOccurrences.achievement
    );

    const streakEndDateKey = toDateKey(
        occurrence.getCellValue(CONFIG.streakOccurrences.streakEndDate)
    );

    if (!achievementId || !streakEndDateKey) {
        continue;
    }

    const occurrenceKey = makeOccurrenceKey(
        occurrenceEnrollmentId,
        achievementId,
        streakEndDateKey
    );

    if (!refreshedByKey.has(occurrenceKey)) {
        refreshedByKey.set(occurrenceKey, []);
    }

    refreshedByKey.get(occurrenceKey).push(occurrence);
}

const recordsToUpdate = [];
let canonicalCount = 0;
let duplicateCount = 0;

for (const target of targetOccurrencesByKey.values()) {
    const matchingOccurrences = refreshedByKey.get(target.occurrenceKey) || [];

    if (matchingOccurrences.length === 0) {
        continue;
    }

    matchingOccurrences.sort((a, b) => {
        const aHasXp = getLinkedRecordIds(a, CONFIG.streakOccurrences.xpEvents).length > 0;
        const bHasXp = getLinkedRecordIds(b, CONFIG.streakOccurrences.xpEvents).length > 0;

        if (aHasXp && !bHasXp) {
            return -1;
        }

        if (!aHasXp && bHasXp) {
            return 1;
        }

        return a.id.localeCompare(b.id);
    });

    const canonical = matchingOccurrences[0];
    const canonicalXpEventIds = getLinkedRecordIds(
        canonical,
        CONFIG.streakOccurrences.xpEvents
    );

    const canonicalStatus = canonicalXpEventIds.length > 0
        ? CONFIG.values.statusAwarded
        : CONFIG.values.statusReady;

    const canonicalFields = {
        [CONFIG.streakOccurrences.active]: true,
        [CONFIG.streakOccurrences.streakDays]: target.streakDays,
        [CONFIG.streakOccurrences.streakStartDate]: target.streakStartDateKey,
        [CONFIG.streakOccurrences.streakEndDate]: target.streakEndDateKey,
        [CONFIG.streakOccurrences.sourceStatus]: canonicalStatus,
        [CONFIG.streakOccurrences.sourceSubmissionDate]: `${target.streakEndDateKey}T12:00:00.000Z`,
        [CONFIG.streakOccurrences.triggerSubmissionDate]: `${target.streakEndDateKey}T12:00:00.000Z`,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: nowIso,
    };

    if (target.weekId) {
        canonicalFields[CONFIG.streakOccurrences.week] = [{ id: target.weekId }];
    }

    recordsToUpdate.push({
        id: canonical.id,
        fields: canonicalFields,
    });

    canonicalCount++;

    for (let i = 1; i < matchingOccurrences.length; i++) {
        const duplicate = matchingOccurrences[i];

        recordsToUpdate.push({
            id: duplicate.id,
            fields: {
                [CONFIG.streakOccurrences.active]: false,
                [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusDuplicate,
                [CONFIG.streakOccurrences.lastEvaluatedAt]: nowIso,
                [CONFIG.streakOccurrences.notes]: `Duplicate streak occurrence. Canonical record: ${canonical.id}`,
            },
        });

        duplicateCount++;
    }
}

if (recordsToUpdate.length > 0) {
    await batchUpdate(streakOccurrencesTable, recordsToUpdate);
}


/************************************************************************************************
 * SECTION 13 — OUTPUTS
 ************************************************************************************************/

setOutputs({
    ok: true,
    actionOut: "rebuilt_and_upserted_streak_occurrences",
    statusOut: CONFIG.outputs.success,
    errorOut: "",
    modeOut: "single_enrollment_rebuild",
    submissionId: recordId,
    enrollmentId,
    validDatesProcessed: validDateKeys.length,
    streakBlocksFound: streakBlocks.length,
    activeStreakAchievements: activeStreakAchievements.length,
    targetOccurrences: targetOccurrencesByKey.size,
    recordsCreated: recordsToCreate.length,
    recordsUpdated: recordsToUpdate.length,
    canonicalRecords: canonicalCount,
    duplicateRecordsMarked: duplicateCount,
});

/************************************************************************************************
 * 054 - Achievements and Milestones - Streak Occurrences - Create or Repair Streak XP Event
 * Version: 4.0
 * Date Written: 2026-06-04
 *
 * PURPOSE
 * - Reads one Streak Occurrence.
 * - Creates or repairs exactly one XP Event for that Streak Occurrence.
 * - Keeps streak XP separate from Automation 059.
 * - Uses XP Reward Rules when possible.
 * - Prevents duplicate streak XP using a stable Source Key:
 *      STREAK_XP|Enrollment ID|Achievement ID|Streak End Date
 * - Copies Week from the Streak Occurrence to the XP Event.
 * - Writes XP Source Date = Streak End Date.
 * - Writes XP Date Source = Streak End Date.
 * - Links the XP Event back to the Streak Occurrence.
 * - Marks the Streak Occurrence Source Status = Awarded.
 *
 * REQUIRED INPUT
 * - recordId = Streak Occurrences record ID
 *
 * IMPORTANT
 * - XP Events does NOT need an Achievement field.
 * - XP Events → XP Source must contain the exact Achievement name as a single-select option.
 * - Fix "60 Day Streak" to "60-Day Streak" in XP Events → XP Source before using a 60-Day achievement.
 ************************************************************************************************/


/************************************************************************************************
 * SECTION 1 — CONFIGURATION
 ************************************************************************************************/

const CONFIG = {
    tables: {
        streakOccurrences: "Streak Occurrences",
        achievements: "Achievements",
        xpEvents: "XP Events",
        xpRules: "XP Reward Rules",
    },

    streakOccurrences: {
        active: "Active?",
        enrollment: "Enrollment",
        achievement: "Achievement",
        streakDays: "Streak Days",
        streakStartDate: "Streak Start Date",
        streakEndDate: "Streak End Date",
        week: "Week",
        sourceStatus: "Source Status",
        xpEvents: "XP Events",
        occurrenceKey: "Streak Occurrence Key",
        lastEvaluatedAt: "Last Evaluated At",
        notes: "Notes",
    },

    achievements: {
        achievementName: "Achievement Name",
        triggerThreshold: "Trigger Threshold",
        rewardRuleKey: "Reward Rule Key",
    },

    xpRules: {
        active: "Active?",
        ruleKey: "Rule Key",
        xpAmount: "XP Amount",
    },

    xpEvents: {
        enrollment: "Enrollment",
        week: "Week",
        streakOccurrence: "Streak Occurrence",
        xpSource: "XP Source",
        xpBucketKey: "XP Bucket Key",
        xpPoints: "XP Points",
        xpReasonPublic: "XP Reason Public",
        active: "Active?",
        sourceKey: "Source Key",
        xpSourceDate: "XP Source Date",
        xpDateSource: "XP Date Source",
        awardMode: "Award Mode",
        processed: "Processed",
    },

    values: {
        statusReady: "Ready for XP",
        statusAwarded: "Awarded",
        statusDuplicate: "Duplicate",
        statusError: "Error",

        xpBucketKey: "Streak",
        xpDateSource: "Streak End Date",
        awardModeAutomatic: "Automatic",

        sourceKeyPrefix: "STREAK_XP|",
    },

    outputs: {
        success: "success",
        skipped: "skipped",
        error: "error",
    },
};


/************************************************************************************************
 * SECTION 2 — INPUT
 ************************************************************************************************/

const inputConfig = input.config();
const recordId = String(inputConfig.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input variable: recordId");
}


/************************************************************************************************
 * SECTION 3 — TABLES
 ************************************************************************************************/

const streakOccurrencesTable = base.getTable(CONFIG.tables.streakOccurrences);
const achievementsTable = base.getTable(CONFIG.tables.achievements);
const xpEventsTable = base.getTable(CONFIG.tables.xpEvents);
const xpRulesTable = base.getTable(CONFIG.tables.xpRules);


/************************************************************************************************
 * SECTION 4 — HELPERS
 ************************************************************************************************/

function setOutputs(values) {
    for (const [key, value] of Object.entries(values)) {
        output.set(key, value);
    }
}

function getLinkedRecordId(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return Array.isArray(value) && value.length > 0 ? value[0].id : null;
}

function getLinkedRecordIds(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return Array.isArray(value) ? value.map((item) => item.id) : [];
}

function getSelectName(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return value && value.name ? value.name : "";
}

function getNumber(record, fieldName) {
    const value = record.getCellValue(fieldName);
    return typeof value === "number" ? value : 0;
}

function isChecked(record, fieldName) {
    return record.getCellValue(fieldName) === true;
}

function getText(record, fieldName) {
    const value = record.getCellValue(fieldName);

    if (value === null || value === undefined) {
        return "";
    }

    if (typeof value === "string") {
        return value.trim();
    }

    if (typeof value === "number") {
        return String(value);
    }

    return String(value).trim();
}

function toDateKey(value) {
    if (!value) {
        return "";
    }

    const date = new Date(value);

    if (Number.isNaN(date.getTime())) {
        return "";
    }

    return date.toISOString().slice(0, 10);
}

function makeSourceKey(enrollmentId, achievementId, streakEndDateKey) {
    return `${CONFIG.values.sourceKeyPrefix}${enrollmentId}|${achievementId}|${streakEndDateKey}`;
}

function makeFallbackRuleKey(streakDays) {
    return `STREAK_${streakDays}DAY`;
}

function makeReason(achievementName, streakDays, streakEndDateKey) {
    return `${achievementName}: ${streakDays}-day shooting streak reached on ${streakEndDateKey}.`;
}

function chunkArray(items, chunkSize) {
    const chunks = [];

    for (let i = 0; i < items.length; i += chunkSize) {
        chunks.push(items.slice(i, i + chunkSize));
    }

    return chunks;
}

async function batchUpdate(table, records) {
    for (const chunk of chunkArray(records, 50)) {
        await table.updateRecordsAsync(chunk);
    }
}


/************************************************************************************************
 * SECTION 5 — LOAD STREAK OCCURRENCE
 ************************************************************************************************/

const occurrence = await streakOccurrencesTable.selectRecordAsync(recordId);

if (!occurrence) {
    setOutputs({
        ok: false,
        actionOut: "skipped_missing_streak_occurrence",
        statusOut: CONFIG.outputs.skipped,
        errorOut: `Streak Occurrence not found: ${recordId}`,
    });
    return;
}

const active = isChecked(
    occurrence,
    CONFIG.streakOccurrences.active
);

const sourceStatus = getSelectName(
    occurrence,
    CONFIG.streakOccurrences.sourceStatus
);

if (!active) {
    setOutputs({
        ok: true,
        actionOut: "skipped_inactive_streak_occurrence",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        streakOccurrenceId: recordId,
    });
    return;
}

if (sourceStatus !== CONFIG.values.statusReady) {
    setOutputs({
        ok: true,
        actionOut: "skipped_not_ready_for_xp",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        streakOccurrenceId: recordId,
        sourceStatus,
    });
    return;
}

const existingLinkedXpEventIds = getLinkedRecordIds(
    occurrence,
    CONFIG.streakOccurrences.xpEvents
);

if (existingLinkedXpEventIds.length > 0) {
    await streakOccurrencesTable.updateRecordAsync(recordId, {
        [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusAwarded,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
    });

    setOutputs({
        ok: true,
        actionOut: "skipped_already_linked_to_xp_event",
        statusOut: CONFIG.outputs.skipped,
        errorOut: "",
        streakOccurrenceId: recordId,
        linkedXpEventCount: existingLinkedXpEventIds.length,
    });
    return;
}


/************************************************************************************************
 * SECTION 6 — VALIDATE REQUIRED VALUES
 ************************************************************************************************/

const enrollmentId = getLinkedRecordId(
    occurrence,
    CONFIG.streakOccurrences.enrollment
);

const achievementId = getLinkedRecordId(
    occurrence,
    CONFIG.streakOccurrences.achievement
);

const weekId = getLinkedRecordId(
    occurrence,
    CONFIG.streakOccurrences.week
);

const streakEndDateKey = toDateKey(
    occurrence.getCellValue(CONFIG.streakOccurrences.streakEndDate)
);

const streakDays = getNumber(
    occurrence,
    CONFIG.streakOccurrences.streakDays
);

if (!enrollmentId || !achievementId || !streakEndDateKey || streakDays <= 0) {
    await streakOccurrencesTable.updateRecordAsync(recordId, {
        [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusError,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
        [CONFIG.streakOccurrences.notes]: "Missing required value for XP creation: Enrollment, Achievement, Streak End Date, or Streak Days.",
    });

    setOutputs({
        ok: false,
        actionOut: "error_missing_required_streak_values",
        statusOut: CONFIG.outputs.error,
        errorOut: "Missing required value for XP creation.",
        streakOccurrenceId: recordId,
        enrollmentId,
        achievementId,
        streakEndDateKey,
        streakDays,
    });
    return;
}


/************************************************************************************************
 * SECTION 7 — LOAD ACHIEVEMENT AND REWARD RULE
 ************************************************************************************************/

const achievement = await achievementsTable.selectRecordAsync(achievementId);

if (!achievement) {
    await streakOccurrencesTable.updateRecordAsync(recordId, {
        [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusError,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
        [CONFIG.streakOccurrences.notes]: `Achievement not found: ${achievementId}`,
    });

    setOutputs({
        ok: false,
        actionOut: "error_missing_achievement",
        statusOut: CONFIG.outputs.error,
        errorOut: `Achievement not found: ${achievementId}`,
        streakOccurrenceId: recordId,
    });
    return;
}

const achievementName = getText(
    achievement,
    CONFIG.achievements.achievementName
);

const achievementThreshold = getNumber(
    achievement,
    CONFIG.achievements.triggerThreshold
);

const configuredRuleKey = getText(
    achievement,
    CONFIG.achievements.rewardRuleKey
);

const fallbackRuleKey = makeFallbackRuleKey(
    achievementThreshold || streakDays
);

const allowedRuleKeys = [
    configuredRuleKey,
    fallbackRuleKey,
].filter(Boolean);

const xpRulesQuery = await xpRulesTable.selectRecordsAsync({
    fields: [
        CONFIG.xpRules.active,
        CONFIG.xpRules.ruleKey,
        CONFIG.xpRules.xpAmount,
    ],
});

const matchingRule = xpRulesQuery.records.find((rule) => {
    const ruleActive = isChecked(rule, CONFIG.xpRules.active);
    const ruleKey = getText(rule, CONFIG.xpRules.ruleKey);
    return ruleActive && allowedRuleKeys.includes(ruleKey);
});

if (!matchingRule) {
    await streakOccurrencesTable.updateRecordAsync(recordId, {
        [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusError,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
        [CONFIG.streakOccurrences.notes]: `No active XP Reward Rule found. Tried: ${allowedRuleKeys.join(", ")}`,
    });

    setOutputs({
        ok: false,
        actionOut: "error_missing_xp_reward_rule",
        statusOut: CONFIG.outputs.error,
        errorOut: `No active XP Reward Rule found. Tried: ${allowedRuleKeys.join(", ")}`,
        streakOccurrenceId: recordId,
        achievementName,
        allowedRuleKeys: allowedRuleKeys.join(", "),
    });
    return;
}

const xpAmount = getNumber(
    matchingRule,
    CONFIG.xpRules.xpAmount
);

if (xpAmount <= 0) {
    await streakOccurrencesTable.updateRecordAsync(recordId, {
        [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusError,
        [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
        [CONFIG.streakOccurrences.notes]: `XP Reward Rule has no positive XP Amount: ${matchingRule.id}`,
    });

    setOutputs({
        ok: false,
        actionOut: "error_invalid_xp_amount",
        statusOut: CONFIG.outputs.error,
        errorOut: `XP Reward Rule has no positive XP Amount: ${matchingRule.id}`,
        streakOccurrenceId: recordId,
        achievementName,
        xpRuleId: matchingRule.id,
    });
    return;
}


/************************************************************************************************
 * SECTION 8 — FIND EXISTING XP EVENT BY SOURCE KEY
 ************************************************************************************************/

const sourceKey = makeSourceKey(
    enrollmentId,
    achievementId,
    streakEndDateKey
);

const xpEventsQuery = await xpEventsTable.selectRecordsAsync({
    fields: [
        CONFIG.xpEvents.enrollment,
        CONFIG.xpEvents.week,
        CONFIG.xpEvents.streakOccurrence,
        CONFIG.xpEvents.xpSource,
        CONFIG.xpEvents.xpBucketKey,
        CONFIG.xpEvents.xpPoints,
        CONFIG.xpEvents.xpReasonPublic,
        CONFIG.xpEvents.active,
        CONFIG.xpEvents.sourceKey,
        CONFIG.xpEvents.xpSourceDate,
        CONFIG.xpEvents.xpDateSource,
        CONFIG.xpEvents.awardMode,
        CONFIG.xpEvents.processed,
    ],
});

const existingXpEvents = xpEventsQuery.records.filter((xpEvent) => {
    return getText(xpEvent, CONFIG.xpEvents.sourceKey) === sourceKey;
});

existingXpEvents.sort((a, b) => {
    return a.id.localeCompare(b.id);
});

const canonicalXpEvent = existingXpEvents.length > 0
    ? existingXpEvents[0]
    : null;

const duplicateXpEvents = existingXpEvents.slice(1);


/************************************************************************************************
 * SECTION 9 — CREATE OR UPDATE CANONICAL XP EVENT
 ************************************************************************************************/

const xpSourceDateIso = `${streakEndDateKey}T12:00:00.000Z`;
const xpReason = makeReason(
    achievementName,
    streakDays,
    streakEndDateKey
);

const xpFields = {
    [CONFIG.xpEvents.enrollment]: [{ id: enrollmentId }],
    [CONFIG.xpEvents.streakOccurrence]: [{ id: recordId }],
    [CONFIG.xpEvents.xpSource]: achievementName,
    [CONFIG.xpEvents.xpBucketKey]: CONFIG.values.xpBucketKey,
    [CONFIG.xpEvents.xpPoints]: xpAmount,
    [CONFIG.xpEvents.xpReasonPublic]: xpReason,
    [CONFIG.xpEvents.active]: true,
    [CONFIG.xpEvents.sourceKey]: sourceKey,
    [CONFIG.xpEvents.xpSourceDate]: xpSourceDateIso,
    [CONFIG.xpEvents.xpDateSource]: CONFIG.values.xpDateSource,
    [CONFIG.xpEvents.awardMode]: CONFIG.values.awardModeAutomatic,
    [CONFIG.xpEvents.processed]: true,
};

if (weekId) {
    xpFields[CONFIG.xpEvents.week] = [{ id: weekId }];
}

let xpEventId = null;
let actionOut = "";

if (canonicalXpEvent) {
    await xpEventsTable.updateRecordAsync(canonicalXpEvent.id, xpFields);
    xpEventId = canonicalXpEvent.id;
    actionOut = "updated_xp_event";
} else {
    xpEventId = await xpEventsTable.createRecordAsync(xpFields);
    actionOut = "created_xp_event";
}


/************************************************************************************************
 * SECTION 10 — MARK DUPLICATE XP EVENTS IF ANY EXIST
 ************************************************************************************************/

if (duplicateXpEvents.length > 0) {
    const duplicateUpdates = duplicateXpEvents.map((duplicate) => ({
        id: duplicate.id,
        fields: {
            [CONFIG.xpEvents.active]: false,
            [CONFIG.xpEvents.xpReasonPublic]: `Duplicate streak XP event. Canonical XP Event: ${xpEventId}`,
        },
    }));

    await batchUpdate(xpEventsTable, duplicateUpdates);
}


/************************************************************************************************
 * SECTION 11 — LINK STREAK OCCURRENCE AND MARK AWARDED
 ************************************************************************************************/

await streakOccurrencesTable.updateRecordAsync(recordId, {
    [CONFIG.streakOccurrences.xpEvents]: [{ id: xpEventId }],
    [CONFIG.streakOccurrences.sourceStatus]: CONFIG.values.statusAwarded,
    [CONFIG.streakOccurrences.lastEvaluatedAt]: new Date().toISOString(),
    [CONFIG.streakOccurrences.notes]: `Streak XP awarded through XP Event ${xpEventId}.`,
});


/************************************************************************************************
 * SECTION 12 — OUTPUTS
 ************************************************************************************************/

setOutputs({
    ok: true,
    actionOut,
    statusOut: CONFIG.outputs.success,
    errorOut: "",
    streakOccurrenceId: recordId,
    xpEventId,
    enrollmentId,
    achievementId,
    achievementName,
    streakDays,
    streakEndDateKey,
    weekId: weekId || "",
    xpAmount,
    xpRuleId: matchingRule.id,
    sourceKey,
    duplicateXpEventsMarkedInactive: duplicateXpEvents.length,
});

