    week: "Week",
    perfectWeekEligible: "Perfect Week Eligible?",
    perfectWeekUnlock: "Perfect Week Unlock",
    automationStatus: "Perfect Week Automation Status",
    automationError: "Perfect Week Automation Error",
  },

  achievementFields: {
    name: "Achievement Name",
    fallbackName: "Name",
    rewardRuleKey: "Reward Rule Key",
    active: "Active?",
  },

  unlockFields: {
    enrollment: "Enrollment",
    week: "Week",
    achievement: "Achievement",
    sourceStatus: "Source Status",
    xpAwardStatus: "XP Award Status",
    sourceKey: "Source Key",
    notes: "Notes",
  },
};

/***************************************************************************************************
 * 2. Helper Functions
 ***************************************************************************************************/

function getFirstLinkedId(record, fieldName) {
  const value = record.getCellValue(fieldName);
  if (!Array.isArray(value) || value.length === 0) return null;
  return value[0].id;
}

function getLinkedIds(record, fieldName) {
  const value = record.getCellValue(fieldName);
  if (!Array.isArray(value)) return [];
  return value.map((item) => item.id);
}

function getSingleSelectName(record, fieldName) {
  const value = record.getCellValue(fieldName);
  return value?.name || "";
}

function getText(record, fieldName) {
  return record.getCellValueAsString(fieldName).trim();
}

function isTruthy(value) {
  return value === true || value === 1 || value === "1";
}

function fieldExists(table, fieldName) {
  return table.fields.some((field) => field.name === fieldName);
}

function getAvailableField(table, preferredName, fallbackName = null) {
  if (fieldExists(table, preferredName)) return preferredName;
  if (fallbackName && fieldExists(table, fallbackName)) return fallbackName;
  return null;
}

async function updateWeekly(fields) {
  await weeklyTable.updateRecordAsync(weeklyRecord.id, fields);
}

/***************************************************************************************************
 * 3. Load Tables and Trigger Record
 ***************************************************************************************************/

const inputConfig = input.config();
const recordId = inputConfig.recordId;

if (!recordId) {
  throw new Error("Missing input variable: recordId");
}

const weeklyTable = base.getTable(CONFIG.tables.weekly);
const achievementsTable = base.getTable(CONFIG.tables.achievements);
const unlocksTable = base.getTable(CONFIG.tables.unlocks);

const weeklyRecord = await weeklyTable.selectRecordAsync(recordId);

if (!weeklyRecord) {
  throw new Error(`Weekly Athlete Summary record not found: ${recordId}`);
}

/***************************************************************************************************
 * 4. Validate Weekly Athlete Summary Record
 ***************************************************************************************************/

try {
  const enrollmentId = getFirstLinkedId(weeklyRecord, CONFIG.weeklyFields.enrollment);
  const weekId = getFirstLinkedId(weeklyRecord, CONFIG.weeklyFields.week);
  const existingUnlockIds = getLinkedIds(weeklyRecord, CONFIG.weeklyFields.perfectWeekUnlock);

  const eligibleValue = weeklyRecord.getCellValue(CONFIG.weeklyFields.perfectWeekEligible);
  const isEligible = isTruthy(eligibleValue);

  const automationStatus = getSingleSelectName(weeklyRecord, CONFIG.weeklyFields.automationStatus);

  if (!enrollmentId) {
    await updateWeekly({
      [CONFIG.weeklyFields.automationError]: "058 skipped: Missing Enrollment.",
    });
    return;
  }

  if (!weekId) {
    await updateWeekly({
      [CONFIG.weeklyFields.automationError]: "058 skipped: Missing Week.",
    });
    return;
  }

  if (!isEligible) {
    await updateWeekly({
      [CONFIG.weeklyFields.automationError]: "058 skipped: Perfect Week Eligible? is not 1.",
    });
    return;
  }

  if (automationStatus !== "Ready") {
    await updateWeekly({
      [CONFIG.weeklyFields.automationError]: `058 skipped: Perfect Week Automation Status is '${automationStatus}', not 'Ready'.`,
    });
    return;
  }

  if (existingUnlockIds.length > 0) {
    await updateWeekly({
      [CONFIG.weeklyFields.automationError]: "",
    });
    return;
  }

  /*************************************************************************************************
   * 5. Find Perfect Week Achievement
   *************************************************************************************************/

  const achievementNameField = getAvailableField(
    achievementsTable,
    CONFIG.achievementFields.name,
    CONFIG.achievementFields.fallbackName
  );

  if (!achievementNameField) {
    throw new Error("Achievements table is missing Achievement Name or Name field.");
  }

  if (!fieldExists(achievementsTable, CONFIG.achievementFields.rewardRuleKey)) {
    throw new Error(`Achievements table is missing field: ${CONFIG.achievementFields.rewardRuleKey}`);
  }

  const achievementQuery = await achievementsTable.selectRecordsAsync({
    fields: [
      achievementNameField,
      CONFIG.achievementFields.rewardRuleKey,
      CONFIG.achievementFields.active,
    ].filter((fieldName) => fieldExists(achievementsTable, fieldName)),
  });

  const matchingAchievements = achievementQuery.records.filter((achievement) => {
    const ruleKey = getText(achievement, CONFIG.achievementFields.rewardRuleKey);
    const name = getText(achievement, achievementNameField);
    const activeFieldExists = fieldExists(achievementsTable, CONFIG.achievementFields.active);
    const active = activeFieldExists ? achievement.getCellValue(CONFIG.achievementFields.active) === true : true;

    return (
      active &&
      (
        ruleKey === CONFIG.achievementLookup.ruleKey ||
        name === CONFIG.achievementLookup.achievementName
      )
    );
  });

  if (matchingAchievements.length === 0) {
    throw new Error(
      `No active Perfect Week achievement found. Expected Reward Rule Key '${CONFIG.achievementLookup.ruleKey}' or name '${CONFIG.achievementLookup.achievementName}'.`
    );
  }

  if (matchingAchievements.length > 1) {
    throw new Error(
      `Multiple active Perfect Week achievements found. Keep only one active achievement with Reward Rule Key '${CONFIG.achievementLookup.ruleKey}'.`
    );
  }

  const achievementRecord = matchingAchievements[0];

  /*************************************************************************************************
   * 6. Duplicate Protection by Source Key
   *************************************************************************************************/

  const sourceKey = `PERFECT_WEEK|${enrollmentId}|${weekId}`;

  const unlockFieldsToQuery = [
    CONFIG.unlockFields.enrollment,
    CONFIG.unlockFields.week,
    CONFIG.unlockFields.achievement,
  ];

  if (fieldExists(unlocksTable, CONFIG.unlockFields.sourceKey)) {
    unlockFieldsToQuery.push(CONFIG.unlockFields.sourceKey);
  }

  const unlockQuery = await unlocksTable.selectRecordsAsync({
    fields: unlockFieldsToQuery,
  });

  let duplicateUnlock = null;

  for (const unlock of unlockQuery.records) {
    if (fieldExists(unlocksTable, CONFIG.unlockFields.sourceKey)) {
      const existingSourceKey = getText(unlock, CONFIG.unlockFields.sourceKey);
      if (existingSourceKey && existingSourceKey === sourceKey) {
        duplicateUnlock = unlock;
        break;
      }
    }

    const unlockEnrollmentId = getFirstLinkedId(unlock, CONFIG.unlockFields.enrollment);
    const unlockWeekId = getFirstLinkedId(unlock, CONFIG.unlockFields.week);
    const unlockAchievementId = getFirstLinkedId(unlock, CONFIG.unlockFields.achievement);

    if (
      unlockEnrollmentId === enrollmentId &&
      unlockWeekId === weekId &&
      unlockAchievementId === achievementRecord.id
    ) {
      duplicateUnlock = unlock;
      break;
    }
  }

  if (duplicateUnlock) {
    await updateWeekly({
      [CONFIG.weeklyFields.perfectWeekUnlock]: [{ id: duplicateUnlock.id }],
      [CONFIG.weeklyFields.automationError]: "",
    });

    return;
  }

  /*************************************************************************************************
   * 7. Create Unlock
   *************************************************************************************************/

  const unlockPayload = {
    [CONFIG.unlockFields.enrollment]: [{ id: enrollmentId }],
    [CONFIG.unlockFields.week]: [{ id: weekId }],
    [CONFIG.unlockFields.achievement]: [{ id: achievementRecord.id }],
  };

  if (fieldExists(unlocksTable, CONFIG.unlockFields.sourceKey)) {
    unlockPayload[CONFIG.unlockFields.sourceKey] = sourceKey;
  }

  if (fieldExists(unlocksTable, CONFIG.unlockFields.sourceStatus)) {
    unlockPayload[CONFIG.unlockFields.sourceStatus] = { name: "Ready for XP" };
  }

  if (fieldExists(unlocksTable, CONFIG.unlockFields.xpAwardStatus)) {
    unlockPayload[CONFIG.unlockFields.xpAwardStatus] = { name: "Pending" };
  }

  if (fieldExists(unlocksTable, CONFIG.unlockFields.notes)) {
    unlockPayload[CONFIG.unlockFields.notes] =
      "Created by 058 after Weekly Athlete Summary qualified for Perfect Week.";
  }

  const newUnlockId = await unlocksTable.createRecordAsync(unlockPayload);

  /*************************************************************************************************
   * 8. Write Unlock Back to Weekly Athlete Summary
   *************************************************************************************************/

  await updateWeekly({
    [CONFIG.weeklyFields.perfectWeekUnlock]: [{ id: newUnlockId }],
    [CONFIG.weeklyFields.automationError]: "",
  });

} catch (error) {
  await updateWeekly({
    [CONFIG.weeklyFields.automationError]: `058 error: ${error.message}`,
  });

  throw error;
}

/***************************************************************************************************
 * 059 - Achievements and Milestones - Create XP Event from Achievement Unlock
 * Version: 2026-06-05 v3.1
 *
 * Purpose:
 * Creates one XP Event from one Athlete Achievement Unlock.
 *
 * Supports:
 * - Shot Milestone
 * - Perfect Week
 *
 * Important Shot Milestone behavior:
 * - Uses Athlete Achievement Unlocks -> Milestone Activity Date
 * - Writes XP Events -> XP Activity Date
 * - Writes XP Events -> XP Activity Date Source = Shot Milestone Activity Date
 * - Links XP Event to Achievement Unlock
 * - Links XP Event to Shot Milestones
 *
 * Required input variable:
 * - recordId = Airtable record ID from triggering Athlete Achievement Unlock
 ***************************************************************************************************/

async function main() {
  /*************************************************************************************************
   * 1. Configuration
   *************************************************************************************************/

  const CONFIG = {
    tables: {
      unlocks: "Athlete Achievement Unlocks",
      achievements: "Achievements",
      xpRewardRules: "XP Reward Rules",
      xpEvents: "XP Events",
      shotMilestones: "Shot Milestones",
      weeks: "Weeks",
    },

    statuses: {
      pending: "Pending",
      awarded: "Awarded",
      error: "Error",
      skipped: "Skipped",
    },

    ruleKeys: {
      perfectWeek: "PERFECT_WEEK",
      shotMilestone: "SHOT_MILESTONE",
    },

    xpBuckets: {
      perfectWeek: "Perfect Week",
      shotMilestone: "Shot Milestone",
    },

    xpSources: {
      perfectWeek: "Perfect Week",
      shotMilestone: "Shot Milestone",
    },

    xpActivityDateSources: {
      perfectWeek: "Perfect Week End Date",
      shotMilestone: "Shot Milestone Activity Date",
    },

    unlockFields: {
      achievement: "Achievement",
      enrollment: "Enrollment",
      week: "Week",
      xpEvents: "XP Events",
      xpAwardStatus: "XP Award Status",
      xpAwarded: "XP Awarded",

      shotMilestone: "Shot Milestone",
      milestoneSourceKey: "Milestone Source Key",
      milestoneActivityDate: "Milestone Activity Date",

      sourceKey: "Source Key",
      unlockKey: "Unlock Key",
      notes: "Notes",

      unlockedDate: "Unlocked Date",
      fallbackUnlockedDate: "Date Unlocked",

      weeklySummary: "Weekly Athlete Summary",
    },

    achievementFields: {
      achievementName: "Achievement Name",
      fallbackName: "Name",
      rewardRuleKey: "Reward Rule Key",
      active: "Active?",
    },

    rewardRuleFields: {
      ruleKey: "Rule Key",
      xpAmount: "XP Amount",
      active: "Active?",
    },

    shotMilestoneFields: {
      pointsAwarded: "Points Awarded",
      milestoneUniqueKey: "Milestone Unique Key",
      milestoneLabel: "Milestone Label",
      milestonePercent: "Milestone Percent",
      milestoneTier: "Milestone Tier",
      milestoneShotCount: "Milestone Shot Count",
      active: "Active?",
      fallbackActive: "Active",
    },

    weekFields: {
      weekEndDate: "Week End Date",
      fallbackEndDate: "End Date",
    },

    xpEventFields: {
      enrollment: "Enrollment",
      week: "Week",
      achievementUnlock: "Achievement Unlock",
      shotMilestones: "Shot Milestones",
      weeklySummary: "Weekly Athlete Summary",

      xpPoints: "XP Points",
      xpSource: "XP Source",
      xpBucket: "XP Bucket",
      sourceKey: "Source Key",

      xpReasonPublic: "XP Reason Public",
      xpReasonDebug: "XP Reason Debug",
      notes: "Notes",

      xpActivityDate: "XP Activity Date",
      xpActivityDateSource: "XP Activity Date Source",

      awardedAt: "Awarded At",
      active: "Active?",
      processed: "Processed",
      awardMode: "Award Mode",
    },
  };

  /*************************************************************************************************
   * 2. Helper Functions
   *************************************************************************************************/

  function findField(table, fieldName) {
    return table.fields.find((field) => field.name === fieldName) || null;
  }

  function fieldExists(table, fieldName) {
    return !!findField(table, fieldName);
  }

  function requireField(table, fieldName) {
    const field = findField(table, fieldName);

    if (!field) {
      throw new Error(`Missing required field on ${table.name}: ${fieldName}`);
    }

    return field;
  }

  function optionalField(table, fieldName) {
    return findField(table, fieldName);
  }

  function getAvailableField(table, preferredName, fallbackName = null) {
    if (fieldExists(table, preferredName)) return preferredName;
    if (fallbackName && fieldExists(table, fallbackName)) return fallbackName;
    return null;
  }

  function fieldNames(fields) {
    return fields.filter(Boolean).map((field) => field.name);
  }

  function getLinkedIds(record, field) {
    if (!field) return [];

    const value = record.getCellValue(field);

    if (!Array.isArray(value)) return [];

    return value.map((item) => item.id).filter(Boolean);
  }

  function getFirstLinkedId(record, field) {
    const ids = getLinkedIds(record, field);
    return ids.length ? ids[0] : null;
  }

  function getText(record, field) {
    if (!field) return "";

    try {
      return record.getCellValueAsString(field).trim();
    } catch {
      return "";
    }
  }

  function getSingleSelectName(record, field) {
    if (!field) return "";

    const value = record.getCellValue(field);

    if (value && value.name) return value.name;

    return "";
  }

  function getNumber(record, field) {
    if (!field) return 0;

    const value = record.getCellValue(field);

    if (typeof value === "number") return value;

    if (Array.isArray(value) && value.length > 0) {
      const first = value[0];

      if (typeof first === "number") return first;

      const parsedFirst = Number(first);
      return Number.isFinite(parsedFirst) ? parsedFirst : 0;
    }

    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }

  function getDateValue(record, field) {
    if (!field) return null;

    const value = record.getCellValue(field);

    if (!value) return null;

    if (value instanceof Date && !Number.isNaN(value.getTime())) {
      return value;
    }

    if (typeof value === "string") {
      const parsed = new Date(value);
      return Number.isNaN(parsed.getTime()) ? null : parsed;
    }

    if (Array.isArray(value) && value.length > 0) {
      const first = value[0];

      if (first instanceof Date && !Number.isNaN(first.getTime())) {
        return first;
      }

      if (typeof first === "string") {
        const parsed = new Date(first);
        return Number.isNaN(parsed.getTime()) ? null : parsed;
      }
    }

    return null;
  }

  function formatDate(dateValue) {
    if (!dateValue) return "No date";

    const year = dateValue.getFullYear();
    const month = String(dateValue.getMonth() + 1).padStart(2, "0");
    const day = String(dateValue.getDate()).padStart(2, "0");

    return `${year}-${month}-${day}`;
  }

  function hasSingleSelectChoice(field, choiceName) {
    if (!field || field.type !== "singleSelect") return true;

    const choices = field.options?.choices || [];

    return choices.some((choice) => choice.name === choiceName);
  }

  function valueForField(field, value, options = {}) {
    const required = options.required === true;

    if (!field) {
      if (required) {
        throw new Error(`Missing required field for value: ${value}`);
      }

      return undefined;
    }

    if (field.type === "singleSelect") {
      if (!hasSingleSelectChoice(field, value)) {
        if (required) {
          throw new Error(
            `Missing single-select option "${value}" on field "${field.name}".`
          );
        }

        return undefined;
      }

      return { name: value };
    }

    return value;
  }

  function addIfFieldExists(payload, field, value) {
    if (field && value !== undefined) {
      payload[field.name] = value;
    }
  }

  function buildPerfectWeekSourceKey(enrollmentId, weekId, fallbackKey) {
    if (fallbackKey) return fallbackKey;
    return `PERFECT_WEEK|${enrollmentId}|${weekId}`;
  }

  function buildShotMilestoneSourceKey(enrollmentId, shotMilestoneId, fallbackKey) {
    if (fallbackKey) return fallbackKey;
    return `SHOT_MILESTONE|${enrollmentId}|${shotMilestoneId}`;
  }

  function formatNumber(value) {
    const number = Number(value);
    if (!Number.isFinite(number)) return "";
    return number.toLocaleString("en-US");
  }

  function sentence(value) {
    const text = String(value || "").trim();
    if (!text) return "";
    if (/[.!?]$/.test(text)) return text;
    return `${text}.`;
  }

  function buildShotMilestoneReasonPublic(percent, tier, shotCount) {
    let reason = "Shot milestone reached";

    if (percent && tier) {
      reason = `Shot milestone reached: ${percent}% ${tier} milestone`;
    } else if (percent) {
      reason = `Shot milestone reached: ${percent}% milestone`;
    }

    if (shotCount) {
      reason += ` — ${formatNumber(shotCount)} shots`;
    }

    return sentence(reason);
  }

  function buildPerfectWeekReasonPublic() {
    return "Perfect Week completed.";
  }

  /*************************************************************************************************
   * 3. Input and Tables
   *************************************************************************************************/

  const inputConfig = input.config();
  const recordId = inputConfig.recordId;

  if (!recordId) {
    throw new Error("Missing input variable: recordId");
  }

  const unlocksTable = base.getTable(CONFIG.tables.unlocks);
  const achievementsTable = base.getTable(CONFIG.tables.achievements);
  const xpRewardRulesTable = base.getTable(CONFIG.tables.xpRewardRules);
  const xpEventsTable = base.getTable(CONFIG.tables.xpEvents);
  const shotMilestonesTable = base.getTable(CONFIG.tables.shotMilestones);
  const weeksTable = base.getTable(CONFIG.tables.weeks);

  /*************************************************************************************************
   * 4. Fields
   *************************************************************************************************/

  const unlock = {
    achievement: requireField(unlocksTable, CONFIG.unlockFields.achievement),
    enrollment: requireField(unlocksTable, CONFIG.unlockFields.enrollment),
    week: optionalField(unlocksTable, CONFIG.unlockFields.week),
    xpEvents: requireField(unlocksTable, CONFIG.unlockFields.xpEvents),
    xpAwardStatus: requireField(unlocksTable, CONFIG.unlockFields.xpAwardStatus),
    xpAwarded: optionalField(unlocksTable, CONFIG.unlockFields.xpAwarded),

    shotMilestone: optionalField(unlocksTable, CONFIG.unlockFields.shotMilestone),
    milestoneSourceKey: optionalField(unlocksTable, CONFIG.unlockFields.milestoneSourceKey),
    milestoneActivityDate: optionalField(unlocksTable, CONFIG.unlockFields.milestoneActivityDate),

    sourceKey: optionalField(unlocksTable, CONFIG.unlockFields.sourceKey),
    unlockKey: optionalField(unlocksTable, CONFIG.unlockFields.unlockKey),
    notes: optionalField(unlocksTable, CONFIG.unlockFields.notes),

    unlockedDate: optionalField(unlocksTable, CONFIG.unlockFields.unlockedDate),
    fallbackUnlockedDate: optionalField(unlocksTable, CONFIG.unlockFields.fallbackUnlockedDate),

    weeklySummary: optionalField(unlocksTable, CONFIG.unlockFields.weeklySummary),
  };

  const achievementNameFieldName = getAvailableField(
    achievementsTable,
    CONFIG.achievementFields.achievementName,
    CONFIG.achievementFields.fallbackName
  );

  if (!achievementNameFieldName) {
    throw new Error("Achievements table is missing Achievement Name or Name field.");
  }

  const achievement = {
    name: requireField(achievementsTable, achievementNameFieldName),
    rewardRuleKey: requireField(achievementsTable, CONFIG.achievementFields.rewardRuleKey),
    active: optionalField(achievementsTable, CONFIG.achievementFields.active),
  };

  const rewardRule = {
    ruleKey: requireField(xpRewardRulesTable, CONFIG.rewardRuleFields.ruleKey),
    xpAmount: requireField(xpRewardRulesTable, CONFIG.rewardRuleFields.xpAmount),
    active: optionalField(xpRewardRulesTable, CONFIG.rewardRuleFields.active),
  };

  const shotMilestone = {
    pointsAwarded: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.pointsAwarded),
    milestoneUniqueKey: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.milestoneUniqueKey),
    milestoneLabel: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.milestoneLabel),
    milestonePercent: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.milestonePercent),
    milestoneTier: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.milestoneTier),
    milestoneShotCount: optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.milestoneShotCount),
    active:
      optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.active) ||
      optionalField(shotMilestonesTable, CONFIG.shotMilestoneFields.fallbackActive),
  };

  const week = {
    weekEndDate:
      optionalField(weeksTable, CONFIG.weekFields.weekEndDate) ||
      optionalField(weeksTable, CONFIG.weekFields.fallbackEndDate),
  };

  const xp = {
    enrollment: requireField(xpEventsTable, CONFIG.xpEventFields.enrollment),
    week: optionalField(xpEventsTable, CONFIG.xpEventFields.week),
    achievementUnlock: requireField(xpEventsTable, CONFIG.xpEventFields.achievementUnlock),
    shotMilestones: optionalField(xpEventsTable, CONFIG.xpEventFields.shotMilestones),
    weeklySummary: optionalField(xpEventsTable, CONFIG.xpEventFields.weeklySummary),

    xpPoints: requireField(xpEventsTable, CONFIG.xpEventFields.xpPoints),
    xpSource: requireField(xpEventsTable, CONFIG.xpEventFields.xpSource),
    xpBucket: requireField(xpEventsTable, CONFIG.xpEventFields.xpBucket),
    sourceKey: requireField(xpEventsTable, CONFIG.xpEventFields.sourceKey),

    xpReasonPublic: optionalField(xpEventsTable, CONFIG.xpEventFields.xpReasonPublic),
    xpReasonDebug: optionalField(xpEventsTable, CONFIG.xpEventFields.xpReasonDebug),
    notes: optionalField(xpEventsTable, CONFIG.xpEventFields.notes),

    xpActivityDate: requireField(xpEventsTable, CONFIG.xpEventFields.xpActivityDate),
    xpActivityDateSource: requireField(xpEventsTable, CONFIG.xpEventFields.xpActivityDateSource),

    awardedAt: optionalField(xpEventsTable, CONFIG.xpEventFields.awardedAt),
    active: optionalField(xpEventsTable, CONFIG.xpEventFields.active),
    processed: optionalField(xpEventsTable, CONFIG.xpEventFields.processed),
    awardMode: optionalField(xpEventsTable, CONFIG.xpEventFields.awardMode),
  };

  /*************************************************************************************************
   * 5. Load Trigger Unlock
   *************************************************************************************************/

  const unlockRecord = await unlocksTable.selectRecordAsync(recordId, {
    fields: fieldNames([
      unlock.achievement,
      unlock.enrollment,
      unlock.week,
      unlock.xpEvents,
      unlock.xpAwardStatus,
      unlock.xpAwarded,

      unlock.shotMilestone,
      unlock.milestoneSourceKey,
      unlock.milestoneActivityDate,

      unlock.sourceKey,
      unlock.unlockKey,
      unlock.notes,

      unlock.unlockedDate,
      unlock.fallbackUnlockedDate,

      unlock.weeklySummary,
    ]),
  });

  if (!unlockRecord) {
    throw new Error(`Athlete Achievement Unlock record not found: ${recordId}`);
  }

  /*************************************************************************************************
   * 6. Validate Unlock Record
   *************************************************************************************************/

  const achievementId = getFirstLinkedId(unlockRecord, unlock.achievement);
  const enrollmentId = getFirstLinkedId(unlockRecord, unlock.enrollment);
  const weekId = unlock.week ? getFirstLinkedId(unlockRecord, unlock.week) : null;
  const existingXpEventIds = getLinkedIds(unlockRecord, unlock.xpEvents);
  const linkedShotMilestoneId = unlock.shotMilestone
    ? getFirstLinkedId(unlockRecord, unlock.shotMilestone)
    : null;

  const weeklySummaryIds = unlock.weeklySummary
    ? getLinkedIds(unlockRecord, unlock.weeklySummary)
    : [];

  const awardStatus = getSingleSelectName(unlockRecord, unlock.xpAwardStatus);

  if (!achievementId) {
    await markUnlockError("059 error: Missing Achievement.");
    return;
  }

  if (!enrollmentId) {
    await markUnlockError("059 error: Missing Enrollment.");
    return;
  }

  if (awardStatus !== CONFIG.statuses.pending) {
    output.set("result", `Skipped: XP Award Status is "${awardStatus || "blank"}", not Pending.`);
    output.set("unlockId", unlockRecord.id);
    return;
  }

  if (existingXpEventIds.length > 0) {
    await updateUnlock({
      [unlock.xpAwardStatus.name]: valueForField(
        unlock.xpAwardStatus,
        CONFIG.statuses.awarded,
        { required: true }
      ),
      [unlock.notes?.name]: "059 skipped: XP Event already linked.",
    });

    output.set("result", "Skipped: XP Event already linked. Marked Awarded.");
    output.set("unlockId", unlockRecord.id);
    output.set("existingXpEventIds", existingXpEventIds.join(", "));
    return;
  }

  /*************************************************************************************************
   * 7. Load Achievement
   *************************************************************************************************/

  const achievementRecord = await achievementsTable.selectRecordAsync(achievementId, {
    fields: fieldNames([
      achievement.name,
      achievement.rewardRuleKey,
      achievement.active,
    ]),
  });

  if (!achievementRecord) {
    await markUnlockError("059 error: Linked Achievement record could not be found.");
    return;
  }

  const achievementName = getText(achievementRecord, achievement.name);
  const achievementRuleKey = getText(achievementRecord, achievement.rewardRuleKey);

  const achievementActive = achievement.active
    ? achievementRecord.getCellValue(achievement.active) === true
    : true;

  if (!achievementActive) {
    await updateUnlock({
      [unlock.xpAwardStatus.name]: valueForField(
        unlock.xpAwardStatus,
        CONFIG.statuses.skipped,
        { required: false }
      ),
      [unlock.notes?.name]: "059 skipped: Linked Achievement is not active.",
    });

    output.set("result", "Skipped: Linked Achievement is not active.");
    return;
  }

  /*************************************************************************************************
   * 8. Determine XP Event Details
   *************************************************************************************************/

  let xpAmount = 0;
  let xpSourceValue = "";
  let xpBucketValue = "";
  let sourceKey = "";
  let xpReasonPublic = "";
  let xpReasonDebug = "";
  let xpActivityDate = null;
  let xpActivityDateSourceValue = "";
  let detailNote = "";

  const isPerfectWeek = achievementRuleKey === CONFIG.ruleKeys.perfectWeek;
  const isShotMilestone = achievementRuleKey === CONFIG.ruleKeys.shotMilestone || !!linkedShotMilestoneId;

  if (isPerfectWeek) {
    if (!weekId) {
      await markUnlockError("059 error: Perfect Week unlock is missing Week.");
      return;
    }

    xpAmount = await getXpAmountFromRewardRule(CONFIG.ruleKeys.perfectWeek);

    if (!xpAmount || xpAmount <= 0) {
      await markUnlockError("059 error: No valid XP amount found for Perfect Week.");
      return;
    }

    xpSourceValue = CONFIG.xpSources.perfectWeek;
    xpBucketValue = CONFIG.xpBuckets.perfectWeek;

    const fallbackKey =
      getText(unlockRecord, unlock.sourceKey) ||
      getText(unlockRecord, unlock.unlockKey);

    sourceKey = buildPerfectWeekSourceKey(enrollmentId, weekId, fallbackKey);

    const weekRecord = await weeksTable.selectRecordAsync(weekId, {
      fields: fieldNames([week.weekEndDate]),
    });

    const weekEndDate = weekRecord && week.weekEndDate
      ? getDateValue(weekRecord, week.weekEndDate)
      : null;

    xpActivityDate =
      weekEndDate ||
      getDateValue(unlockRecord, unlock.unlockedDate) ||
      getDateValue(unlockRecord, unlock.fallbackUnlockedDate);

    if (!xpActivityDate) {
      await markUnlockError("059 error: Could not determine Perfect Week XP Activity Date.");
      return;
    }

    xpActivityDateSourceValue = CONFIG.xpActivityDateSources.perfectWeek;

    xpReasonPublic = buildPerfectWeekReasonPublic();

    xpReasonDebug = [
      `Created by 059 v3.1.`,
      `Type: Perfect Week`,
      `Achievement: ${achievementName}`,
      `Reward Rule Key: ${achievementRuleKey}`,
      `Enrollment ID: ${enrollmentId}`,
      `Week ID: ${weekId}`,
      `XP Points: ${xpAmount}`,
      `Source Key: ${sourceKey}`,
      `XP Activity Date: ${formatDate(xpActivityDate)}`,
      `XP Activity Date Source: ${xpActivityDateSourceValue}`,
    ].join("\n");

    detailNote = xpReasonDebug;
  }

  if (isShotMilestone) {
    if (!linkedShotMilestoneId) {
      await markUnlockError("059 error: Shot Milestone unlock is missing linked Shot Milestone.");
      return;
    }

    const shotMilestoneRecord = await shotMilestonesTable.selectRecordAsync(linkedShotMilestoneId, {
      fields: fieldNames([
        shotMilestone.pointsAwarded,
        shotMilestone.milestoneUniqueKey,
        shotMilestone.milestoneLabel,
        shotMilestone.milestonePercent,
        shotMilestone.milestoneTier,
        shotMilestone.milestoneShotCount,
        shotMilestone.active,
      ]),
    });

    if (!shotMilestoneRecord) {
      await markUnlockError("059 error: Linked Shot Milestone record could not be found.");
      return;
    }

    const milestoneActive = shotMilestone.active
      ? shotMilestoneRecord.getCellValue(shotMilestone.active) === true ||
        shotMilestoneRecord.getCellValueAsString(shotMilestone.active).toLowerCase() === "checked"
      : true;

    if (!milestoneActive) {
      await updateUnlock({
        [unlock.xpAwardStatus.name]: valueForField(
          unlock.xpAwardStatus,
          CONFIG.statuses.skipped,
          { required: false }
        ),
        [unlock.notes?.name]: "059 skipped: Linked Shot Milestone is not active.",
      });

      output.set("result", "Skipped: Linked Shot Milestone is not active.");
      return;
    }

    xpAmount = getNumber(shotMilestoneRecord, shotMilestone.pointsAwarded);

    if (!xpAmount || xpAmount <= 0) {
      xpAmount = await getXpAmountFromRewardRule(CONFIG.ruleKeys.shotMilestone);
    }

    if (!xpAmount || xpAmount <= 0) {
      await markUnlockError("059 error: No valid XP amount found for Shot Milestone.");
      return;
    }

    const milestoneLabel = getText(shotMilestoneRecord, shotMilestone.milestoneLabel);
    const milestonePercent = getNumber(shotMilestoneRecord, shotMilestone.milestonePercent);
    const milestoneTier = getText(shotMilestoneRecord, shotMilestone.milestoneTier);
    const milestoneShotCount = getNumber(shotMilestoneRecord, shotMilestone.milestoneShotCount);

    xpSourceValue = CONFIG.xpSources.shotMilestone;
    xpBucketValue = CONFIG.xpBuckets.shotMilestone;

    const milestoneSourceKey = getText(unlockRecord, unlock.milestoneSourceKey);

    sourceKey = buildShotMilestoneSourceKey(
      enrollmentId,
      linkedShotMilestoneId,
      milestoneSourceKey
    );

    xpActivityDate = getDateValue(unlockRecord, unlock.milestoneActivityDate);

    if (!xpActivityDate) {
      await markUnlockError(
        "059 error: Shot Milestone unlock is missing Milestone Activity Date. Run 066 v2.0 or backfill this field before awarding XP."
      );
      return;
    }

    xpActivityDateSourceValue = CONFIG.xpActivityDateSources.shotMilestone;

    xpReasonPublic = buildShotMilestoneReasonPublic(
      milestonePercent,
      milestoneTier,
      milestoneShotCount
    );

    xpReasonDebug = [
      `Created by 059 v3.1.`,
      `Type: Shot Milestone`,
      `Achievement: ${achievementName}`,
      `Reward Rule Key: ${achievementRuleKey}`,
      `Enrollment ID: ${enrollmentId}`,
      `Shot Milestone ID: ${linkedShotMilestoneId}`,
      `Milestone Label: ${milestoneLabel}`,
      `Milestone Percent: ${milestonePercent}`,
      `Milestone Tier: ${milestoneTier}`,
      `Milestone Shot Count: ${milestoneShotCount}`,
      `XP Points: ${xpAmount}`,
      `Source Key: ${sourceKey}`,
      `XP Activity Date: ${formatDate(xpActivityDate)}`,
      `XP Activity Date Source: ${xpActivityDateSourceValue}`,
    ].join("\n");

    detailNote = xpReasonDebug;
  }

  if (!isPerfectWeek && !isShotMilestone) {
    await updateUnlock({
      [unlock.xpAwardStatus.name]: valueForField(
        unlock.xpAwardStatus,
        CONFIG.statuses.skipped,
        { required: false }
      ),
      [unlock.notes?.name]: `059 skipped: Unsupported Achievement Reward Rule Key "${achievementRuleKey}".`,
    });

    output.set("result", `Skipped: Unsupported Achievement Reward Rule Key "${achievementRuleKey}".`);
    return;
  }

  /*************************************************************************************************
   * 9. Preflight Single Select Options
   *************************************************************************************************/

  valueForField(xp.xpSource, xpSourceValue, { required: true });
  valueForField(xp.xpBucket, xpBucketValue, { required: true });
  valueForField(xp.xpActivityDateSource, xpActivityDateSourceValue, { required: true });
  valueForField(unlock.xpAwardStatus, CONFIG.statuses.awarded, { required: true });

  /*************************************************************************************************
   * 10. Duplicate Protection
   *************************************************************************************************/

  const xpQuery = await xpEventsTable.selectRecordsAsync({
    fields: fieldNames([
      xp.achievementUnlock,
      xp.sourceKey,
    ]),
  });

  let duplicateXpEvent = null;

  for (const xpEvent of xpQuery.records) {
    const existingSourceKey = getText(xpEvent, xp.sourceKey);

    if (existingSourceKey && existingSourceKey === sourceKey) {
      duplicateXpEvent = xpEvent;
      break;
    }

    const existingUnlockId = getFirstLinkedId(xpEvent, xp.achievementUnlock);

    if (existingUnlockId === unlockRecord.id) {
      duplicateXpEvent = xpEvent;
      break;
    }
  }

  if (duplicateXpEvent) {
    await updateUnlock({
      [unlock.xpEvents.name]: [{ id: duplicateXpEvent.id }],
      [unlock.xpAwardStatus.name]: valueForField(
        unlock.xpAwardStatus,
        CONFIG.statuses.awarded,
        { required: true }
      ),
      [unlock.notes?.name]: "059 linked existing duplicate-protected XP Event.",
    });

    output.set("result", "Existing XP Event found. Linked and marked Awarded.");
    output.set("xpEventId", duplicateXpEvent.id);
    output.set("sourceKey", sourceKey);
    return;
  }

  /*************************************************************************************************
   * 11. Build XP Event Payload
   *************************************************************************************************/

  const xpPayload = {};

  addIfFieldExists(xpPayload, xp.enrollment, [{ id: enrollmentId }]);

  if (weekId) {
    addIfFieldExists(xpPayload, xp.week, [{ id: weekId }]);
  }

  addIfFieldExists(xpPayload, xp.achievementUnlock, [{ id: unlockRecord.id }]);

  if (isShotMilestone && linkedShotMilestoneId) {
    addIfFieldExists(xpPayload, xp.shotMilestones, [{ id: linkedShotMilestoneId }]);
  }

  if (weeklySummaryIds.length > 0) {
    addIfFieldExists(xpPayload, xp.weeklySummary, weeklySummaryIds.map((id) => ({ id })));
  }

  addIfFieldExists(xpPayload, xp.xpPoints, xpAmount);
  addIfFieldExists(xpPayload, xp.xpSource, valueForField(xp.xpSource, xpSourceValue, { required: true }));
  addIfFieldExists(xpPayload, xp.xpBucket, valueForField(xp.xpBucket, xpBucketValue, { required: true }));
  addIfFieldExists(xpPayload, xp.sourceKey, sourceKey);

  addIfFieldExists(xpPayload, xp.xpActivityDate, xpActivityDate);
  addIfFieldExists(
    xpPayload,
    xp.xpActivityDateSource,
    valueForField(xp.xpActivityDateSource, xpActivityDateSourceValue, { required: true })
  );

  addIfFieldExists(xpPayload, xp.xpReasonPublic, xpReasonPublic);
  addIfFieldExists(xpPayload, xp.xpReasonDebug, xpReasonDebug);
  addIfFieldExists(xpPayload, xp.notes, detailNote);

  addIfFieldExists(xpPayload, xp.awardedAt, new Date());
  addIfFieldExists(xpPayload, xp.active, true);
  addIfFieldExists(xpPayload, xp.processed, true);

  if (xp.awardMode) {
    addIfFieldExists(
      xpPayload,
      xp.awardMode,
      valueForField(xp.awardMode, "Automatic", { required: false })
    );
  }

  /*************************************************************************************************
   * 12. Create XP Event
   *************************************************************************************************/

  const newXpEventId = await xpEventsTable.createRecordAsync(xpPayload);

  /*************************************************************************************************
   * 13. Link XP Event Back and Mark Unlock Awarded
   *************************************************************************************************/

  const unlockUpdate = {
    [unlock.xpEvents.name]: [{ id: newXpEventId }],
    [unlock.xpAwardStatus.name]: valueForField(
      unlock.xpAwardStatus,
      CONFIG.statuses.awarded,
      { required: true }
    ),
  };

  if (unlock.xpAwarded) {
    unlockUpdate[unlock.xpAwarded.name] = xpAmount;
  }

  if (unlock.notes) {
    const oldNotes = getText(unlockRecord, unlock.notes);

    unlockUpdate[unlock.notes.name] = [
      oldNotes,
      `059 v3.1 created XP Event ${newXpEventId}. XP Points: ${xpAmount}. Source Key: ${sourceKey}. Activity Date: ${formatDate(xpActivityDate)}. Activity Date Source: ${xpActivityDateSourceValue}.`,
    ]
      .filter(Boolean)
      .join("\n");
  }

  await updateUnlock(unlockUpdate);

  output.set("result", "059 created XP Event and marked Achievement Unlock awarded.");
  output.set("unlockId", unlockRecord.id);
  output.set("xpEventId", newXpEventId);
  output.set("xpBucket", xpBucketValue);
  output.set("xpSource", xpSourceValue);
  output.set("xpPoints", xpAmount);
  output.set("sourceKey", sourceKey);
  output.set("xpActivityDate", xpActivityDate ? xpActivityDate.toISOString() : "");
  output.set("xpActivityDateSource", xpActivityDateSourceValue);

  /*************************************************************************************************
   * 14. Local Helper Functions Requiring Loaded Tables
   *************************************************************************************************/

  async function getXpAmountFromRewardRule(ruleKey) {
    if (!ruleKey) return 0;

    const rewardRuleQuery = await xpRewardRulesTable.selectRecordsAsync({
      fields: fieldNames([
        rewardRule.ruleKey,
        rewardRule.xpAmount,
        rewardRule.active,
      ]),
    });

    const matchingRules = rewardRuleQuery.records.filter((rule) => {
      const existingRuleKey = getText(rule, rewardRule.ruleKey);

      const active = rewardRule.active
        ? rule.getCellValue(rewardRule.active) === true
        : true;

      return active && existingRuleKey === ruleKey;
    });

    if (matchingRules.length === 0) return 0;

    if (matchingRules.length > 1) {
      throw new Error(`Multiple active XP Reward Rules found for Rule Key "${ruleKey}".`);
    }

    return getNumber(matchingRules[0], rewardRule.xpAmount);
  }

  async function updateUnlock(fields) {
    const safeFields = {};

    for (const [fieldName, value] of Object.entries(fields)) {
      if (fieldName && value !== undefined) {
        safeFields[fieldName] = value;
      }
    }

    if (Object.keys(safeFields).length > 0) {
      await unlocksTable.updateRecordAsync(unlockRecord.id, safeFields);
    }
  }

  async function markUnlockError(message) {
    const update = {};

    update[unlock.xpAwardStatus.name] = valueForField(
      unlock.xpAwardStatus,
      CONFIG.statuses.error,
      { required: false }
    );

    if (unlock.notes) {
      update[unlock.notes.name] = message;
    }

    await updateUnlock(update);

    output.set("result", message);
    output.set("unlockId", unlockRecord.id);
  }
}

await main();

/************************************************************
 * 063 - HOMEWORK REVIEW AND XP - Copy Enrollment Grade Band to Homework Completion
 *
 * Version: v2.0
 * Date Written: 2026-04-27
 * Last Reviewed: 2026-05-23
 *
 * PURPOSE
 * - Runs from one Homework Completions record.
 * - Reads the linked Enrollment record.
 * - Pulls the linked Grade Band from the Enrollment record.
 * - Writes that Grade Band back to the Homework Completions record.
 *
 * FOLDER
 * - 06 - Homework Review and XP
 *
 * AUTOMATION NAME
 * - 061 - Homework Review and XP - Copy Enrollment Grade Band to Homework Completion
 *
 * TRIGGER TABLE
 * - Homework Completions
 *
 * TRIGGER TYPE
 * - When record matches conditions
 *
 * REQUIRED TRIGGER CONDITIONS
 * - Enrollment is not empty
 * - Grade Band is empty
 *
 * OPTIONAL TRIGGER CONDITION
 * - Satisfactory? is unchecked
 *
 * REQUIRED INPUT VARIABLES
 * - recordId = Airtable record ID from the triggering Homework Completions record
 *
 * PRIMARY TABLES USED
 * - Homework Completions
 * - Enrollments
 *
 * OUTPUT / WRITEBACK FIELDS
 * - Homework Completions → Grade Band = Enrollment → Grade Band
 *
 * IMPORTANT NOTES
 * - This is not a parent feedback email automation.
 * - This is not the homework XP event automation.
 * - This prepares Homework Completions records for later review/XP processing.
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: EASY-EDIT VARIABLES
   ========================================================= */

const HOMEWORK_TABLE = "Homework Completions";
const ENROLLMENTS_TABLE = "Enrollments";

/* ---------- Homework Completions fields ---------- */

const FIELD_HW_ENROLLMENT = "Enrollment";
const FIELD_HW_GRADE_BAND = "Grade Band";

/* ---------- Enrollments fields ---------- */

const FIELD_ENR_GRADE_BAND = "Grade Band";

/* ---------- Status values ---------- */

const STATUS_SUCCESS = "success";
const STATUS_SKIPPED = "skipped";
const STATUS_ERROR = "error";

/* =========================================================
   SECTION 2: INPUTS
   ========================================================= */

const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLE REFERENCES
   ========================================================= */

const homeworkTable = base.getTable(HOMEWORK_TABLE);
const enrollmentsTable = base.getTable(ENROLLMENTS_TABLE);

/* =========================================================
   SECTION 4: HELPER FUNCTIONS
   ========================================================= */

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function requireField(table, fieldName) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing required field on ${table.name}: ${fieldName}`);
    }
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getLinkedIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) return [];

    return raw
        .map(item => item?.id)
        .filter(Boolean);
}

function getFirstLinkedId(record, table, fieldName) {
    const ids = getLinkedIds(record, table, fieldName);
    return ids[0] || "";
}

function buildLinkedRecordArray(ids) {
    return ids.map(id => ({ id }));
}

function arraysMatch(a, b) {
    const left = [...a].sort().join("|");
    const right = [...b].sort().join("|");

    return left === right;
}

function setOutputSafe(name, value) {
    try {
        output.set(name, value);
    } catch {
        // Ignore output mapping errors.
    }
}

function exitSkipped(reason, details = {}) {
    setOutputSafe("statusOut", STATUS_SKIPPED);
    setOutputSafe("errorOut", reason);
    setOutputSafe("recordIdOut", recordId);
    setOutputSafe("homeworkCompletionIdOut", recordId);
    setOutputSafe("enrollmentIdOut", details.enrollmentId || "");
    setOutputSafe("gradeBandIdsOut", details.gradeBandIds || "");
}

/* =========================================================
   SECTION 5: VALIDATE REQUIRED FIELDS
   ========================================================= */

requireField(homeworkTable, FIELD_HW_ENROLLMENT);
requireField(homeworkTable, FIELD_HW_GRADE_BAND);
requireField(enrollmentsTable, FIELD_ENR_GRADE_BAND);

/* =========================================================
   SECTION 6: LOAD HOMEWORK COMPLETION RECORD
   ========================================================= */

const homeworkRecord = await homeworkTable.selectRecordAsync(recordId, {
    fields: [
        FIELD_HW_ENROLLMENT,
        FIELD_HW_GRADE_BAND,
    ],
});

if (!homeworkRecord) {
    throw new Error(`Homework Completion record not found: ${recordId}`);
}

/* =========================================================
   SECTION 7: READ HOMEWORK COMPLETION VALUES
   ========================================================= */

const enrollmentId = getFirstLinkedId(
    homeworkRecord,
    homeworkTable,
    FIELD_HW_ENROLLMENT
);

const existingHomeworkGradeBandIds = getLinkedIds(
    homeworkRecord,
    homeworkTable,
    FIELD_HW_GRADE_BAND
);

if (!enrollmentId) {
    exitSkipped("Homework Completion is missing Enrollment.");
    return;
}

/* =========================================================
   SECTION 8: LOAD ENROLLMENT RECORD
   ========================================================= */

const enrollmentRecord = await enrollmentsTable.selectRecordAsync(enrollmentId, {
    fields: [FIELD_ENR_GRADE_BAND],
});

if (!enrollmentRecord) {
    throw new Error(`Enrollment record not found: ${enrollmentId}`);
}

/* =========================================================
   SECTION 9: READ ENROLLMENT GRADE BAND
   ========================================================= */

const enrollmentGradeBandIds = getLinkedIds(
    enrollmentRecord,
    enrollmentsTable,
    FIELD_ENR_GRADE_BAND
);

if (!enrollmentGradeBandIds.length) {
    exitSkipped("Linked Enrollment is missing Grade Band.", {
        enrollmentId,
    });
    return;
}

/* =========================================================
   SECTION 10: AVOID UNNECESSARY WRITEBACK
   ========================================================= */

if (
    existingHomeworkGradeBandIds.length > 0 &&
    arraysMatch(existingHomeworkGradeBandIds, enrollmentGradeBandIds)
) {
    exitSkipped("Homework Completion Grade Band already matches Enrollment Grade Band.", {
        enrollmentId,
        gradeBandIds: existingHomeworkGradeBandIds.join(","),
    });
    return;
}

/* =========================================================
   SECTION 11: WRITE GRADE BAND TO HOMEWORK COMPLETION
   ========================================================= */

await homeworkTable.updateRecordAsync(recordId, {
    [FIELD_HW_GRADE_BAND]: buildLinkedRecordArray(enrollmentGradeBandIds),
});

/* =========================================================
   SECTION 12: OUTPUTS
   ========================================================= */

setOutputSafe("statusOut", STATUS_SUCCESS);
setOutputSafe("errorOut", "");
setOutputSafe("recordIdOut", recordId);
setOutputSafe("homeworkCompletionIdOut", recordId);
setOutputSafe("enrollmentIdOut", enrollmentId);
setOutputSafe("gradeBandIdsOut", enrollmentGradeBandIds.join(","));

console.log(JSON.stringify({
    automation: "061 - Homework Review and XP - Copy Enrollment Grade Band to Homework Completion",
    statusOut: STATUS_SUCCESS,
    recordIdOut: recordId,
    homeworkCompletionIdOut: recordId,
    enrollmentIdOut: enrollmentId,
    gradeBandIdsOut: enrollmentGradeBandIds.join(","),
}, null, 2));

/************************************************************************************************
 * 064 - Homework Review and XP - Prepare Homework XP Award
 * Version: 2026-06-17 v12.1
 *
 * PURPOSE
 * - Reads one Homework Completions record.
 * - Confirms coach grading is complete.
 * - Requires:
 *      Coach Feedback is not blank
 *      Satisfactory? is checked
 *      Review Complete is checked
 *      Enrollment exists
 *      Homework exists
 *      Week exists
 *      Submission Date exists
 * - Finds the active XP Reward Rule for HOMEWORK_COMPLETION.
 * - Writes XP Reward Rules -> XP Amount into Homework Completions -> Base XP Awarded.
 * - Sets Award Status = Pending.
 * - Re-arms Shot Milestone checking on the linked Enrollment.
 *
 * IMPORTANT
 * - This script does NOT create the XP Event.
 * - Automation 065 creates the XP Event after Total Homework XP Awarded updates.
 *
 * REQUIRED INPUT
 * - recordId = triggering Homework Completions record ID
 ************************************************************************************************/


/************************************************************************************************
 * SECTION 1 — CONFIGURATION
 ************************************************************************************************/

const CONFIG = {
    tables: {
        homeworkCompletions: "Homework Completions",
        xpRewardRules: "XP Reward Rules",
        enrollments: "Enrollments",
    },

    homework: {
        homework: "Homework",
        enrollment: "Enrollment",
        week: "Week",
        submissionDate: "Submission Date",

        satisfactory: "Satisfactory?",
        reviewComplete: "Review Complete",
        coachFeedback: "Coach Feedback",

        baseXpAwarded: "Base XP Awarded",
        extraCreditXpAwarded: "Extra Credit XP Awarded",
        totalHomeworkXpAwarded: "Total Homework XP Awarded",

        awardStatus: "Award Status",
        reviewedAt: "Reviewed At",
        reviewedBy: "Reviewed By",

        automationError: "Automation Error",
    },

    enrollments: {
        runShotMilestoneCheck: "Run Shot Milestone Check?",
    },

    xpRules: {
        ruleKey: "Rule Key",
        xpAmount: "XP Amount",
        active: "Active?",
    },

    values: {
        homeworkRuleKey: "HOMEWORK_COMPLETION",
        pendingStatus: "Pending",
        errorStatus: "Error",
        reviewedBy: "Mike Schmidt",
    },

    debug: {
        logToConsole: true,
    },
};


/************************************************************************************************
 * SECTION 2 — INPUT
 ************************************************************************************************/

const inputConfig = input.config();
const recordId = String(inputConfig.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input variable: recordId");
}

if (!recordId.startsWith("rec")) {
    throw new Error(`Invalid Homework Completion recordId input: ${recordId}`);
}


/************************************************************************************************
 * SECTION 3 — TABLES
 ************************************************************************************************/

const homeworkTable = base.getTable(CONFIG.tables.homeworkCompletions);
const xpRulesTable = base.getTable(CONFIG.tables.xpRewardRules);
const enrollmentsTable = base.getTable(CONFIG.tables.enrollments);


/************************************************************************************************
 * SECTION 4 — HELPERS
 ************************************************************************************************/

function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
        console.log(message);
    } else {
        console.log(message, JSON.stringify(data, null, 2));
    }
}

function setOutputSafe(key, value) {
    try {
        output.set(key, value);
    } catch {
        // Ignore output errors.
    }
}

function setOutputs(values) {
    for (const [key, value] of Object.entries(values)) {
        setOutputSafe(key, value);
    }
}

function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    try {
        return table.getField(fieldName);
    } catch {
        return null;
    }
}

function fieldExists(table, fieldName) {
    return Boolean(getFieldSafe(table, fieldName));
}

function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);

    if (!field) return false;

    if (field.isComputed === true) {
        return false;
    }

    const nonWritableTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "createdBy",
        "lastModifiedBy",
        "autoNumber",
        "button",
        "aiText",
        "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
}

function requireField(table, fieldName) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing required field: ${table.name} -> ${fieldName}`);
    }
}

function requireWritableField(table, fieldName) {
    requireField(table, fieldName);

    if (!isWritableField(table, fieldName)) {
        throw new Error(`Required field is not writable: ${table.name} -> ${fieldName}`);
    }
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";

    const raw = record.getCellValue(fieldName);

    if (raw === null || raw === undefined) return "";
    if (typeof raw === "string") return raw.trim();
    if (typeof raw === "number") return String(raw);

    if (typeof raw === "object" && raw.name) {
        return String(raw.name).trim();
    }

    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getNumber(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (raw === null || raw === undefined || raw === "") return 0;
    if (typeof raw === "number" && Number.isFinite(raw)) return raw;

    const text = String(record.getCellValueAsString(fieldName) || "")
        .replace(/,/g, "")
        .trim();

    const parsed = Number(text);
    return Number.isFinite(parsed) ? parsed : 0;
}

function getBooleanish(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (raw === true || raw === 1) return true;
    if (raw === false || raw === 0 || raw === null || raw === undefined) return false;

    if (typeof raw === "object" && raw.name) {
        return ["1", "true", "yes", "checked", "active"].includes(
            String(raw.name).trim().toLowerCase()
        );
    }

    const text = String(record.getCellValueAsString(fieldName) || "")
        .trim()
        .toLowerCase();

    return ["1", "true", "yes", "checked", "active"].includes(text);
}

function getLinkedRecordIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) return [];

    return raw
        .map((item) => item?.id)
