    sourceTable,
    sendType,
    sendMode,
    sendTag,

    athleteName,
    homeworkTitle,
    weekText,
    parentEmailsCsv,
    testRecipientEmail,

    toEmail: sendMode === "test" ? testRecipientEmail : parentEmailsCsv,
    liveRecipientEmail: parentEmailsCsv,
    testRecipientEmail,

    subjectOut,
    htmlOut,
    replyTo,

    assetFiles,
    assetFileCount: assetFiles.length,
    assetFileUrlCount: assetFilesWithUrls.length,
};

/* =========================================================
   SECTION 11: SEND TO MAKE
   ========================================================= */

let response;
let responseBody = {
    rawText: "",
    json: null,
};

try {
    response = await postJson(makeWebhookUrl, payload);
    responseBody = await readResponseBody(response);

    if (!response.ok) {
        throw new Error(`Webhook failed with status ${response.status}: ${responseBody.rawText}`);
    }

    validateMakeResponse(responseBody);
} catch (error) {
    const updates = {};

    if (fieldExists(homeworkCompletionsTable, FIELD_HW_PARENT_ERROR)) {
        updates[FIELD_HW_PARENT_ERROR] = String(error.message || error);
    }

    if (Object.keys(updates).length) {
        await homeworkCompletionsTable.updateRecordAsync(recordId, updates);
    }

    output.set("ok", false);
    output.set("recordId", recordId);
    output.set("sendMode", sendMode);
    output.set("errorOut", String(error.message || error));

    throw error;
}

