            displayedXp: xpInfo.displayedXp,
            xpEventMissing: xpInfo.xpEventMissing,
        };
    })
    .filter(submissionIsInsideWeek)
    .sort((a, b) => {
        return String(a.dateKey || "").localeCompare(String(b.dateKey || ""));
    });

