            reason = "Video feedback XP earned.";
        }

        if (isStreakXp(row)) {
            source = row.source || "Streak Award";
            reason = `${source} earned this week.`;
        }

        if (isThresholdXp(row)) {
            source = row.source || "Threshold Award";
            reason = `${source} earned this week.`;
