            .replace(/Submission Record = rec[a-zA-Z0-9]+\.?/g, "")
            .replace(/Unlock Record = rec[a-zA-Z0-9]+\.?/g, "")
            .replace(/Legacy Submission Key = [^\.]+\.?/g, "")
            .replace(/Streak Instance Key = [^\.]+\.?/g, "")
            .replace(/Homework Completion Key = .*$/gi, "")
            .replace(/Context:.*$/gi, "")
            .replace(/\s+/g, " ")
            .trim();

        return [
            source,
            reason || "Weekly XP item.",
            formatXp(row.points),
        ];
    });

