function normalizeSendMode(value) {
    const raw = String(value || "").trim().toLowerCase();

    if (["live", "l", "real", "send", "parent"].includes(raw)) {
        return "live";
    }

    if (["test", "t", "preview", "practice", "draft"].includes(raw)) {
        return "test";
