async function main() {
  let debugStep = "start";

  let meetingName = "";
  let zoomMeetingKey = "";
  let weekId = "";
  let attendeeCount = 0;
  let attendeesProcessed = 0;
  let attendeesSkipped = 0;
  let baseEventsCreated = 0;
  let baseEventsUpdated = 0;
  let bonusEventsCreated = 0;
  let bonusEventsUpdated = 0;

  try {
    debugStep = "load_zoom_meeting";
    setOutputSafe("debugStep", debugStep);

    const zoomRecord = await zoomTable.selectRecordAsync(recordId, {
      fields: buildFieldsToLoad(zoomTable, [
        CONFIG.zoom.meetingName,
        zoomStartField,
        CONFIG.zoom.week,
        CONFIG.zoom.attendees,
        CONFIG.zoom.createXpEvents,
        CONFIG.zoom.xpAwardStatus,
        CONFIG.zoom.zoomMeetingKey,
        CONFIG.zoom.meetingStatus,
      ]),
    });

    if (!zoomRecord) {
      throw new Error(`Zoom Meeting record not found: ${recordId}`);
    }

    meetingName = getText(zoomRecord, zoomTable, CONFIG.zoom.meetingName) || zoomRecord.name;
    zoomMeetingKey = getText(zoomRecord, zoomTable, CONFIG.zoom.zoomMeetingKey);
    weekId = getFirstLinkedRecordId(zoomRecord, zoomTable, CONFIG.zoom.week);

    const createXpEvents = getBooleanish(
      zoomRecord,
      zoomTable,
      CONFIG.zoom.createXpEvents
    );

    const currentAwardStatus = getText(
      zoomRecord,
      zoomTable,
      CONFIG.zoom.xpAwardStatus
    );

    const meetingStatus = getText(
      zoomRecord,
      zoomTable,
      CONFIG.zoom.meetingStatus
    );

    const meetingDateKey = dateToDateKey(
      getRaw(zoomRecord, zoomTable, zoomStartField)
    );

    const attendeeIds = [
      ...new Set(getLinkedRecordIds(zoomRecord, zoomTable, CONFIG.zoom.attendees)),
    ];

    attendeeCount = attendeeIds.length;

    if (!createXpEvents) {
      setFinalOutputs({
        ok: true,
        actionOut: "skipped_create_xp_events_not_checked",
        statusOut: CONFIG.values.skipped,
        meetingName,
        zoomMeetingKey,
        weekId,
        attendeeCount,
      });
      return;
    }

    if (normalizeText(currentAwardStatus) === normalizeText(CONFIG.statuses.awarded)) {
      setFinalOutputs({
        ok: true,
        actionOut: "skipped_already_awarded",
        statusOut: CONFIG.values.skipped,
        meetingName,
        zoomMeetingKey,
        weekId,
        attendeeCount,
      });
      return;
    }

    if (
      fieldExists(zoomTable, CONFIG.zoom.meetingStatus) &&
      normalizeText(meetingStatus) !== normalizeText(CONFIG.statuses.completed)
    ) {
      setFinalOutputs({
        ok: true,
        actionOut: "skipped_meeting_not_completed",
        statusOut: CONFIG.values.skipped,
        errorOut: `Skipped: Meeting Status is "${meetingStatus}", not "${CONFIG.statuses.completed}".`,
        meetingName,
        zoomMeetingKey,
        weekId,
        attendeeCount,
      });
      return;
    }

    if (!weekId) {
      throw new Error("Zoom Meeting is missing Week.");
    }

    if (!zoomMeetingKey) {
      throw new Error("Zoom Meeting is missing Zoom Meeting Key.");
    }

    if (!meetingDateKey) {
      throw new Error(`Zoom Meeting is missing a valid date in field "${zoomStartField}".`);
    }

    if (attendeeIds.length === 0) {
      throw new Error("Zoom Meeting has no linked Attendees.");
    }

    debugStep = "load_source_records";
    setOutputSafe("debugStep", debugStep);

    const [enrollmentsQuery, rulesQuery, xpEventsQuery, zoomHistoryQuery] = await Promise.all([
      enrollmentsTable.selectRecordsAsync({
        fields: buildFieldsToLoad(enrollmentsTable, [
          CONFIG.enrollments.active,
          CONFIG.enrollments.fullName,
        ]),
      }),
      rulesTable.selectRecordsAsync({
        fields: buildFieldsToLoad(rulesTable, [
          CONFIG.xpRewardRules.ruleKey,
          CONFIG.xpRewardRules.xpAmount,
          CONFIG.xpRewardRules.xpSourceLabel,
          CONFIG.xpRewardRules.active,
        ]),
      }),
      xpEventsTable.selectRecordsAsync({
        fields: buildFieldsToLoad(xpEventsTable, [
          CONFIG.xpEvents.enrollment,
          CONFIG.xpEvents.week,
          CONFIG.xpEvents.xpSource,
          CONFIG.xpEvents.xpBucketKey,
          CONFIG.xpEvents.xpPoints,
          CONFIG.xpEvents.xpReason,
          CONFIG.xpEvents.active,
          CONFIG.xpEvents.sourceKey,
          CONFIG.xpEvents.awardMode,
          CONFIG.xpEvents.awardedBy,
          CONFIG.xpEvents.processed,
          CONFIG.xpEvents.error,
          CONFIG.xpEvents.zoomMeeting,
        ]),
      }),
      zoomTable.selectRecordsAsync({
        fields: buildFieldsToLoad(zoomTable, [
          CONFIG.zoom.meetingName,
          zoomStartField,
          CONFIG.zoom.week,
          CONFIG.zoom.attendees,
          CONFIG.zoom.xpAwardStatus,
          CONFIG.zoom.zoomMeetingKey,
          CONFIG.zoom.meetingStatus,
        ]),
      }),
    ]);

    const enrollmentById = new Map(
      enrollmentsQuery.records.map(record => [record.id, record])
    );

    const ruleIndex = indexActiveRulesByKey(rulesQuery.records);

    const baseRule = findRequiredRule(
      ruleIndex,
      CONFIG.ruleKeys.base,
      "Base"
    );

    const bonus2Rule = findRequiredRule(
      ruleIndex,
      CONFIG.ruleKeys.bonus2,
      "Bonus 2"
    );

    const bonus3Rule = findRequiredRule(
      ruleIndex,
      CONFIG.ruleKeys.bonus3,
      "Bonus 3"
    );

    const sourceKeyIndex = new Map();

    for (const xpRecord of xpEventsQuery.records) {
      const existingSourceKey = getText(
        xpRecord,
        xpEventsTable,
        CONFIG.xpEvents.sourceKey
      );

      if (!existingSourceKey) continue;

      sourceKeyIndex.set(normalizeKey(existingSourceKey), xpRecord);
    }

    debugStep = "process_attendees";
    setOutputSafe("debugStep", debugStep);

    for (const enrollmentId of attendeeIds) {
      const enrollmentRecord = enrollmentById.get(enrollmentId);

      if (!enrollmentRecord) {
        attendeesSkipped += 1;

        log("Skipped attendee because Enrollment record was not found", {
          enrollmentId,
        });

        continue;
      }

      if (
        fieldExists(enrollmentsTable, CONFIG.enrollments.active) &&
        !getBooleanish(enrollmentRecord, enrollmentsTable, CONFIG.enrollments.active)
      ) {
        attendeesSkipped += 1;

        log("Skipped inactive attendee Enrollment", {
          enrollmentId,
        });

        continue;
      }

      const attendeeName = fieldExists(enrollmentsTable, CONFIG.enrollments.fullName)
        ? getText(enrollmentRecord, enrollmentsTable, CONFIG.enrollments.fullName)
        : enrollmentRecord.name;

      const qualifyingMeetingKeys = new Set();

      for (const meetingRecord of zoomHistoryQuery.records) {
        const historicalMeetingKey = getText(
          meetingRecord,
          zoomTable,
          CONFIG.zoom.zoomMeetingKey
        );

        if (!historicalMeetingKey) continue;

        const historicalWeekId = getFirstLinkedRecordId(
          meetingRecord,
          zoomTable,
          CONFIG.zoom.week
        );

        if (!historicalWeekId) continue;

        const historicalDateKey = dateToDateKey(
          getRaw(meetingRecord, zoomTable, zoomStartField)
        );

        if (!historicalDateKey) continue;

        if (compareDateKeys(historicalDateKey, meetingDateKey) > 0) {
          continue;
        }

        if (
          fieldExists(zoomTable, CONFIG.zoom.meetingStatus) &&
          normalizeText(getText(meetingRecord, zoomTable, CONFIG.zoom.meetingStatus)) !==
            normalizeText(CONFIG.statuses.completed)
        ) {
          continue;
        }

        const historicalAttendeeIds = getLinkedRecordIds(
          meetingRecord,
          zoomTable,
          CONFIG.zoom.attendees
        );

        if (!historicalAttendeeIds.includes(enrollmentId)) continue;

        qualifyingMeetingKeys.add(historicalMeetingKey);
      }

      const attendanceCount = qualifyingMeetingKeys.size;

      const baseSourceKey = buildBaseSourceKey(zoomMeetingKey, enrollmentId);

      const baseResult = await createOrUpdateXpEvent({
        sourceKeyIndex,
        sourceKey: baseSourceKey,
        enrollmentId,
        weekId,
        source: baseRule.xpSourceLabel || CONFIG.xpLabels.baseSourceFallback,
        bucketKey: CONFIG.xpLabels.bucketKey,
        points: baseRule.xpAmount,
        reason: buildXpReason({
          meetingName,
          zoomMeetingKey,
          enrollmentId,
          attendeeName,
          attendanceCount,
          ruleKey: baseRule.ruleKey,
          xpPoints: baseRule.xpAmount,
          xpType: "Base Attendance",
        }),
        zoomMeetingId: recordId,
      });

      if (baseResult.action === "created") {
        baseEventsCreated += 1;
      } else {
        baseEventsUpdated += 1;
      }

      if (attendanceCount === CONFIG.bonusMeetingCounts.bonus2) {
        const bonus2SourceKey = buildBonus2SourceKey(enrollmentId);

        const bonus2Result = await createOrUpdateXpEvent({
          sourceKeyIndex,
          sourceKey: bonus2SourceKey,
          enrollmentId,
          weekId,
          source: bonus2Rule.xpSourceLabel || CONFIG.xpLabels.bonus2SourceFallback,
          bucketKey: CONFIG.xpLabels.bucketKey,
          points: bonus2Rule.xpAmount,
          reason: buildXpReason({
            meetingName,
            zoomMeetingKey,
            enrollmentId,
            attendeeName,
            attendanceCount,
            ruleKey: bonus2Rule.ruleKey,
            xpPoints: bonus2Rule.xpAmount,
            xpType: "Meeting Count 2 Bonus",
          }),
          zoomMeetingId: recordId,
        });

        if (bonus2Result.action === "created") {
          bonusEventsCreated += 1;
        } else {
          bonusEventsUpdated += 1;
        }
      }

      if (attendanceCount === CONFIG.bonusMeetingCounts.bonus3) {
        const bonus3SourceKey = buildBonus3SourceKey(enrollmentId);

        const bonus3Result = await createOrUpdateXpEvent({
          sourceKeyIndex,
          sourceKey: bonus3SourceKey,
          enrollmentId,
          weekId,
          source: bonus3Rule.xpSourceLabel || CONFIG.xpLabels.bonus3SourceFallback,
          bucketKey: CONFIG.xpLabels.bucketKey,
          points: bonus3Rule.xpAmount,
          reason: buildXpReason({
            meetingName,
            zoomMeetingKey,
            enrollmentId,
            attendeeName,
            attendanceCount,
            ruleKey: bonus3Rule.ruleKey,
            xpPoints: bonus3Rule.xpAmount,
            xpType: "Meeting Count 3 Bonus",
          }),
          zoomMeetingId: recordId,
        });

        if (bonus3Result.action === "created") {
          bonusEventsCreated += 1;
        } else {
          bonusEventsUpdated += 1;
        }
      }

      attendeesProcessed += 1;
    }

    if (attendeesProcessed === 0) {
      throw new Error("No attendees were processed. Check Attendees and Enrollment Active? values.");
    }

    debugStep = "write_zoom_success";
    setOutputSafe("debugStep", debugStep);

    await updateRecordSafe(zoomTable, recordId, {
      [CONFIG.zoom.xpAwardStatus]: buildSingleSelectValueOptional(
        zoomTable,
        CONFIG.zoom.xpAwardStatus,
        CONFIG.statuses.awarded
      ),
      [CONFIG.zoom.createXpEvents]: false,
      [CONFIG.zoom.xpAwardedAt]: new Date().toISOString(),
      [CONFIG.zoom.xpAwardError]: "",
    });

    setFinalOutputs({
      ok: true,
      actionOut: "awarded_zoom_attendance_xp",
      statusOut: CONFIG.values.success,
      errorOut: "",
      meetingName,
      zoomMeetingKey,
      weekId,
      attendeeCount,
      attendeesProcessed,
      attendeesSkipped,
      baseEventsCreated,
      baseEventsUpdated,
      bonusEventsCreated,
      bonusEventsUpdated,
    });

    log("Automation 101 complete", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      recordId,
      meetingName,
      zoomMeetingKey,
      weekId,
      attendeeCount,
      attendeesProcessed,
      attendeesSkipped,
      baseEventsCreated,
      baseEventsUpdated,
      bonusEventsCreated,
      bonusEventsUpdated,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setOutputSafe("debugStep", `FAILED AT: ${debugStep}`);

    await updateRecordSafe(zoomTable, recordId, {
      [CONFIG.zoom.xpAwardStatus]: buildSingleSelectValueOptional(
        zoomTable,
        CONFIG.zoom.xpAwardStatus,
        CONFIG.statuses.error
      ),
      [CONFIG.zoom.xpAwardError]: message,
    });

    setFinalOutputs({
      ok: false,
      actionOut: "error",
      statusOut: CONFIG.values.error,
      errorOut: message,
      meetingName,
      zoomMeetingKey,
      weekId,
      attendeeCount,
      attendeesProcessed,
      attendeesSkipped,
      baseEventsCreated,
      baseEventsUpdated,
      bonusEventsCreated,
      bonusEventsUpdated,
    });

    log("Automation 101 failed", {
      scriptName: CONFIG.scriptName,
      version: CONFIG.version,
      debugStep,
      error: message,
      recordId,
    });

    throw error;
  }
}


/* =========================================================
   SECTION 7: RUN
========================================================= */

await main();

/************************************************************
 * 111 - VIDEO REVIEW AND XP
 * Copy Enrollment Grade Band to Video Feedback
 *
 * Version: v1.1
 * Date Written: 2026-04-27
 * Last Reviewed: 2026-05-23
 *
 * PURPOSE
 * - Runs from one Video Feedback record.
 * - Reads the linked Enrollment record.
 * - Pulls the linked Grade Band from the Enrollment record.
 * - Writes that Grade Band back to the Video Feedback record.
 *
 * FOLDER
 * - 11 - Video Review and XP
 *
 * AUTOMATION NAME
 * - 111 - Video Review and XP - Copy Enrollment Grade Band to Video Feedback
 *
 * TRIGGER TABLE
 * - Video Feedback
 *
 * TRIGGER TYPE
 * - When record matches conditions
 *
 * REQUIRED TRIGGER CONDITIONS
 * - Enrollment is not empty
 * - Grade Band is empty
 *
 * OPTIONAL TRIGGER CONDITION
 * - Feedback Posted? is unchecked
 *
 * REQUIRED INPUT VARIABLES
 * - recordId = Airtable record ID from the triggering Video Feedback record
 *
 * OUTPUT / WRITEBACK FIELDS
 * - Video Feedback → Grade Band = Enrollment → Grade Band
 *
 * IMPORTANT NOTES
 * - This is not an email automation.
 * - This is not the Video Feedback parent email webhook.
 * - This prepares Video Feedback records for later Video XP processing.
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: EASY-EDIT VARIABLES
   ========================================================= */

const VIDEO_TABLE = "Video Feedback";
const ENROLLMENTS_TABLE = "Enrollments";

const FIELD_VIDEO_ENROLLMENT = "Enrollment";
const FIELD_VIDEO_GRADE_BAND = "Grade Band";

const FIELD_ENROLLMENT_GRADE_BAND = "Grade Band";

/* =========================================================
   SECTION 2: INPUTS
   ========================================================= */

const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 3: TABLE REFERENCES
   ========================================================= */

const videoTable = base.getTable(VIDEO_TABLE);
const enrollmentsTable = base.getTable(ENROLLMENTS_TABLE);

/* =========================================================
   SECTION 4: HELPER FUNCTIONS
   ========================================================= */

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function getLinkedIds(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return [];

    const value = record.getCellValue(fieldName);

    if (!Array.isArray(value)) return [];

    return value
        .map(item => item?.id)
        .filter(Boolean);
}

function getFirstLinkedId(record, table, fieldName) {
    const ids = getLinkedIds(record, table, fieldName);
    return ids[0] || "";
}

function buildLinkedRecordArray(ids) {
    return ids.map(id => ({ id }));
}

/* =========================================================
   SECTION 5: LOAD VIDEO FEEDBACK RECORD
   ========================================================= */

const videoRecord = await videoTable.selectRecordAsync(recordId);

if (!videoRecord) {
    throw new Error(`Video Feedback record not found: ${recordId}`);
}

/* =========================================================
   SECTION 6: VALIDATE VIDEO FEEDBACK FIELDS
   ========================================================= */

if (!fieldExists(videoTable, FIELD_VIDEO_ENROLLMENT)) {
    throw new Error(`Missing field on Video Feedback table: ${FIELD_VIDEO_ENROLLMENT}`);
}

if (!fieldExists(videoTable, FIELD_VIDEO_GRADE_BAND)) {
    throw new Error(`Missing field on Video Feedback table: ${FIELD_VIDEO_GRADE_BAND}`);
}

/* =========================================================
   SECTION 7: GET LINKED ENROLLMENT
   ========================================================= */

const enrollmentId = getFirstLinkedId(
    videoRecord,
    videoTable,
    FIELD_VIDEO_ENROLLMENT
);

if (!enrollmentId) {
    throw new Error("Video Feedback record is missing Enrollment.");
}

/* =========================================================
   SECTION 8: LOAD ENROLLMENT RECORD
   ========================================================= */

const enrollmentRecord = await enrollmentsTable.selectRecordAsync(enrollmentId);

if (!enrollmentRecord) {
    throw new Error(`Enrollment not found: ${enrollmentId}`);
}

if (!fieldExists(enrollmentsTable, FIELD_ENROLLMENT_GRADE_BAND)) {
    throw new Error(`Missing field on Enrollments table: ${FIELD_ENROLLMENT_GRADE_BAND}`);
}

/* =========================================================
   SECTION 9: GET GRADE BAND FROM ENROLLMENT
   ========================================================= */

const enrollmentGradeBandIds = getLinkedIds(
    enrollmentRecord,
    enrollmentsTable,
    FIELD_ENROLLMENT_GRADE_BAND
);

if (!enrollmentGradeBandIds.length) {
    throw new Error("Linked Enrollment is missing Grade Band.");
}

/* =========================================================
   SECTION 10: AVOID UNNECESSARY WRITEBACK
   ========================================================= */

const currentVideoGradeBandIds = getLinkedIds(
    videoRecord,
    videoTable,
    FIELD_VIDEO_GRADE_BAND
);

const currentKey = currentVideoGradeBandIds.slice().sort().join("|");
const nextKey = enrollmentGradeBandIds.slice().sort().join("|");

if (currentKey === nextKey) {
    output.set("statusOut", "SKIPPED_ALREADY_MATCHES");
    output.set("recordIdOut", recordId);
    output.set("enrollmentIdOut", enrollmentId);
    output.set("gradeBandCountOut", enrollmentGradeBandIds.length);
    output.set("messageOut", "Video Feedback Grade Band already matches Enrollment Grade Band.");
    return;
}

/* =========================================================
   SECTION 11: WRITE GRADE BAND BACK TO VIDEO FEEDBACK
   ========================================================= */

await videoTable.updateRecordAsync(recordId, {
    [FIELD_VIDEO_GRADE_BAND]: buildLinkedRecordArray(enrollmentGradeBandIds),
});

/* =========================================================
   SECTION 12: OUTPUTS
   ========================================================= */

output.set("statusOut", "SUCCESS");
output.set("recordIdOut", recordId);
output.set("enrollmentIdOut", enrollmentId);
output.set("gradeBandCountOut", enrollmentGradeBandIds.length);
output.set("gradeBandIdsOut", enrollmentGradeBandIds.join(","));

/************************************************************
 * 112 - VIDEO REVIEW AND XP
 * Create Video Feedback from Submission Asset
 *
 * Version: v2.1
 * Date Written: 2026-05-19
 * Last Reviewed: 2026-05-23
 *
 * PURPOSE
 * - Runs from one Submission Assets record.
 * - Creates one linked Video Feedback record when the asset is routed
 *   to Video Feedback.
 * - Uses the Submission Asset record ID as the stable Video Feedback Key.
 * - Prevents duplicate Video Feedback records by checking:
 *   1. Submission Assets → Video Feedback linked record field
 *   2. Video Feedback → Video Feedback Key
 * - Skips incomplete or incorrectly routed records without creating
 *   partial Video Feedback records.
 *
 * FOLDER
 * - 11 - Video Review and XP
 *
 * AUTOMATION NAME
 * - 112 - Video Review and XP - Create Video Feedback from Submission Asset
 *
 * TRIGGER TABLE
 * - Submission Assets
 *
 * TRIGGER TYPE
 * - When record matches conditions
 *
 * REQUIRED TRIGGER CONDITIONS
 * - Upload Destination is Video Feedback
 * - Airtable Attachment is not empty
 * - Submission - Linked is not empty
 * - Enrollment - Linked is not empty
 * - Video Feedback is empty
 *
 * REQUIRED INPUT VARIABLES
 * - recordId = Airtable record ID from the triggering Submission Assets record
 *
 * PRIMARY TABLES USED
 * - Submission Assets
 * - Video Feedback
 *
 * IMPORTANT NOTES
 * - This is not the Video Feedback parent email automation.
 * - This is not the Video XP award automation.
 * - This creates the Video Feedback review record only.
 * - Grade Band can still be filled later by Automation 111.
 * - XP can still be awarded later by a separate Video XP automation.
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: INPUTS
   ========================================================= */

const cfg = input.config();
const recordId = String(cfg.recordId || "").trim();

if (!recordId) {
    throw new Error("Missing required input: recordId");
}

/* =========================================================
   SECTION 2: TABLES / FIELDS / CONSTANTS
   ========================================================= */

const ASSETS_TABLE = "Submission Assets";
const VIDEO_TABLE = "Video Feedback";

/* ---------- Submission Assets fields ---------- */

const FIELD_ASSET_SUBMISSION = "Submission - Linked";
const FIELD_ASSET_ENROLLMENT = "Enrollment - Linked";
const FIELD_ASSET_WEEK = "Week";
const FIELD_ASSET_VIDEO_FEEDBACK = "Video Feedback";
const FIELD_ASSET_UPLOAD_DESTINATION = "Upload Destination";
const FIELD_ASSET_ASSET_PURPOSE = "Asset Purpose";
const FIELD_ASSET_ATTACHMENT = "Airtable Attachment";
const FIELD_ASSET_ORIGINAL_FILE_NAME = "Original File Name";
const FIELD_ASSET_GOOGLE_FILE_URL = "Google Drive File URL";
const FIELD_ASSET_UPLOADED_AT = "Uploaded At";

/* ---------- Video Feedback fields ---------- */

const FIELD_VIDEO_SUBMISSION_ASSET = "Submission Asset";
const FIELD_VIDEO_SUBMISSION = "Submission";
const FIELD_VIDEO_ENROLLMENT = "Enrollment";
const FIELD_VIDEO_KEY = "Video Feedback Key";
const FIELD_VIDEO_AWARD_STATUS = "Award Status";
const FIELD_VIDEO_ACTIVE = "Active?";
const FIELD_VIDEO_URL = "Video URL or Drive Link";
const FIELD_VIDEO_FILE_NAME = "Video Asset File Name";
const FIELD_VIDEO_UPLOADED_AT = "Video Asset Uploaded At";

/* ---------- Routing values ---------- */

const DEST_VIDEO_FEEDBACK = "video feedback";
const PURPOSE_VIDEO_FEEDBACK = "video for feedback";

/* ---------- Select values ---------- */

const AWARD_STATUS_PENDING = "Pending";

/* =========================================================
   SECTION 3: TABLE REFERENCES
   ========================================================= */

const assetsTable = base.getTable(ASSETS_TABLE);
const videoTable = base.getTable(VIDEO_TABLE);

/* =========================================================
   SECTION 4: HELPERS
   ========================================================= */

function fieldExists(table, fieldName) {
    if (!table || !fieldName) return false;

    try {
        table.getField(fieldName);
        return true;
    } catch {
        return false;
    }
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getLinkedIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) return [];

    return raw
        .map(item => item?.id)
        .filter(Boolean);
}

function firstLinkedId(record, table, fieldName) {
    const ids = getLinkedIds(record, table, fieldName);
    return ids[0] || "";
}

function getAttachmentCount(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);
    return Array.isArray(raw) ? raw.length : 0;
}

function normalize(value) {
    return String(value || "")
        .trim()
        .toLowerCase();
}

function setOutputSafe(name, value) {
    try {
        output.set(name, value);
    } catch {
        // Ignore output mapping issues.
    }
}

function exitSkipped(reason, details = {}) {
    setOutputSafe("statusOut", "skipped");
    setOutputSafe("actionOut", "skipped");
    setOutputSafe("reasonOut", reason);
    setOutputSafe("submissionAssetIdOut", recordId);
    setOutputSafe("videoFeedbackIdOut", details.videoFeedbackIdOut || "");
    setOutputSafe("videoFeedbackKeyOut", recordId);
    setOutputSafe("uploadDestinationOut", details.uploadDestination || "");
    setOutputSafe("assetPurposeOut", details.assetPurpose || "");
    setOutputSafe("errorOut", details.errorOut || "");
}

function buildSingleSelectValue(table, fieldName, optionName) {
    if (!fieldExists(table, fieldName)) return null;

    const field = table.getField(fieldName);

    if (field.type !== "singleSelect") {
        return optionName;
    }

    const choices = field?.options?.choices || [];
    const match = choices.find(choice =>
        String(choice?.name || "").trim().toLowerCase() === String(optionName).trim().toLowerCase()
    );

    if (!match) {
        throw new Error(`Missing single-select option "${optionName}" in ${table.name}.${fieldName}`);
    }

    return { id: match.id };
}

function addIfFieldExists(payload, table, fieldName, value) {
    if (!fieldExists(table, fieldName)) return;

    if (value === null || value === undefined) return;

    if (typeof value === "string" && value.trim() === "") return;

    payload[fieldName] = value;
}

/* =========================================================
   SECTION 5: LOAD SUBMISSION ASSET
   ========================================================= */

const assetFieldsToLoad = [
    FIELD_ASSET_SUBMISSION,
    FIELD_ASSET_ENROLLMENT,
    FIELD_ASSET_WEEK,
    FIELD_ASSET_VIDEO_FEEDBACK,
    FIELD_ASSET_UPLOAD_DESTINATION,
    FIELD_ASSET_ASSET_PURPOSE,
    FIELD_ASSET_ATTACHMENT,
    FIELD_ASSET_ORIGINAL_FILE_NAME,
    FIELD_ASSET_GOOGLE_FILE_URL,
    FIELD_ASSET_UPLOADED_AT,
].filter(fieldName => fieldExists(assetsTable, fieldName));

const assetRecord = await assetsTable.selectRecordAsync(recordId, {
    fields: assetFieldsToLoad,
});

if (!assetRecord) {
    throw new Error(`Submission Asset record not found: ${recordId}`);
}

/* =========================================================
   SECTION 6: READ SOURCE VALUES
   ========================================================= */

const submissionId = firstLinkedId(
    assetRecord,
    assetsTable,
    FIELD_ASSET_SUBMISSION
);

const enrollmentId = firstLinkedId(
    assetRecord,
    assetsTable,
    FIELD_ASSET_ENROLLMENT
);

const existingLinkedVideoFeedbackIds = getLinkedIds(
    assetRecord,
    assetsTable,
    FIELD_ASSET_VIDEO_FEEDBACK
);

const uploadDestination = normalize(
    getText(assetRecord, assetsTable, FIELD_ASSET_UPLOAD_DESTINATION)
);

const assetPurpose = normalize(
    getText(assetRecord, assetsTable, FIELD_ASSET_ASSET_PURPOSE)
);

const attachmentCount = getAttachmentCount(
    assetRecord,
    assetsTable,
    FIELD_ASSET_ATTACHMENT
);

const originalFileName = getText(
    assetRecord,
    assetsTable,
    FIELD_ASSET_ORIGINAL_FILE_NAME
);

const googleFileUrl = getText(
    assetRecord,
    assetsTable,
    FIELD_ASSET_GOOGLE_FILE_URL
);

const uploadedAtRaw = getRaw(
    assetRecord,
    assetsTable,
    FIELD_ASSET_UPLOADED_AT
);

const videoFeedbackKey = recordId;

/* =========================================================
   SECTION 7: ROUTING / READINESS GUARDS
   ========================================================= */

const routedToVideoFeedback =
    uploadDestination === DEST_VIDEO_FEEDBACK ||
    assetPurpose === PURPOSE_VIDEO_FEEDBACK;

if (!routedToVideoFeedback) {
    exitSkipped("Submission Asset is not routed to Video Feedback.", {
        uploadDestination,
        assetPurpose,
    });
    return;
}

if (!submissionId) {
    exitSkipped("Submission - Linked is blank.", {
        uploadDestination,
        assetPurpose,
        errorOut: "Submission - Linked is blank.",
    });
    return;
}

if (!enrollmentId) {
    exitSkipped("Enrollment - Linked is blank.", {
        uploadDestination,
        assetPurpose,
        errorOut: "Enrollment - Linked is blank.",
    });
    return;
}

if (attachmentCount < 1) {
    exitSkipped("Airtable Attachment is blank.", {
        uploadDestination,
        assetPurpose,
        errorOut: "Airtable Attachment is blank.",
    });
    return;
}

if (existingLinkedVideoFeedbackIds.length > 0) {
    exitSkipped("Video Feedback already linked on Submission Asset.", {
        uploadDestination,
        assetPurpose,
        videoFeedbackIdOut: existingLinkedVideoFeedbackIds[0] || "",
    });
    return;
}

/* =========================================================
   SECTION 8: SECOND DEDUPE CHECK BY VIDEO FEEDBACK KEY
   ========================================================= */

const videoFieldsToLoad = [
    FIELD_VIDEO_KEY,
    FIELD_VIDEO_SUBMISSION_ASSET,
    FIELD_VIDEO_SUBMISSION,
    FIELD_VIDEO_ENROLLMENT,
    FIELD_VIDEO_AWARD_STATUS,
].filter(fieldName => fieldExists(videoTable, fieldName));

const videoQuery = await videoTable.selectRecordsAsync({
    fields: videoFieldsToLoad,
});

const existingVideoFeedback = videoQuery.records.find(record => {
    const existingKey = normalize(getText(record, videoTable, FIELD_VIDEO_KEY));
    return existingKey === normalize(videoFeedbackKey);
});

if (existingVideoFeedback) {
    exitSkipped("Video Feedback already exists for this Video Feedback Key.", {
        uploadDestination,
        assetPurpose,
        videoFeedbackIdOut: existingVideoFeedback.id,
    });
    return;
}

/* =========================================================
   SECTION 9: BUILD VIDEO FEEDBACK PAYLOAD
   ========================================================= */

const payload = {};

addIfFieldExists(payload, videoTable, FIELD_VIDEO_SUBMISSION_ASSET, [{ id: recordId }]);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_SUBMISSION, [{ id: submissionId }]);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_ENROLLMENT, [{ id: enrollmentId }]);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_KEY, videoFeedbackKey);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_ACTIVE, true);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_URL, googleFileUrl);
addIfFieldExists(payload, videoTable, FIELD_VIDEO_FILE_NAME, originalFileName);

if (uploadedAtRaw) {
    addIfFieldExists(payload, videoTable, FIELD_VIDEO_UPLOADED_AT, uploadedAtRaw);
}

if (fieldExists(videoTable, FIELD_VIDEO_AWARD_STATUS)) {
    const pendingValue = buildSingleSelectValue(
        videoTable,
        FIELD_VIDEO_AWARD_STATUS,
        AWARD_STATUS_PENDING
    );

    addIfFieldExists(payload, videoTable, FIELD_VIDEO_AWARD_STATUS, pendingValue);
}

if (Object.keys(payload).length === 0) {
    throw new Error("No writable fields were found for Video Feedback payload.");
}

/* =========================================================
   SECTION 10: CREATE VIDEO FEEDBACK RECORD
   ========================================================= */

const videoFeedbackId = await videoTable.createRecordAsync(payload);

/* =========================================================
   SECTION 11: OUTPUTS
   ========================================================= */

setOutputSafe("statusOut", "success");
setOutputSafe("actionOut", "created");
setOutputSafe("reasonOut", "");
setOutputSafe("submissionAssetIdOut", recordId);
setOutputSafe("videoFeedbackIdOut", videoFeedbackId);
setOutputSafe("videoFeedbackKeyOut", videoFeedbackKey);
setOutputSafe("uploadDestinationOut", uploadDestination);
setOutputSafe("assetPurposeOut", assetPurpose);
setOutputSafe("errorOut", "");

console.log(JSON.stringify({
    automation: "112 - Video Review and XP - Create Video Feedback from Submission Asset",
    statusOut: "success",
    actionOut: "created",
    submissionAssetIdOut: recordId,
    videoFeedbackIdOut: videoFeedbackId,
    videoFeedbackKeyOut: videoFeedbackKey,
    uploadDestinationOut: uploadDestination,
    assetPurposeOut: assetPurpose,
    originalFileName,
    googleFileUrl,
}, null, 2));

/************************************************************
 * 113 - VIDEO REVIEW AND XP
 * Assign Base Video XP
 *
 * Version: v6.1
 * Date Written: 2026-06-06
 * Date Updated: 2026-06-17
 *
 * PURPOSE
 * - Runs from one Video Feedback record.
 * - Confirms video feedback has been posted.
 * - Confirms the record should receive XP.
 * - Reads the active shared video XP rule from XP Reward Rules.
 * - Uses Rule Key = VIDEO_SUBMISSION.
 * - Does NOT use Grade Band.
 * - Writes XP Reward Rules -> XP Amount into Video Feedback -> Base XP Awarded.
 * - Sets Award Status to Pending.
 * - Checks Ready for XP Automation? so Automation 114 can create/update the XP Event.
 * - Writes Reviewed By and Reviewed At when the review is completed.
 * - Does NOT create the XP Event.
 *
 * IMPORTANT HANDOFF RULE
 * - 113 prepares the Video Feedback record for XP event creation.
 * - 114 creates/updates the XP Event and then marks Award Status = Awarded.
 *
 * REQUIRED INPUT VARIABLES
 * - recordId = Airtable record ID from the triggering Video Feedback record
 ************************************************************/

// @ts-nocheck

/* =========================================================
   SECTION 1: CONFIGURATION
========================================================= */

const CONFIG = {
    tables: {
        videoFeedback: "Video Feedback",
        xpRewardRules: "XP Reward Rules",
    },

    video: {
        feedbackPosted: "Feedback Posted?",
        baseXpAwarded: "Base XP Awarded",
