        coachFeedback: "Coach Feedback",
        enrollment: "Enrollment",
        submission: "Submission",
        readyForXp: "Ready for XP Automation?",
        workflowStatus: "Video Feedback Workflow Status",
        xpEvents: "XP Events",
        reviewedBy: "Reviewed By",
        reviewedAt: "Reviewed At",
    },

    rules: {
        active: "Active?",
        xpAmount: "XP Amount",
        rewardRule: "Reward Rule",
        ruleKey: "Rule Key",
    },

    values: {
        ruleKeyVideo: "VIDEO_SUBMISSION",
        awardStatusPending: "Pending",
        awardStatusAwarded: "Awarded",
        awardStatusError: "Error",
        workflowStatusReadyForXp: "Ready for XP",
