        success: "success",
        skipped: "skipped",
        error: "error",
    },

    debug: {
        logToConsole: true,
    },
};

/* =========================================================
   SECTION 2: RUNTIME CONTEXT
========================================================= */

let recordId = "";
let videoTable = null;
let rulesTable = null;
let videoRecordLoaded = false;

/* =========================================================
   SECTION 3: FIELD CACHE
========================================================= */

const fieldCache = new Map();

/* =========================================================
   SECTION 4: HELPERS
========================================================= */

function log(message, data = null) {
    if (!CONFIG.debug.logToConsole) return;

    if (data === null || data === undefined) {
        console.log(message);
    } else {
        console.log(message, JSON.stringify(data, null, 2));
    }
}

function setOutputSafe(name, value) {
    try {
        output.set(name, value);
    } catch {
        // Ignore output mapping errors in automation context.
    }
}

function setCommonOutputs(status, message, details = {}) {
    setOutputSafe("statusOut", status);
    setOutputSafe("errorOut", message || "");
    setOutputSafe("recordIdOut", recordId || "");
    setOutputSafe("matchedRuleOut", details.matchedRule || "");
    setOutputSafe("baseXpOut", details.baseXp ?? 0);
    setOutputSafe("ruleKeyOut", details.ruleKey || CONFIG.values.ruleKeyVideo);
    setOutputSafe("actionOut", details.action || "");
    setOutputSafe("reviewedByOut", details.reviewedBy || "");
    setOutputSafe("reviewedAtOut", details.reviewedAt || "");
}

function getFieldSafe(table, fieldName) {
    if (!table || !fieldName) return null;

    const tableName = table.name || "unknown-table";
    const cacheKey = `${tableName}:${fieldName}`;

    if (fieldCache.has(cacheKey)) {
        return fieldCache.get(cacheKey);
    }

    try {
        const field = table.getField(fieldName);
        fieldCache.set(cacheKey, field);
        return field;
    } catch {
        fieldCache.set(cacheKey, null);
        return null;
    }
}

function fieldExists(table, fieldName) {
    return !!getFieldSafe(table, fieldName);
}

function fieldHasType(table, fieldName, allowedTypes) {
    const field = getFieldSafe(table, fieldName);
    return !!field && allowedTypes.includes(field.type);
}

function requireField(table, fieldName) {
    if (!fieldExists(table, fieldName)) {
        throw new Error(`Missing required field on ${table.name}: ${fieldName}`);
    }
}

function requireFieldType(table, fieldName, allowedTypes) {
    requireField(table, fieldName);

    const field = getFieldSafe(table, fieldName);

    if (!allowedTypes.includes(field.type)) {
        throw new Error(
            `Field ${table.name}.${fieldName} has type "${field.type}" but expected one of: ${allowedTypes.join(", ")}`
        );
    }
}

function isWritableField(table, fieldName) {
    const field = getFieldSafe(table, fieldName);

    if (!field) return false;

    if (field.isComputed === true) {
        return false;
    }

    const nonWritableTypes = new Set([
        "formula",
        "rollup",
        "count",
        "lookup",
        "multipleLookupValues",
        "createdTime",
        "lastModifiedTime",
        "createdBy",
        "lastModifiedBy",
        "autoNumber",
        "button",
        "aiText",
        "externalSyncSource",
    ]);

    return !nonWritableTypes.has(field.type);
}

function requireWritableField(table, fieldName) {
    requireField(table, fieldName);

    if (!isWritableField(table, fieldName)) {
        throw new Error(`Field ${table.name}.${fieldName} exists but is not writable.`);
    }
}

function normalizeText(value) {
    return String(value || "").trim().toUpperCase();
}

function normalizeLooseText(value) {
    return String(value || "").trim().toLowerCase();
}

function singleSelectOptionExists(table, fieldName, optionName) {
    const field = getFieldSafe(table, fieldName);

    if (!field || field.type !== "singleSelect") {
        return true;
    }

    return field.options?.choices?.some(
        choice => normalizeLooseText(choice?.name) === normalizeLooseText(optionName)
    ) === true;
}

function requireSingleSelectOption(table, fieldName, optionName) {
    requireFieldType(table, fieldName, ["singleSelect"]);

    if (!singleSelectOptionExists(table, fieldName, optionName)) {
        const field = getFieldSafe(table, fieldName);
        const available = field?.options?.choices?.map(choice => choice.name).join(", ") || "";

        throw new Error(
            `Missing single-select option "${optionName}" in ${table.name}.${fieldName}. Available options: ${available}`
        );
    }
}

function buildSingleSelectValue(table, fieldName, optionName) {
    const field = getFieldSafe(table, fieldName);

    if (!field || field.type !== "singleSelect") {
        return optionName;
    }

    const choices = field?.options?.choices || [];

    const match = choices.find(choice =>
        normalizeLooseText(choice?.name) === normalizeLooseText(optionName)
    );

    if (!match) {
        const available = choices.map(choice => choice.name).join(", ");
        throw new Error(
            `Missing single-select option "${optionName}" in ${table.name}.${fieldName}. Available options: ${available}`
        );
    }

    return { id: match.id };
}

function buildOptionalSingleSelectValue(table, fieldName, optionName) {
    const field = getFieldSafe(table, fieldName);

    if (!field) return undefined;

    if (field.type !== "singleSelect") {
        return optionName;
    }

    if (!singleSelectOptionExists(table, fieldName, optionName)) {
        log(`Optional single-select write skipped. Missing option: ${table.name}.${fieldName} = ${optionName}`);
        return undefined;
    }

    return buildSingleSelectValue(table, fieldName, optionName);
}

function getRaw(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return null;
    return record.getCellValue(fieldName);
}

function getText(record, table, fieldName) {
    if (!record || !fieldExists(table, fieldName)) return "";
    return String(record.getCellValueAsString(fieldName) || "").trim();
}

function getNumber(record, table, fieldName, fallback = null) {
    const raw = getRaw(record, table, fieldName);

    if (typeof raw === "number" && Number.isFinite(raw)) {
        return raw;
    }

    const text = String(raw ?? "")
        .replace(/[$,%]/g, "")
        .replace(/,/g, "")
        .trim();

    if (!text) return fallback;

    const n = Number(text);
    return Number.isFinite(n) ? n : fallback;
}

function getCheckbox(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (raw === true) return true;
    if (raw === false) return false;
    if (raw === 1) return true;
    if (raw === 0) return false;

    if (raw && typeof raw === "object" && raw.name) {
        const name = String(raw.name).trim().toLowerCase();
        return ["1", "true", "yes", "checked", "active"].includes(name);
    }

    const text = String(raw ?? "").trim().toLowerCase();
    return ["1", "true", "yes", "checked", "active"].includes(text);
}

function getLinkedIds(record, table, fieldName) {
    const raw = getRaw(record, table, fieldName);

    if (!Array.isArray(raw)) return [];

    return raw
        .map(item => item?.id)
        .filter(Boolean);
}

function getDateOutputValue(value) {
    if (!value) return "";

    if (value instanceof Date) {
        return value.toISOString();
    }

    const asDate = new Date(value);

    if (!Number.isNaN(asDate.getTime())) {
        return asDate.toISOString();
    }

    return String(value);
}

function addIfWritable(payload, table, fieldName, value) {
    if (!fieldExists(table, fieldName)) {
        log(`Skipped missing field: ${table?.name || "unknown"}.${fieldName}`);
        return;
    }

    if (!isWritableField(table, fieldName)) {
        log(`Skipped non-writable field: ${table.name}.${fieldName}`);
        return;
    }

    if (value === null || value === undefined) return;
    if (typeof value === "string" && value.trim() === "") return;

    payload[fieldName] = value;
}

function assertUpdateIncludes(updateFields, fieldName, label) {
    if (!Object.prototype.hasOwnProperty.call(updateFields, fieldName)) {
        throw new Error(`Critical update field was not included: ${label || fieldName}`);
    }
}

async function updateRecordSafe(table, recordIdToUpdate, updates) {
    const safeUpdates = {};

    for (const [fieldName, value] of Object.entries(updates || {})) {
        addIfWritable(safeUpdates, table, fieldName, value);
    }

    if (Object.keys(safeUpdates).length === 0) {
        throw new Error(`No writable fields found for ${table.name} update.`);
    }

    await table.updateRecordAsync(recordIdToUpdate, safeUpdates);
    return true;
}

async function updateRecordBestEffort(table, recordIdToUpdate, updates) {
    try {
        const safeUpdates = {};

        for (const [fieldName, value] of Object.entries(updates || {})) {
            addIfWritable(safeUpdates, table, fieldName, value);
        }

        if (Object.keys(safeUpdates).length === 0) {
            return false;
        }

        await table.updateRecordAsync(recordIdToUpdate, safeUpdates);
        return true;
    } catch (error) {
        log("Best-effort update failed", {
            table: table?.name || "",
            recordId: recordIdToUpdate,
            error: error instanceof Error ? error.message : String(error),
        });
        return false;
    }
}

function buildVideoFieldsToLoad() {
    return [
        CONFIG.video.feedbackPosted,
        CONFIG.video.baseXpAwarded,
        CONFIG.video.doNotAwardXp,
        CONFIG.video.awardStatus,
        CONFIG.video.xpEvents,
        CONFIG.video.active,
        CONFIG.video.coachFeedback,
        CONFIG.video.enrollment,
        CONFIG.video.submission,
        CONFIG.video.readyForXp,
        CONFIG.video.workflowStatus,
        CONFIG.video.reviewedBy,
        CONFIG.video.reviewedAt,
    ].filter(fieldName => fieldExists(videoTable, fieldName));
}

function buildRuleFieldsToLoad() {
    return [
        CONFIG.rules.active,
        CONFIG.rules.xpAmount,
        CONFIG.rules.rewardRule,
        CONFIG.rules.ruleKey,
    ].filter(fieldName => fieldExists(rulesTable, fieldName));
}

function exitSkipped(reason, details = {}) {
    setCommonOutputs(CONFIG.outputs.skipped, reason, details);

    log("113 skipped", {
        automation: "113 - Video Review and XP - Assign Base Video XP",
        version: "v6.1",
        statusOut: CONFIG.outputs.skipped,
        reason,
        recordIdOut: recordId,
        ...details,
    });
}

function exitError(reason, details = {}) {
    setCommonOutputs(CONFIG.outputs.error, reason, details);

    log("113 error", {
        automation: "113 - Video Review and XP - Assign Base Video XP",
        version: "v6.1",
        statusOut: CONFIG.outputs.error,
        reason,
        recordIdOut: recordId,
        ...details,
    });
}

async function markAwardStatusErrorBestEffort() {
    if (!videoTable || !recordId || !videoRecordLoaded) return;

    if (!fieldExists(videoTable, CONFIG.video.awardStatus)) return;
    if (!isWritableField(videoTable, CONFIG.video.awardStatus)) return;
    if (!fieldHasType(videoTable, CONFIG.video.awardStatus, ["singleSelect"])) return;
    if (!singleSelectOptionExists(videoTable, CONFIG.video.awardStatus, CONFIG.values.awardStatusError)) return;

    await updateRecordBestEffort(videoTable, recordId, {
        [CONFIG.video.awardStatus]: buildSingleSelectValue(
            videoTable,
            CONFIG.video.awardStatus,
            CONFIG.values.awardStatusError
        ),
    });
}

/* =========================================================
   SECTION 5: REQUIRED FIELD CHECKS
========================================================= */

function validateRequiredFields() {
    for (const fieldName of [
        CONFIG.video.feedbackPosted,
        CONFIG.video.baseXpAwarded,
        CONFIG.video.awardStatus,
        CONFIG.video.doNotAwardXp,
        CONFIG.video.coachFeedback,
        CONFIG.video.enrollment,
        CONFIG.video.submission,
        CONFIG.video.readyForXp,
    ]) {
        requireField(videoTable, fieldName);
    }

    for (const fieldName of [
        CONFIG.rules.active,
        CONFIG.rules.xpAmount,
        CONFIG.rules.rewardRule,
        CONFIG.rules.ruleKey,
    ]) {
        requireField(rulesTable, fieldName);
    }

    requireFieldType(videoTable, CONFIG.video.enrollment, ["multipleRecordLinks"]);
    requireFieldType(videoTable, CONFIG.video.submission, ["multipleRecordLinks"]);
    requireFieldType(videoTable, CONFIG.video.awardStatus, ["singleSelect"]);

    if (fieldExists(videoTable, CONFIG.video.xpEvents)) {
        requireFieldType(videoTable, CONFIG.video.xpEvents, ["multipleRecordLinks"]);
    }

    requireWritableField(videoTable, CONFIG.video.baseXpAwarded);
    requireWritableField(videoTable, CONFIG.video.awardStatus);
    requireWritableField(videoTable, CONFIG.video.readyForXp);

    requireSingleSelectOption(
        videoTable,
        CONFIG.video.awardStatus,
        CONFIG.values.awardStatusPending
    );

    requireField(rulesTable, CONFIG.rules.xpAmount);
}

/* =========================================================
   SECTION 6: MAIN
========================================================= */

async function main() {
    let debugStep = "Start";
    setOutputSafe("debugStep", debugStep);

    debugStep = "1 - Read Input";
    setOutputSafe("debugStep", debugStep);

    const cfg =
        typeof input !== "undefined" && input && typeof input.config === "function"
            ? input.config()
            : {};

    recordId = String(cfg.recordId || "").trim();

    if (!recordId) {
        throw new Error("Missing required input: recordId");
    }

    if (!recordId.startsWith("rec")) {
        throw new Error(`Invalid Video Feedback recordId input: ${recordId}`);
    }

    debugStep = "2 - Load Tables";
    setOutputSafe("debugStep", debugStep);

    videoTable = base.getTable(CONFIG.tables.videoFeedback);
    rulesTable = base.getTable(CONFIG.tables.xpRewardRules);

    debugStep = "3 - Validate Required Fields";
    setOutputSafe("debugStep", debugStep);

    validateRequiredFields();

    debugStep = "4 - Load Video Feedback";
    setOutputSafe("debugStep", debugStep);

    const videoRecord = await videoTable.selectRecordAsync(recordId, {
        fields: buildVideoFieldsToLoad(),
    });

    if (!videoRecord) {
        throw new Error(`Video Feedback record not found: ${recordId}`);
    }

    videoRecordLoaded = true;

    debugStep = "5 - Read Video Feedback Values";
    setOutputSafe("debugStep", debugStep);

    const feedbackPosted = getCheckbox(
        videoRecord,
        videoTable,
        CONFIG.video.feedbackPosted
    );

    const doNotAwardXp = getCheckbox(
        videoRecord,
        videoTable,
        CONFIG.video.doNotAwardXp
    );

    const currentBaseXp = getNumber(
        videoRecord,
        videoTable,
        CONFIG.video.baseXpAwarded,
        null
    );

    const hasValidExistingBaseXp =
        Number.isFinite(currentBaseXp) && currentBaseXp > 0;

    const currentAwardStatus = getText(
        videoRecord,
        videoTable,
        CONFIG.video.awardStatus
    );

    const existingXpEventIds = fieldExists(videoTable, CONFIG.video.xpEvents)
        ? getLinkedIds(videoRecord, videoTable, CONFIG.video.xpEvents)
        : [];

    const videoActive = fieldExists(videoTable, CONFIG.video.active)
        ? getCheckbox(videoRecord, videoTable, CONFIG.video.active)
        : true;

    const coachFeedback = getText(
        videoRecord,
        videoTable,
        CONFIG.video.coachFeedback
    );

    const enrollmentIds = getLinkedIds(
        videoRecord,
        videoTable,
        CONFIG.video.enrollment
    );

    const submissionIds = getLinkedIds(
        videoRecord,
        videoTable,
        CONFIG.video.submission
    );

    const reviewedAtCurrent = fieldExists(videoTable, CONFIG.video.reviewedAt)
        ? getRaw(videoRecord, videoTable, CONFIG.video.reviewedAt)
        : null;

    const reviewedAtOutputValue = getDateOutputValue(reviewedAtCurrent);

    const reviewedByCurrent = fieldExists(videoTable, CONFIG.video.reviewedBy)
        ? getText(videoRecord, videoTable, CONFIG.video.reviewedBy)
        : "";

    log("113 input", {
        recordId,
        feedbackPosted,
        doNotAwardXp,
        currentBaseXp,
        hasValidExistingBaseXp,
        currentAwardStatus,
        existingXpEventIds,
        videoActive,
        coachFeedbackPresent: Boolean(coachFeedback),
        enrollmentIds,
        submissionIds,
        reviewedByCurrent,
        reviewedAtCurrent,
    });

    /* =========================================================
       VALIDATION / SKIP LOGIC
    ========================================================= */

    debugStep = "6 - Validate Skip Conditions";
    setOutputSafe("debugStep", debugStep);

    if (!videoActive) {
        exitSkipped("Video Feedback record is not active.");
        return;
    }

    if (!feedbackPosted) {
        exitSkipped("Feedback Posted? is not checked.");
        return;
    }

    if (doNotAwardXp) {
        exitSkipped("Do Not Award XP? is checked.");
        return;
    }

    if (!coachFeedback) {
        exitSkipped("Coach Feedback is blank.");
        return;
    }

    if (enrollmentIds.length === 0) {
        exitSkipped("Enrollment is missing.");
        return;
    }

    if (submissionIds.length === 0) {
        exitSkipped("Submission is missing.");
        return;
    }

    const now = new Date();
    const nowOutputValue = now.toISOString();

    /* =========================================================
       HANDLE EXISTING VALID BASE XP SAFELY
       - Base XP is valid only when currentBaseXp > 0.
       - If XP Event already exists or Award Status is Awarded, do not re-arm.
       - If Base XP exists but the record is not awarded yet, re-arm it for 114.
       - Also fill Reviewed By / Reviewed At only if missing.
    ========================================================= */

    debugStep = "7 - Handle Existing Base XP";
    setOutputSafe("debugStep", debugStep);

    if (hasValidExistingBaseXp) {
        if (
            normalizeText(currentAwardStatus) === normalizeText(CONFIG.values.awardStatusAwarded) ||
            existingXpEventIds.length > 0
        ) {
            const auditOnlyFields = {};

            let reviewedAtFinalOut = reviewedAtOutputValue;
            let reviewedByFinalOut = reviewedByCurrent;

            if (!reviewedAtCurrent) {
                addIfWritable(
                    auditOnlyFields,
                    videoTable,
                    CONFIG.video.reviewedAt,
                    now
                );
                reviewedAtFinalOut = nowOutputValue;
            }

            if (!reviewedByCurrent) {
                addIfWritable(
                    auditOnlyFields,
                    videoTable,
                    CONFIG.video.reviewedBy,
                    CONFIG.values.reviewedByName
                );
                reviewedByFinalOut = CONFIG.values.reviewedByName;
            }

            if (Object.keys(auditOnlyFields).length > 0) {
                await updateRecordSafe(videoTable, recordId, auditOnlyFields);
            }

            exitSkipped("Base XP already exists and XP appears to be awarded.", {
                baseXp: currentBaseXp,
                xpEventCount: existingXpEventIds.length,
                awardStatus: currentAwardStatus,
                reviewedBy: reviewedByFinalOut,
                reviewedAt: reviewedAtFinalOut,
                action: Object.keys(auditOnlyFields).length > 0
                    ? "audit_fields_repaired"
                    : "already_awarded_no_update",
            });

            return;
        }

        const rearmFields = {};

        addIfWritable(
            rearmFields,
            videoTable,
            CONFIG.video.awardStatus,
            buildSingleSelectValue(
                videoTable,
                CONFIG.video.awardStatus,
                CONFIG.values.awardStatusPending
            )
        );

        addIfWritable(
            rearmFields,
            videoTable,
            CONFIG.video.readyForXp,
            true
        );

        const workflowStatusValue = buildOptionalSingleSelectValue(
            videoTable,
            CONFIG.video.workflowStatus,
            CONFIG.values.workflowStatusReadyForXp
        );

        if (workflowStatusValue !== undefined) {
            addIfWritable(
                rearmFields,
                videoTable,
                CONFIG.video.workflowStatus,
                workflowStatusValue
            );
        }

        let reviewedAtFinalOut = reviewedAtOutputValue;
        let reviewedByFinalOut = reviewedByCurrent;

        if (!reviewedAtCurrent) {
            addIfWritable(
                rearmFields,
                videoTable,
                CONFIG.video.reviewedAt,
                now
            );
            reviewedAtFinalOut = nowOutputValue;
        }

        if (!reviewedByCurrent) {
            addIfWritable(
                rearmFields,
                videoTable,
                CONFIG.video.reviewedBy,
                CONFIG.values.reviewedByName
            );
            reviewedByFinalOut = CONFIG.values.reviewedByName;
        }

        assertUpdateIncludes(
            rearmFields,
            CONFIG.video.awardStatus,
            CONFIG.video.awardStatus
        );

        assertUpdateIncludes(
            rearmFields,
            CONFIG.video.readyForXp,
            CONFIG.video.readyForXp
        );

        await updateRecordSafe(videoTable, recordId, rearmFields);

        setCommonOutputs(CONFIG.outputs.success, "", {
            baseXp: currentBaseXp,
            ruleKey: CONFIG.values.ruleKeyVideo,
            action: "rearmed_existing_base_xp",
            reviewedBy: reviewedByFinalOut,
            reviewedAt: reviewedAtFinalOut,
        });

        log("113 success", {
            automation: "113 - Video Review and XP - Assign Base Video XP",
            version: "v6.1",
            statusOut: CONFIG.outputs.success,
            actionOut: "rearmed_existing_base_xp",
            recordIdOut: recordId,
            baseXpOut: currentBaseXp,
            reviewedByOut: reviewedByFinalOut,
            reviewedAtOut: reviewedAtFinalOut,
            updateFieldsWritten: Object.keys(rearmFields),
        });

        return;
    }

    /* =========================================================
       LOAD XP REWARD RULES
    ========================================================= */

    debugStep = "8 - Load XP Reward Rules";
    setOutputSafe("debugStep", debugStep);

    const rulesQuery = await rulesTable.selectRecordsAsync({
        fields: buildRuleFieldsToLoad(),
    });

    try {
        const matchingRules = rulesQuery.records.filter(ruleRecord => {
            const active = getCheckbox(ruleRecord, rulesTable, CONFIG.rules.active);
            const ruleKey = getText(ruleRecord, rulesTable, CONFIG.rules.ruleKey);

            if (!active) return false;

            return normalizeText(ruleKey) === normalizeText(CONFIG.values.ruleKeyVideo);
        });

        if (matchingRules.length === 0) {
            const message = `No active XP Reward Rule found with Rule Key = ${CONFIG.values.ruleKeyVideo}`;
            exitError(message);
            throw new Error(message);
        }

        if (matchingRules.length > 1) {
            const names = matchingRules.map(record => record.name).join(", ");
            const message = `Multiple active XP Reward Rules found with Rule Key = ${CONFIG.values.ruleKeyVideo}: ${names}`;
            exitError(message);
            throw new Error(message);
        }

        const matchedRule = matchingRules[0];

        const xpAmount = getNumber(
            matchedRule,
            rulesTable,
            CONFIG.rules.xpAmount,
            null
        );

        if (!Number.isFinite(xpAmount) || xpAmount <= 0) {
            const message = `Matched XP Reward Rule is missing a valid XP Amount: ${matchedRule.name}`;
            exitError(message, {
                matchedRule: matchedRule.name,
            });
            throw new Error(message);
        }

        /* =========================================================
           WRITE BASE XP, AUDIT FIELDS, AND ARM 114
        ========================================================= */

        debugStep = "9 - Write Base XP and Arm 114";
        setOutputSafe("debugStep", debugStep);

        const updateFields = {};

        addIfWritable(
            updateFields,
            videoTable,
            CONFIG.video.baseXpAwarded,
            xpAmount
        );

        addIfWritable(
            updateFields,
            videoTable,
            CONFIG.video.awardStatus,
            buildSingleSelectValue(
                videoTable,
                CONFIG.video.awardStatus,
                CONFIG.values.awardStatusPending
            )
        );

        addIfWritable(
            updateFields,
            videoTable,
            CONFIG.video.readyForXp,
            true
        );

        const workflowStatusValue = buildOptionalSingleSelectValue(
            videoTable,
            CONFIG.video.workflowStatus,
            CONFIG.values.workflowStatusReadyForXp
        );

        if (workflowStatusValue !== undefined) {
            addIfWritable(
                updateFields,
                videoTable,
                CONFIG.video.workflowStatus,
                workflowStatusValue
            );
        }

        let reviewedAtFinalOut = reviewedAtOutputValue;
        let reviewedByFinalOut = reviewedByCurrent;

        if (!reviewedAtCurrent) {
            addIfWritable(
                updateFields,
                videoTable,
                CONFIG.video.reviewedAt,
                now
            );
            reviewedAtFinalOut = nowOutputValue;
        }

        if (!reviewedByCurrent) {
            addIfWritable(
                updateFields,
                videoTable,
                CONFIG.video.reviewedBy,
                CONFIG.values.reviewedByName
            );
            reviewedByFinalOut = CONFIG.values.reviewedByName;
        }

        assertUpdateIncludes(
            updateFields,
            CONFIG.video.baseXpAwarded,
            CONFIG.video.baseXpAwarded
        );

        assertUpdateIncludes(
            updateFields,
            CONFIG.video.awardStatus,
            CONFIG.video.awardStatus
        );

        assertUpdateIncludes(
            updateFields,
            CONFIG.video.readyForXp,
            CONFIG.video.readyForXp
        );

        await updateRecordSafe(videoTable, recordId, updateFields);

        /* =========================================================
           OUTPUTS
        ========================================================= */

        debugStep = "10 - Outputs";
        setOutputSafe("debugStep", debugStep);

        setCommonOutputs(CONFIG.outputs.success, "", {
            matchedRule: matchedRule.name,
            baseXp: xpAmount,
            ruleKey: CONFIG.values.ruleKeyVideo,
            action: "assigned_base_xp_and_armed_114",
            reviewedBy: reviewedByFinalOut,
            reviewedAt: reviewedAtFinalOut,
        });

        log("113 success", {
            automation: "113 - Video Review and XP - Assign Base Video XP",
            version: "v6.1",
            statusOut: CONFIG.outputs.success,
            actionOut: "assigned_base_xp_and_armed_114",
            recordIdOut: recordId,
            matchedRuleOut: matchedRule.name,
            ruleKeyOut: CONFIG.values.ruleKeyVideo,
            baseXpOut: xpAmount,
            awardStatusWritten: CONFIG.values.awardStatusPending,
            readyForXpAutomationWritten: true,
            reviewedByOut: reviewedByFinalOut,
            reviewedAtOut: reviewedAtFinalOut,
            reviewedAtWritten: !reviewedAtCurrent,
            reviewedByWritten: !reviewedByCurrent,
            updateFieldsWritten: Object.keys(updateFields),
        });
    } finally {
        rulesQuery.unloadData();
    }
}

/* =========================================================
   SECTION 7: RUN
========================================================= */

try {
    await main();
} catch (error) {
    const message = error instanceof Error ? error.message : String(error);

    setCommonOutputs(CONFIG.outputs.error, message, {
        action: "error",
    });

    try {
        await markAwardStatusErrorBestEffort();
    } catch {
        // Keep original error visible.
    }

    log("113 failed", {
        automation: "113 - Video Review and XP - Assign Base Video XP",
        version: "v6.1",
        statusOut: CONFIG.outputs.error,
        actionOut: "error",
        recordIdOut: recordId || "",
        errorOut: message,
    });

    throw error;
}

/************************************************************
